-- Poems batch 223
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b996118b-2c7b-4d7a-9250-edaa2eb5e7b8','題淵明採菊圖','鄭起潛','宋','宋诗','song-poetry','','[]','閑却經綸手，東籬把菊枝。',24,'全唐诗/poet.song.206000.json','["閑却經綸手，東籬把菊枝。", "先生花外意，難畫亦難詩。"]'),
('e2cde39d-ca81-4383-9555-a62477f59dc5','題蜀道難圖','鄭起潛','宋','宋诗','song-poetry','','[]','蜀道難從古，于今分外難。',24,'全唐诗/poet.song.206000.json','["蜀道難從古，于今分外難。", "江山風景在，忍把畫圖看。"]'),
('2441b122-6473-4ba1-8a7d-7898d6442513','遊七星巖和曾景亮同年','趙崇垓','宋','宋诗','song-poetry','','[]','地本乎陰竅本空，巖名以斗古傳風。',64,'全唐诗/poet.song.206000.json','["地本乎陰竅本空，巖名以斗古傳風。", "世人適意爲行樂，造物何心著巧功。", "弱水蓬萊仙境界，石橋方廣佛神通。", "達觀不作塵寰看，笑挹天漿樂在中。"]'),
('b5f79696-111f-4600-85d5-c3d03968a34a','遊七星巖','曾純','宋','宋诗','song-poetry','','[]','斗宿垂精插碧空，嵌巖太古石屏風。',64,'全唐诗/poet.song.206000.json','["斗宿垂精插碧空，嵌巖太古石屏風。", "自然一道玲瓏穴，誰見五丁開鑿功。", "竇裏乳泉時點滴，門前瀝水暗流通。", "吾儕洞目崧臺景，謝屐何曾到此中。"]'),
('4f0d31e6-fd32-4c6b-b111-bee953dc40a4','過楊子橋','趙崇淵','宋','宋诗','song-poetry','','[]','一抹輕烟隔小橋，新篁褪籜兩三梢。',32,'全唐诗/poet.song.206000.json','["一抹輕烟隔小橋，新篁褪籜兩三梢。", "惜春不覺歸來晚，花壓重門带月敲。"]'),
('d8057dce-2f22-42ae-86d3-c041fef9d76f','南園','牟子才','宋','宋诗','song-poetry','','[]','買家喜傍水精宮，正是南園故址中。',32,'全唐诗/poet.song.206000.json','["買家喜傍水精宮，正是南園故址中。", "我欲築堂名六老，追還慶曆太平風。"]'),
('a3a6e6d9-4d05-43dc-8cab-ea6400098eb1','宴江檢詳','牟子才','宋','宋诗','song-poetry','','[]','神螺卷雨入田疇，留得公堂一片秋。',64,'全唐诗/poet.song.206000.json','["神螺卷雨入田疇，留得公堂一片秋。", "天上已催郎署去，人間難挽使華留。", "莫嫌仲舉題輿晚，猶及東坡秉燭遊。", "易在虎皮公在坐，試開寶篋爲人謀。"]'),
('18260ee8-2ca3-4c81-98eb-6b9a2e7c86bf','同張倅宴吳吉州','牟子才','宋','宋诗','song-poetry','','[]','新陽葭琯已浮灰，昨夜珠從合浦回。',64,'全唐诗/poet.song.206000.json','["新陽葭琯已浮灰，昨夜珠從合浦回。", "曉日鸞旂新竹契，春風龍炙古蘭陔。", "青原別駕𣂏丹酒，碧落仙人醉玉梅。", "來歲五更三點入，直迎紅藥看蒼苔。"]'),
('f4633f64-fa8e-4f30-b2f8-28bd102f7643','淳祐七年丁未十一月朔蔡九軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得河字','牟子才','宋','宋诗','song-poetry','','[]','群玉之峰千丈高，太微左宇凌星河。',384,'全唐诗/poet.song.206000.json','["群玉之峰千丈高，太微左宇凌星河。", "承明著作記仙室，汗青芸香老研磨。", "瀛洲學士水蒼佩，清響戛擊諧雲和。", "我朝仁祖重茲選，涵養澤媲周菁莪。", "一時搜羅盡才傑，論事往往無譏訶。", "四賢景祐國之鎮，肯爲公議輕倒戈。", "當年棖觸鼎鼐意，愿與希文同謫播。", "慶曆一客傷衆客，醉飽過耳寧有他。", "文符搜索網打盡，謠詠可但仇傲歌。", "古來館閣有如此，勁氣金石相盪摩。", "能令皇圖聳天際，勢與泰華並嵯峨。", "南箕貝錦半天下，翻作采葛傷讒多。", "視若弁髦如土梗，甚者足蹋鯨海波。", "吁嗟此意久不作，遺響近續應非訛。", "西山有孫賸文采，二十八宿心包羅。", "芳菲彌章楚騷蕙，碩大且儼陳陂荷。", "峨冠蓬島兩冰暑，凌遡迤邐風玉珂。", "俯而就之豈不可，議論乃欲降妖魔。", "紀綱一疏有奇氣，幾微半語驅沉疴。", "手披逆鱗觸震電，心翼漢鼎扶羲娥。", "悠然群聵發深省，誦之穆若清風過。", "鳳凰肯啄我傷粟，騏驥豈飫天山禾。", "殿頭拜疏勇莫遏，指點歸問煙江蓑。", "要津未若急流退，苞栩孰與考槃過。"]'),
('a4cc41da-7916-48d4-a7c6-6c54f575bc54','春雨懷述  其一','牟子才','宋','宋诗','song-poetry','','[]','懶把閑情去問花，花如含淚向天涯。',64,'全唐诗/poet.song.206000.json','["懶把閑情去問花，花如含淚向天涯。", "二分春色已拋過，幾處芳枝蹇未芽。", "羯鼓無功緣底事，鶑梢已恨落誰家。", "門前楊柳黄猶淡，爲問何時可暮鴉。"]'),
('15f15840-0c64-4b7e-a124-4412e904f765','春雨懷述  其二','牟子才','宋','宋诗','song-poetry','','[]','把酒臨風酹太和，春光九十已無多。',64,'全唐诗/poet.song.206000.json','["把酒臨風酹太和，春光九十已無多。", "四陽壯矣陰如此，萬卉淒其愁奈何。", "不怕生成銷鑠盡，祇緣花信等閑過。", "欲將詩句勾晴色，南墅騷人製芰荷。"]'),
('94fa1a20-bcbe-4840-99be-185985e612b4','慶丁大監  其一','牟子才','宋','宋诗','song-poetry','','[]','兩朝表異詔言溫，忠厚根基百世培。',64,'全唐诗/poet.song.206000.json','["兩朝表異詔言溫，忠厚根基百世培。", "嶽麓湖湘多秀氣，玉杯繁露是奇才。", "詞章近接秦而上，學術羞肩漢以來。", "事業元從儒者出，經綸之地自恢恢。"]'),
('0bc5bb01-75fc-4b4d-8515-d55459b877bc','慶丁大監  其二','牟子才','宋','宋诗','song-poetry','','[]','三瑞堂前香燕凝，詩書一脈浸人心。',64,'全唐诗/poet.song.206000.json','["三瑞堂前香燕凝，詩書一脈浸人心。", "韜峰不露全牛解，振鬣長嘶萬馬瘖。", "諸縣屢豐公事少，朞年未及去思深。", "減租除粟興三學，人口如碑詠到今。"]'),
('13b17d62-a883-4646-a2ea-87764d1574e7','慶丁大監  其三','牟子才','宋','宋诗','song-poetry','','[]','碧露猶餘不盡翰，文章少露豹林斑。',64,'全唐诗/poet.song.206000.json','["碧露猶餘不盡翰，文章少露豹林斑。", "身行襄蜀江淮外，名在龔黄召杜間。", "使傳暫勞濡轡沃，帥幢已聳碧油閑。", "笑談盡護風寒了，歸踏春風輦路班。"]'),
('a743099b-0b2c-4d9e-a703-32f838d1f655','慶丁大監  其四','牟子才','宋','宋诗','song-poetry','','[]','侯門六射喜從逢，今歲豐和夐不同。',64,'全唐诗/poet.song.206000.json','["侯門六射喜從逢，今歲豐和夐不同。", "漕輓甫資蕭相策，閟宮恰壽魯僖功。", "鶴歸動是三千歲，松夢終當十八公。", "願舉家風祝公壽，夜來已壓小槽紅。"]'),
('c22d14ef-a1dd-405e-a73f-3813ab7ec311','雷雨夜賦絕句','蔣重珍','宋','宋诗','song-poetry','','[]','電飛窗上明如月，雨溜簷前響過泉。',32,'全唐诗/poet.song.206000.json','["電飛窗上明如月，雨溜簷前響過泉。", "蠢動有生皆發蟄，是龍那得不升天。"]'),
('44b2479e-64e3-4f72-8ed3-7280e1d587d8','題慧山','蔣重珍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','龍山慧山兩山雲，出能爲雨入爲晴。',96,'全唐诗/poet.song.206000.json','["龍山慧山兩山雲，出能爲雨入爲晴。", "雲山之氣有歛散，歛散之理斯爲神。", "我廬山下爲小隠，雲爲動兮山爲靜。", "悠然而出物之澤，屹然而峙地之鎮。", "我見雲山善與俱，雲山無情不見余。", "我比雲山多此見，不如一似雲山無。"]'),
('c28e60d7-133a-4b47-b407-551dfe272eda','題惠山','蔣重珍','宋','宋诗','song-poetry','','[]','妄慮散毛髮，真源生齒牙。',48,'全唐诗/poet.song.206000.json','["妄慮散毛髮，真源生齒牙。", "我聞甘露飯，即是惠山茶。", "欲駐歲月晚，重遊道路遐。", "更須煩稚子，再煮鼎中花。"]'),
('46e5a0ac-195f-433a-9f2e-eba3a914bf29','樂溪居萬卷樓三首  其一','蔣重珍','宋','宋诗','song-poetry','','[]','小艇溪邊月，來尋萬卷樓。',24,'全唐诗/poet.song.206000.json','["小艇溪邊月，來尋萬卷樓。", "遂初讀書處，鶴去白雲留。"]'),
('f286d085-af8b-44cc-ba3d-ddeea13cbf1e','樂溪居萬卷樓三首  其二','蔣重珍','宋','宋诗','song-poetry','','[]','剩有溪山樹，書樓迹已陳。',24,'全唐诗/poet.song.206000.json','["剩有溪山樹，書樓迹已陳。", "故人不可見，繞樹一悲吟。"]'),
('e2b3b5df-4dd6-4302-a0bb-b25f13c228ad','樂溪居萬卷樓三首  其三','蔣重珍','宋','宋诗','song-poetry','','[]','萬壑注清流，孤煙起暮愁。',24,'全唐诗/poet.song.206000.json','["萬壑注清流，孤煙起暮愁。", "龍山半溪落，鴈影過書樓。"]'),
('8018b30d-f016-4113-8e74-4ad387f2f3ea','存目','蔣重珍','宋','宋诗','song-poetry','','[]','詩題：題蕭岳英常州朱氏畫草蟲卷首句：常州草蟲天下奇，筆端生意已如生。',34,'全唐诗/poet.song.206000.json','["詩題：題蕭岳英常州朱氏畫草蟲卷首句：常州草蟲天下奇，筆端生意已如生。"]'),
('5680b98e-5c00-47c8-9200-be6111630bd1','茶','戴翼','宋','宋诗','song-poetry','','[]','騷客辭眠腸正苦，睡魔退聽骨先寒。',32,'全唐诗/poet.song.206000.json','["騷客辭眠腸正苦，睡魔退聽骨先寒。", "未堪入餠供龍焙，且遣一旗登虎壇。"]'),
('5f59d4f8-83ab-4561-838a-90449b3bfdea','棋  其一','戴翼','宋','宋诗','song-poetry','','[]','休將斤斧向般揮，殺處誰知有活機。',64,'全唐诗/poet.song.206000.json','["休將斤斧向般揮，殺處誰知有活機。", "我且雙關聊自固，君無一眼漫相圍。", "只能暗裏龜頭縮，怎識伊邊虎口危。", "莫向人前誇己會，降旗幾度送君歸。"]'),
('13bdedc3-1a1a-4208-a01b-6d092668111c','棋  其二','戴翼','宋','宋诗','song-poetry','','[]','部曲縱橫聽指揮，元來棋算即兵機。',64,'全唐诗/poet.song.206000.json','["部曲縱橫聽指揮，元來棋算即兵機。", "雙關似鐵吳堅壁，一著還魂漢解圍。", "中壘占形包兩陝，邊隅拓土卷三危。", "一枰未罷兵書至，戰退苻秦奏凱歸。"]'),
('3f113ac3-40e8-4035-8be9-362599baed8d','贈星術黄太史','戴翼','宋','宋诗','song-poetry','','[]','粵從太極生兩儀，大明生東月生西。',176,'全唐诗/poet.song.206000.json','["粵從太極生兩儀，大明生東月生西。", "煌煌兩日照今古，一晝一夜分主之。", "人具陰陽中造化，亦係日月之所舍。", "在日爲命月爲身，所主各隨其晝夜。", "此數定不差毫毛，惜哉庸術其傳訛。", "談命以日不及月，日本昱晝如夜何。", "甘石不作今已矣，星學之精其能幾。", "掌中日月分旦昏，獨有黄生精算爾。", "黄生算到毫杪處，吉凶定如鼓應桴。", "奇哉此術真神祕，世人不知反爲異。", "俗流何可輕與談，吾有潁濱月軒記。"]'),
('9f60100a-82e7-49f7-aad1-a34bc34adeac','寧皇御舟','黄洪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','龍舟大半沒西湖，此是先皇節儉圖。',32,'全唐诗/poet.song.206000.json','["龍舟大半沒西湖，此是先皇節儉圖。", "三十六年安靜裏，櫂歌一曲在康衢。"]'),
('911d5234-2192-4e20-8b7c-9821e8568814','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩得霜字','黄洪','宋','宋诗','song-poetry','','[]','戀闕心逾赤，乘軺鬢未霜。',48,'全唐诗/poet.song.206000.json','["戀闕心逾赤，乘軺鬢未霜。", "祇家將六學，綜國劄三章。", "眷近花明路，風馳錦過鄉。", "臨分不成飲，相對獨凄凉。"]'),
('5382b143-0fad-40f5-95ee-993654a244b7','題忠毅姚公廟  其一','林宋偉','宋','宋诗','song-poetry','','[]','赤心許國自平時，見敵捐軀更不疑。',32,'全唐诗/poet.song.206000.json','["赤心許國自平時，見敵捐軀更不疑。", "權忌皋庸皆遁走，同時死難只青獅。"]'),
('341fc4bb-5189-4198-8474-fe33cfff24b3','題忠毅姚公廟  其二','林宋偉','宋','宋诗','song-poetry','','[]','農父犁田出寶刀，銅花浸血冷侵毛。',32,'全唐诗/poet.song.206000.json','["農父犁田出寶刀，銅花浸血冷侵毛。", "神鋒懔懔衝星斗，未讓豐城劍氣高。"]'),
('6574777f-a984-4175-90cb-969558fcdc1c','題忠毅姚公廟  其三','林宋偉','宋','宋诗','song-poetry','','[]','歲歲蒸嘗九月期，西風笳鼓萬人悲。',32,'全唐诗/poet.song.206000.json','["歲歲蒸嘗九月期，西風笳鼓萬人悲。", "山邊走馬神旗閃，父老齊呼太尉來。"]'),
('84391c44-cf69-4343-be36-ecea07d38fe7','題忠毅姚公廟  其四','林宋偉','宋','宋诗','song-poetry','','[]','兩日經行舊戰場，却來祠下謁堂堂。',32,'全唐诗/poet.song.206000.json','["兩日經行舊戰場，却來祠下謁堂堂。", "偷生諸將今何在，萬古英靈獨耿光。"]'),
('a5242589-532f-4e9d-80a0-48f153cf1c07','勸農即事和厲寺正韻  其一','林宋偉','宋','宋诗','song-poetry','','[]','春將新綠滿郊原，喜逐雙旌曉出關。',64,'全唐诗/poet.song.206000.json','["春將新綠滿郊原，喜逐雙旌曉出關。", "初度麥畦行詰曲，却穿竹徑俯潺湲。", "陰陰霽色催歸騎，獵獵溪風醒醉顔。", "父老歡呼隨幼稚，隔途爭看使車還。"]'),
('cfd5928c-1683-43af-8218-f8bf99e2cba5','勸農即事和厲寺正韻  其二','林宋偉','宋','宋诗','song-poetry','','[]','我不歸耕却勸耕，下車且伴老農行。',64,'全唐诗/poet.song.206000.json','["我不歸耕却勸耕，下車且伴老農行。", "萊苗已過花纔盛，桑葉方開葚早生。", "此去耕牛無暇日，新年啼鳥總懽聲。", "定符賢守豐年願，甘返田園老太平。"]'),
('cca8c5bb-22ce-4354-bb3d-62edd28e467b','句','林宋偉','宋','宋诗','song-poetry','','[]','韓非老子俱同傳，乞與時人子細看。',16,'全唐诗/poet.song.206000.json','["韓非老子俱同傳，乞與時人子細看。"]'),
('bbc567e1-6c18-4312-a247-22ff0e818c54','句','胡鏜','宋','宋诗','song-poetry','','[]','貧居三不往，薄宦兩無求。',12,'全唐诗/poet.song.206000.json','["貧居三不往，薄宦兩無求。"]'),
('9b229e4d-23a5-43ff-92fd-f00150a5ec0d','登法華臺','陳琰','宋','宋诗','song-poetry','','[]','南楚歸舟牽客思，西風脫葉轉秋寒。',32,'全唐诗/poet.song.206000.json','["南楚歸舟牽客思，西風脫葉轉秋寒。", "年華漸晚邊城遠，凝望中天更倚欄。"]'),
('39efdcd8-31af-4495-a6ea-bb28174d3cff','詩意','陳琰','宋','宋诗','song-poetry','','[]','慘淡輕縈似畫圖，神遊物外有還無。',64,'全唐诗/poet.song.206000.json','["慘淡輕縈似畫圖，神遊物外有還無。", "灞橋雪裏清應苦，飯顆山頭人亦癯。", "敏掣鯨魚當碧幽，隨象網索玄珠出。", "□塵解悟天機妙，一字何勞撚斷鬚。"]'),
('5b88902f-092d-41b9-8a3a-a5cc1ff77bc6','詩思','陳琰','宋','宋诗','song-poetry','','[]','本與名言絕，乾坤鍾氣清。',48,'全唐诗/poet.song.206000.json','["本與名言絕，乾坤鍾氣清。", "靜中取拾得，閒裏琢磨成。", "美刺明時化，幽微索至精。", "不曾親悟入，似隔萬重城。"]'),
('30ba5a21-b1a3-41b9-83fb-ab61c7ca0798','柵口致喜亭詠懷  其一','劉宗','宋','宋诗','song-poetry','','[]','經年多病少逢迎，投老歸來稱野情。',64,'全唐诗/poet.song.206000.json','["經年多病少逢迎，投老歸來稱野情。", "閉戶且教防俗客，擁書終自笑浮生。", "怪人鴻雁呼羣起，浴水鵁鶄傍母輕。", "幾點疎螢獨來往，鬢絲禪榻落花聲。"]'),
('88a5a4f4-398f-4ddb-a16d-890b9e2229f5','柵口致喜亭詠懷  其二','劉宗','宋','宋诗','song-poetry','','[]','天末凉風吹白雲，漸看長晝少炎氛。',64,'全唐诗/poet.song.206000.json','["天末凉風吹白雲，漸看長晝少炎氛。", "滿庭慈竹秋陰合，夾岸枯荷夜雨聞。", "漂泊鄉關新避寇，荒唐客夢舊從軍。", "起來極目西山望，故里松楸悵夕曛。"]'),
('847cc0fd-49af-41c0-a0b0-b3ce6890a6d1','白蓮花','高子鳳','宋','宋诗','song-poetry','','[]','地産枝蓮異，蓮宮自此興。',48,'全唐诗/poet.song.206000.json','["地産枝蓮異，蓮宮自此興。", "殊祥天不靳，奇艷雪堪陵。", "魄化疑吳女，碑傳有蜀僧。", "何當尋勝概，吟斷佛前燈。"]'),
('3c34b1ca-4d43-4a67-a419-2a0921381e3b','松澤西亭  其一','高子鳳','宋','宋诗','song-poetry','','[]','松澤亭前山色幽，洙涇渡口荻花秋。',32,'全唐诗/poet.song.206000.json','["松澤亭前山色幽，洙涇渡口荻花秋。", "離鈎三寸無人會，一棹東西獨未休。"]'),
('3e35e4cd-c9c9-4571-808b-7f392d114854','松澤西亭  其二','高子鳳','宋','宋诗','song-poetry','','[]','野水閒雲無定蹤，一生空棹月明中。',32,'全唐诗/poet.song.206000.json','["野水閒雲無定蹤，一生空棹月明中。", "錦鱗纔得翻船去，堪笑家風徹底窮。"]'),
('2edb380b-5ff9-403c-af97-26b914d920ee','松澤西亭  其三','高子鳳','宋','宋诗','song-poetry','','[]','西亭無處認遺基，煙月空餘舊唱辭。',32,'全唐诗/poet.song.206000.json','["西亭無處認遺基，煙月空餘舊唱辭。", "欲問辭中端的意，渚花堤柳可能知。"]'),
('ee1f2c8c-0637-412d-a958-c9790236a3fe','松澤西亭  其四','高子鳳','宋','宋诗','song-poetry','','[]','劈口兩橈無剩法，點頭三下不容聲。',32,'全唐诗/poet.song.206000.json','["劈口兩橈無剩法，點頭三下不容聲。", "謝師付授從今了，一段風流畫不成。"]'),
('0a1a7325-36c3-49c4-9931-4f8c683da069','松澤西亭  其五','高子鳳','宋','宋诗','song-poetry','','[]','隔水遥山數朵青，送人依舊泊閒亭。',32,'全唐诗/poet.song.206000.json','["隔水遥山數朵青，送人依舊泊閒亭。", "此舟未信無重過，門枕蘋汀夜不扃。"]'),
('50802535-fbe3-419d-9df8-92644f5e417b','題楊補之墨梅卷','高子鳳','宋','宋诗','song-poetry','','[]','籬根玉瘦兩三枝，爲繞吟香夜不歸。',32,'全唐诗/poet.song.206000.json','["籬根玉瘦兩三枝，爲繞吟香夜不歸。", "安得密林千畝月，仰眠吹笛看花飛。"]'),
('60a73879-3798-40fc-aa6b-ebf98c4ee543','挽李仲通','古田里人','宋','宋诗','song-poetry','','[]','久矣厭塵世，逃名雲水間。',48,'全唐诗/poet.song.206000.json','["久矣厭塵世，逃名雲水間。", "五湖正覓地，一曲歌滄浪。", "風雨晚來急，笠簑時下忙。", "釣龍手中竹，分付與兒郎。"]'),
('eb26ee41-ac5a-49b3-af46-cac796fd6b1d','龍脊灘','沈安義','宋','宋诗','song-poetry','','[]','龍脊灘頭春已歸，舊章重舉到江湄。',64,'全唐诗/poet.song.206000.json','["龍脊灘頭春已歸，舊章重舉到江湄。", "玉簫金縷民風樂，麥隴桑疇農事熙。", "猶記去年來把酒，又還今日再題詩。", "桃花三月歸帆過，此地紅濤漸渺瀰。"]'),
('88e04b0e-2b40-4f59-bb98-a366100a7a84','城山國清塘','李丑父','宋','宋诗','song-poetry','','[]','平田一水自縈迴，喜見茲塘亦壯哉。',64,'全唐诗/poet.song.206000.json','["平田一水自縈迴，喜見茲塘亦壯哉。", "夏潦久收猶浩渺，壺山近看更崔巍。", "刺船葑蓼中邊去，喚月烟嵐外面來。", "見說艾軒詩句好，不逢墨迹重徘徊。"]'),
('804ef31b-39dc-4868-82cb-28f5d7a9e73b','句','李丑父','宋','宋诗','song-poetry','','[]','諸生幸不笑韓愈，官長何因駡鄭虔。',16,'全唐诗/poet.song.206000.json','["諸生幸不笑韓愈，官長何因駡鄭虔。"]'),
('e58605b3-5a4f-4fd9-9786-770994d65cf4','妃嬪','彭耜','宋','宋诗','song-poetry','','[]','凉殿初生露滿天，木犀花發月初圓。',32,'全唐诗/poet.song.206000.json','["凉殿初生露滿天，木犀花發月初圓。", "君王少御珊瑚枕，多就宮人玉臂眠。"]'),
('9e6cc0ba-5570-44f1-bd2e-29b315c87cf9','知州  其一','彭耜','宋','宋诗','song-poetry','','[]','鎮靜一如無，頒條甫月餘。',48,'全唐诗/poet.song.206000.json','["鎮靜一如無，頒條甫月餘。", "來惟盡傳客，去不識兵符。", "健判風生筆，精祈雨洒車。", "丈夫何必假，行矣兩輪朱。"]'),
('0857e069-398f-4845-9ebb-b599149e97a7','知州  其二','彭耜','宋','宋诗','song-poetry','','[]','雖擁朱轓貴，清癯兩鬢霜。',48,'全唐诗/poet.song.206000.json','["雖擁朱轓貴，清癯兩鬢霜。", "判花人競誦，待草士深藏。", "農飽因蠲賦，州貧爲救荒。", "公歸無愧面，應可見嚴光。"]'),
('f37899f8-a39a-40cc-9c06-1b6e81103d6a','知州  其三','彭耜','宋','宋诗','song-poetry','','[]','瀟洒使君風度峻，神仙謫墮在人間。',32,'全唐诗/poet.song.206000.json','["瀟洒使君風度峻，神仙謫墮在人間。", "只今坐嘯凝香處，帝賜羅浮作鎮還。"]'),
('3501458e-1b77-457b-a329-072253ad552b','知州  其四','彭耜','宋','宋诗','song-poetry','','[]','郡人不識疾呼聲，甘雨和風遍一城。',48,'全唐诗/poet.song.206000.json','["郡人不識疾呼聲，甘雨和風遍一城。", "歲久偏多遺愛事，天高未察借留情。", "舟行精舍漁歌晚，家近華亭鶴唳清。"]'),
('12f6f8bc-03fe-4c70-baa1-9779a00ff211','知州  其五','彭耜','宋','宋诗','song-poetry','','[]','倦入承明聽履聲，朱轓今復壓專城。',64,'全唐诗/poet.song.206000.json','["倦入承明聽履聲，朱轓今復壓專城。", "盪胸碧華供吟興，照眼清洢洗宦情。", "鱸鱠何慙高士潔，琴龜不減昔賢清。", "未應更葺東山墅，出處方關世重輕。"]'),
('5a21b0d1-a39e-4dee-bc94-c9a77a56b11b','知州  其六','彭耜','宋','宋诗','song-poetry','','[]','聞道泉人截鐙留，翰林從此去吾州。',32,'全唐诗/poet.song.206000.json','["聞道泉人截鐙留，翰林從此去吾州。", "村中父老相持泣，但祝今侯似故侯。"]'),
('985a4928-591e-45cf-9c8b-0289671a4ce5','知州  其七','彭耜','宋','宋诗','song-poetry','','[]','淮漢紛紛戰血腥，蜀山鬼哭不堪聽。',32,'全唐诗/poet.song.206000.json','["淮漢紛紛戰血腥，蜀山鬼哭不堪聽。", "如何一線江西路，獨見奎星與福星。"]'),
('e4b1ae24-ff2b-4c28-8d6e-f6f62750bc75','幕職','彭耜','宋','宋诗','song-poetry','','[]','一昨聞公幕府開，夢魂頻遶嶺頭梅。',64,'全唐诗/poet.song.206000.json','["一昨聞公幕府開，夢魂頻遶嶺頭梅。", "久拋鞾袴辭軍去，忽有弓旌扣戶來。", "茅舍相過爭借問，荷衣欲出却徘徊。", "舊時檄草今焚棄，辜負黄金百尺臺。"]'),
('5aeef011-b960-4ec2-839b-54eabd98aad3','知縣','彭耜','宋','宋诗','song-poetry','','[]','茲邑猶淳古，君行作長官。',48,'全唐诗/poet.song.206000.json','["茲邑猶淳古，君行作長官。", "假令三尺密，終有一分寬。", "栗里歸差易，桐鄉愛極難。", "千峰青遶郭，暇日想憑欄。"]'),
('81672c04-4622-48bd-8e58-21ff359ef93c','將帥','彭耜','宋','宋诗','song-poetry','','[]','昨釋兵符歸故里，耳聽兵事幾番新。',64,'全唐诗/poet.song.206000.json','["昨釋兵符歸故里，耳聽兵事幾番新。", "偶逢麾下來猶識，欲說遼陽記不真。", "兒覓寶刀堅愛惜，奴吹蘆管怨悲辛。", "夜來忽作關山夢，萬一君王起舊人。"]'),
('b695425d-deb4-44ce-a0f3-eeed0c8992f2','第宅  其一','彭耜','宋','宋诗','song-poetry','','[]','宅成天下借圖看，始笑平生眼力慳。',64,'全唐诗/poet.song.206000.json','["宅成天下借圖看，始笑平生眼力慳。", "地占百灣多是水，樓無一面不當山。", "荷深似入苕溪路，石怪疑行鴈蕩間。", "只恐中原方鼎沸，天心未遣主人閒。"]'),
('f6c7446f-4b70-483e-a86a-7047359e1759','第宅  其二','彭耜','宋','宋诗','song-poetry','','[]','一生不蓄買田錢，華屋何心亦偶然。',32,'全唐诗/poet.song.206000.json','["一生不蓄買田錢，華屋何心亦偶然。", "客至多逢僧在坐，釣歸惟許鶴隨船。"]'),
('cb9e5945-6fdc-4c46-b10e-744c98660e06','樓','彭耜','宋','宋诗','song-poetry','','[]','人世應無第二樓，暮雲飛不到簾鈎。',32,'全唐诗/poet.song.206000.json','["人世應無第二樓，暮雲飛不到簾鈎。", "未開寶鏡青冥裏，先賞冰輪碧海頭。"]'),
('036c82f8-fb53-4f22-bfcf-7d3d2f5884f4','沖虛觀','彭耜','宋','宋诗','song-poetry','','[]','天風吹衣霞颼颼，叱馭從南來羅浮。',64,'全唐诗/poet.song.206000.json','["天風吹衣霞颼颼，叱馭從南來羅浮。", "何謂玉笥搗藥鳥，亦於石樓喧夜愁。", "仙翁定知野人到，道觀聊爲朝真留。", "一粒刀圭吾不與，大椿那有八千秋。"]'),
('5ad437b6-e0cf-4c3b-aa71-f844e2770f61','句  其一','彭耜','宋','宋诗','song-poetry','','[]','判事有花皆可錄，諫書無草豈求名。',16,'全唐诗/poet.song.206000.json','["判事有花皆可錄，諫書無草豈求名。"]'),
('64bed4e9-27ed-4825-a270-fc31b0389e77','句  其二','彭耜','宋','宋诗','song-poetry','','[]','家爲買琴添舊債，厨因養鶴減晨炊。',16,'全唐诗/poet.song.206000.json','["家爲買琴添舊債，厨因養鶴減晨炊。"]'),
('9873f26b-15fc-40c5-9910-4f8ca246a6ae','句','包真人','宋','宋诗','song-poetry','','[]','待吾了却人間事，然後相從面紫羅。',16,'全唐诗/poet.song.206000.json','["待吾了却人間事，然後相從面紫羅。"]'),
('fbbe47b8-2070-4a0b-bce4-566c01876719','玉溪雪夜','嚴粲','宋','宋诗','song-poetry','','[]','雪霽天夜白，月上江空明。',60,'全唐诗/poet.song.206000.json','["雪霽天夜白，月上江空明。", "飲散客就船，萬籟沈三更。", "誰家竹籬岸，摸索疎枝橫。", "不著色與香，令我毛骨清。", "醉魂乘沆瀣，看舞婆羅城。"]'),
('0c31359d-47ca-422b-8e4c-fcff50b6a238','獨往','嚴粲','宋','宋诗','song-poetry','','[]','一徑歷紆餘，獨往未到處。',48,'全唐诗/poet.song.206000.json','["一徑歷紆餘，獨往未到處。", "豈曰巖泉幽，心閒即真趣。", "蕭蕭松有聲，依依花自開。", "樵翁向我笑，問我何從來。"]'),
('e989952a-c68f-4839-98cc-7dae6de343ba','昭君怨','嚴粲','宋','宋诗','song-poetry','','[]','欲洗鉛華浄，那須畫手工。',24,'全唐诗/poet.song.206000.json','["欲洗鉛華浄，那須畫手工。", "玉顔翻自誤，不似舊圖中。"]'),
('39133109-57d1-44a1-b113-bc8e783d1433','送黄炳','嚴粲','宋','宋诗','song-poetry','','[]','未盡連牀話，匆匆又語離。',48,'全唐诗/poet.song.206000.json','["未盡連牀話，匆匆又語離。", "襟期無限事，書寄若爲辭。", "昔別已十載，重逢還幾時。", "孤舟明夜月，何處照相思。"]'),
('7bb8a206-4720-44e3-be5b-dae37fd96a10','望彭蠡','嚴粲','宋','宋诗','song-poetry','','[]','萬壑氣交會，今知楚澤雄。',48,'全唐诗/poet.song.206000.json','["萬壑氣交會，今知楚澤雄。", "水明纔辨樹，霧合忽迷空。", "遠浦沈初月，孤舟亂去鴻。", "闌干已愁思，漁唱入蘋風。"]'),
('55ef9152-dcb8-4a37-9dc1-9030286aee77','春晚','嚴粲','宋','宋诗','song-poetry','','[]','向來得意在煙霞，失脚黄塵負歲華。',32,'全唐诗/poet.song.206000.json','["向來得意在煙霞，失脚黄塵負歲華。", "過却海棠渾不省，夢中猶自咏梅花。"]'),
('624b5518-da2e-4fbb-b943-a786c6680327','秋入','嚴粲','宋','宋诗','song-poetry','','[]','秋入蘋風白浪生，癡雲未放楚天晴。',32,'全唐诗/poet.song.206000.json','["秋入蘋風白浪生，癡雲未放楚天晴。", "青山湖水知何處，中有斜陽一段明。"]'),
('1d0663a6-b75b-4b35-a2b0-da1d8e28bf6d','陽關圖','嚴粲','宋','宋诗','song-poetry','','[]','人人腸斷渭城歌，誰獨持竿面碧波。',32,'全唐诗/poet.song.206000.json','["人人腸斷渭城歌，誰獨持竿面碧波。", "可是無情如木石，祇應此地別離多。"]'),
('713c997d-8e8a-40a9-843a-2f8efb2bd476','月夜與張輯論詩','嚴粲','宋','宋诗','song-poetry','','[]','凉露初長夜，纖雲浄盡時。',48,'全唐诗/poet.song.206000.json','["凉露初長夜，纖雲浄盡時。", "幾人還對月，與客共論詩。", "苦思常難穩，閒題或更奇。", "不應誇末俗，準擬古人知。"]'),
('8cf71d6b-9ac6-4990-8a7c-30f70f448287','自樂平閲視渡舟取道太陽渡宿地藏院','嚴粲','宋','宋诗','song-poetry','','[]','康山問民涉，陽渡平地訟。',72,'全唐诗/poet.song.206000.json','["康山問民涉，陽渡平地訟。", "朅來招提宿，疏峰結飛棟。", "研丹啟囊書，點勘自成諷。", "佛香觸深悟，僧茗來清供。", "陽頹嵐氣生，鴻沒天宇空。", "向來山中樂，忽忽豈其夢。"]'),
('6609e297-01d9-4f46-b61f-4ca37e881609','盤谷圖','嚴粲','宋','宋诗','song-poetry','','[]','聲利爭馳毫末間，幾人能得健時閒。',32,'全唐诗/poet.song.206000.json','["聲利爭馳毫末間，幾人能得健時閒。", "不須展畫相撩弄，昨夜秋風憶故山。"]'),
('1c5d757e-7c6c-431b-8e7e-3800622f7af8','見梅','嚴粲','宋','宋诗','song-poetry','','[]','絕憐生意上寒枝，幾度巡簷錯恨遲。',32,'全唐诗/poet.song.206000.json','["絕憐生意上寒枝，幾度巡簷錯恨遲。", "數點疎花人未見，窗間早被月明知。"]'),
('6d73f556-aa5b-41be-baff-729dcba09269','春歸','嚴粲','宋','宋诗','song-poetry','','[]','抵死連宵雨不休，今朝晴景莫登樓。',32,'全唐诗/poet.song.206000.json','["抵死連宵雨不休，今朝晴景莫登樓。", "杜鵑啼得春歸了，風裏楊花點點愁。"]'),
('7aebc131-fb6e-464e-a0e9-ca9637253cc2','薦福寺','嚴粲','宋','宋诗','song-poetry','','[]','石徑秋痕苔蘚深，誰將清氣潤脩林。',32,'全唐诗/poet.song.206000.json','["石徑秋痕苔蘚深，誰將清氣潤脩林。", "戴公堤上古時月，幾度凉宵照苦吟。"]'),
('87d58728-8c86-4e3f-8245-d5ed770c8046','招提遊  其一','嚴粲','宋','宋诗','song-poetry','','[]','幽尋愜所適，蘭若白石靜。',48,'全唐诗/poet.song.206000.json','["幽尋愜所適，蘭若白石靜。", "天籟鳴松壑，古意滿苔徑。", "清泉醒客心，啼鳥喚僧定。", "留連不能去，翫月歸路永。"]'),
('f2d73644-54a3-484e-9dfc-50ff84a8517e','招提遊  其二','嚴粲','宋','宋诗','song-poetry','','[]','煩抱忽如遺，僧境得清勝。',48,'全唐诗/poet.song.206000.json','["煩抱忽如遺，僧境得清勝。", "花發巖洞幽，雲生窗戶冷。", "來驂樹陰直，歸棹川光暝。", "遺思山蒼蒼，半空聞夕磬。"]'),
('2238264e-d4de-4f4f-805e-3916dcc6d1ca','拾橡亭爲黄炳賦','嚴粲','宋','宋诗','song-poetry','','[]','世上危機富貴身，由來著意鬼神嗔。',32,'全唐诗/poet.song.206000.json','["世上危機富貴身，由來著意鬼神嗔。", "到頭鐘鼎誰消得，正要山中拾橡人。"]'),
('9a5a8394-646f-466e-9636-b25225a6c0a8','林和靖祠','嚴粲','宋','宋诗','song-poetry','','[]','白雲人已矣，古屋自蒼苔。',48,'全唐诗/poet.song.206000.json','["白雲人已矣，古屋自蒼苔。", "林下誤疑鶴，水邊空見梅。", "市人携酒至，歌女棹船囘。", "檢點幽棲處，湖光似向來。"]'),
('e27a46e4-116a-43f6-92f6-f46f0d7c8821','元上人見訪','嚴粲','宋','宋诗','song-poetry','','[]','昔子青青佩，重逢怪衲衣。',48,'全唐诗/poet.song.206000.json','["昔子青青佩，重逢怪衲衣。", "樊籠留不住，雲水靜相依。", "習氣餘詩句，枯禪墮佛機。", "東湖自塵外，還带夕陽歸。"]'),
('6ced16c8-56a6-4581-af59-373d5e096a85','憶張輯','嚴粲','宋','宋诗','song-poetry','','[]','畏景如焚客路塵，寂寥山店獨吟身。',32,'全唐诗/poet.song.206000.json','["畏景如焚客路塵，寂寥山店獨吟身。", "多情唯有別時月，低傍茅簷巧趁人。"]'),
('8de6a19b-46f5-46fb-bf40-9de82cd056d7','宿石潭寺寄黄炳','嚴粲','宋','宋诗','song-poetry','','[]','昨夜湖心共泊船，一天星露宿寒煙。',32,'全唐诗/poet.song.206000.json','["昨夜湖心共泊船，一天星露宿寒煙。", "朝來極目無洲渚，知采蘋花何處邊。"]'),
('5c2c3156-d254-4135-93d8-1e295e9c0582','畫梅蘭竹石','嚴粲','宋','宋诗','song-poetry','','[]','正憶吟窗占竹坡，風煙觸眼奈愁何。',32,'全唐诗/poet.song.206000.json','["正憶吟窗占竹坡，風煙觸眼奈愁何。", "梅蘭只作從前瘦，石上蒼苔別後多。"]'),
('1f851142-b03d-4d67-9906-bdf92860f342','春恨','嚴粲','宋','宋诗','song-poetry','','[]','馬上東風吹酒醒，空將春恨到江亭。',32,'全唐诗/poet.song.206000.json','["馬上東風吹酒醒，空將春恨到江亭。", "飛香寂寞無尋處，煙映晚山深淺青。"]'),
('282754d2-ec32-45d1-9262-5964c30349fb','廬陵黄炳築亭所居侯山扁以赤松子自號赤松亭長之官鄂渚爲賦詩','嚴粲','宋','宋诗','song-poetry','','[]','仙人遺世不曾愁，但欲相期汗漫遊。',32,'全唐诗/poet.song.206000.json','["仙人遺世不曾愁，但欲相期汗漫遊。", "亭長祇今閒未得，南樓孤嘯望神州。"]'),
('772c4e4e-e395-4924-990a-286d5794294b','霧中早行','嚴粲','宋','宋诗','song-poetry','','[]','行人模糊畫中影，高樹夭矯空際雲。',32,'全唐诗/poet.song.206000.json','["行人模糊畫中影，高樹夭矯空際雲。", "樓臺幾處半隠見，三島夢斷猶紛紜。"]'),
('bd107089-577a-4d66-8b59-39901e2ac7be','秋思','嚴粲','宋','宋诗','song-poetry','','[]','風落葉間殘點雨，月窺窗下不眠人。',32,'全唐诗/poet.song.206000.json','["風落葉間殘點雨，月窺窗下不眠人。", "秋清一片無誰領，併作詩愁入鬢新。"]'),
('15cc8a04-3265-404f-b860-c42f024e6c8e','松雪','嚴粲','宋','宋诗','song-poetry','','[]','陰崖未知晴，松雪自在白。',24,'全唐诗/poet.song.206000.json','["陰崖未知晴，松雪自在白。", "可恨晚風顛，飛寒亂苔石。"]'),
('f4eb7646-2dca-4c55-8b4e-b72df0fb2ae2','次韻宴坐畫圖','嚴粲','宋','宋诗','song-poetry','','[]','京塵倦來歸，故山喜還璧。',192,'全唐诗/poet.song.206000.json','["京塵倦來歸，故山喜還璧。", "淡交松桂在，昔別猿鶴憶。", "晚知閒味深，甘爲幽討惑。", "尚念身在山，佳處恐未識。", "看山須全境，一覽盡目力。", "伊誰有巨軸，亭亭挂空碧。", "吾聞古靈匠，能事略翰墨。", "盤礴溟涬初，太素含黼飾。", "妙手斡玄微，鍊此石五色。", "天機一呈露，真宰惜不得。", "寫出萬古愁，蒼茫思何極。", "煙村带遠市，雲樹出峭壁。", "有人閒倚欄，飛鳥亦自適。", "俗間重小景，局促無奇特。", "五日十日畫，大類宋楮刻。", "誰會悠然心，醉來眠對客。"]'),
('eb3ee62f-358d-42dc-ac66-e939b9b19dd5','酴醿','嚴粲','宋','宋诗','song-poetry','','[]','東風暖迸龍蛇起，麗日晴烘玉雪香。',32,'全唐诗/poet.song.206000.json','["東風暖迸龍蛇起，麗日晴烘玉雪香。", "可惜開時春向晚，不教桃李見清芳。"]'),
('6f11b593-21c3-4618-917d-eacd8e91f5e1','客裏','嚴粲','宋','宋诗','song-poetry','','[]','客裏何知度歲華，春風香却一番花。',32,'全唐诗/poet.song.206000.json','["客裏何知度歲華，春風香却一番花。", "山行轉處聞雞犬，楊柳陰陰賣酒家。"]'),
('c3aa43e6-5c31-4098-afb6-b3b7ccea788f','紀夢','嚴粲','宋','宋诗','song-poetry','','[]','煙島空濛一鶴飛，天風滿袖自吟詩。',32,'全唐诗/poet.song.206000.json','["煙島空濛一鶴飛，天風滿袖自吟詩。", "覺來猶似非人世，花影欄干月上時。"]'),
('fc51b8c3-8669-4327-8fe4-b75672c4f7aa','送張輯游宣城','嚴粲','宋','宋诗','song-poetry','','[]','君撫淵明底樣琴，肯於絃上要知音。',64,'全唐诗/poet.song.206000.json','["君撫淵明底樣琴，肯於絃上要知音。", "相逢塵事不挂口，別去清愁總上心。", "聽雨夜牀孤舊約，看雲秋壑想幽尋。", "他年跨鶴相過否，應笑浮名雪滿簪。"]'),
('9974bebb-0396-4a6d-aa68-006e91f16b0c','道中見茶花','嚴粲','宋','宋诗','song-poetry','','[]','朝來露溼欲寒天，誰賞幽芳古道邊。',32,'全唐诗/poet.song.206000.json','["朝來露溼欲寒天，誰賞幽芳古道邊。", "風味十分留貢焙，浮花正自不須妍。"]'),
('8236cbc2-47b3-4034-9a28-5dd9e5edaab0','巧夕添丁','嚴粲','宋','宋诗','song-poetry','','[]','書來知有喜，客夢應維熊。',48,'全唐诗/poet.song.206000.json','["書來知有喜，客夢應維熊。", "久作庭闈別，遥知笑語同。", "充閭非我願，釣瀨是家風。", "莫學天孫巧，朱愚肖乃翁。"]'),
('334860ec-6beb-4664-9413-8749fc8d3aaf','琵琶洲','嚴粲','宋','宋诗','song-poetry','','[]','琵琶古怨猶淒清，何年一抹橫煙汀。',192,'全唐诗/poet.song.206000.json','["琵琶古怨猶淒清，何年一抹橫煙汀。", "人言隨波高下如浮萍，神鼇背負能亭亭。", "不知水仙宮殿碧皎潔，玉絃遥映雲錦屏。", "胡沙萬里音塵絕，獨與鸚鵡愁青冥。", "天際歸舟認髣髴，江頭寒月傷伶仃。", "悄然夜久天籟起，往往恍惚游百靈。", "秋風嫋嫋兮水泠泠，俗耳箏笛兮誰能聽。", "我眼如耳耳如鼻，妙處不言心獨醒。", "鈞天住奏三千齡，石鍾水樂遺林坰，豈有寶器終飄零。", "一朝詄蕩開天扃，帝命下取呵六丁。", "陶梭共起變化隨雷霆，古餘山色空青青。"]'),
('ee60f70b-edf1-46a2-a276-60f6dddead39','池陽道中','嚴粲','宋','宋诗','song-poetry','','[]','脫葉舞風過別岸，溼雲含雨上晴天。',32,'全唐诗/poet.song.206000.json','["脫葉舞風過別岸，溼雲含雨上晴天。", "脩途喜借晚凉得，幽鳥一聲生翠煙。"]'),
('93e24af6-d412-4d45-ab20-74dfa54819b6','挽陳邵武','嚴粲','宋','宋诗','song-poetry','','[]','前輩聞如此，今人見未多。',48,'全唐诗/poet.song.206000.json','["前輩聞如此，今人見未多。", "難將通介論，不在語言科。", "胄監開華近，樵川借撫摩。", "鄉評最期望，一夢只南柯。"]'),
('e47e7de1-736d-4df0-8f15-1949fe8607f9','夜投荒店戲成','嚴粲','宋','宋诗','song-poetry','','[]','喚起吹松火，開門問带嗔。',48,'全唐诗/poet.song.206000.json','["喚起吹松火，開門問带嗔。", "隨行曾有米，同伴幾何人。", "亂稈鋪添薦，殘籬拾作薪。", "夜寒難得酒，煩扣隔山鄰。"]'),
('2fe47170-75e2-4cd9-9495-cea14521bc54','被檄樂平至鳴溪渡有山與南豐軍山同名者予昔從嶺庵謝先生夢得游先生于湖畏友也豪於詩悅軍山之峭拔暢其吟懷自昭武徙家于市山築室曰西窗以朝夕對焉嘗命余記之余時從西窗樽酒論文爲樂如是者十載今先生已矣感而賦詩','嚴粲','宋','宋诗','song-poetry','','[]','江西絕頂插晴空，此地山名偶自同。',32,'全唐诗/poet.song.206000.json','["江西絕頂插晴空，此地山名偶自同。", "喚起西窗十年夢，一樽何處酹詩翁。"]'),
('17a82ed4-7880-4c3a-b1d4-09195ae48df1','重到地藏院','嚴粲','宋','宋诗','song-poetry','','[]','泥濘行良苦，青山且眼前。',48,'全唐诗/poet.song.206000.json','["泥濘行良苦，青山且眼前。", "題詩如昨日，倒指已三年。", "僧榻寒宵雨，漁村落照煙。", "薄游聊復爾，終擬老林泉。"]'),
('43a5a2b7-11d7-44b6-adfa-0136abbb7b1c','寄張輯','嚴粲','宋','宋诗','song-poetry','','[]','不見吾張輯，新詩何處吟。',48,'全唐诗/poet.song.206000.json','["不見吾張輯，新詩何處吟。", "身留江介遠，秋入夜凉深。", "燈影還家夢，蛩聲倦客心。", "歸來及嘉節，細把菊花斟。"]'),
('6546c9b2-aebb-4131-ac5a-680ba77627ab','建德縣梅山寺','嚴粲','宋','宋诗','song-poetry','','[]','公退逢長日，清游到寶坊。',48,'全唐诗/poet.song.206000.json','["公退逢長日，清游到寶坊。", "山圍露天小，徑遶引溪長。", "苔壁晴雲溼，松軒暑月凉。", "鐘聲半歸路，回首暮蒼蒼。"]'),
('57f71093-a70e-4402-86b4-5a05e466e0c9','叨第後日者自謂奇中索詩','嚴粲','宋','宋诗','song-poetry','','[]','兒時意氣謾騎鯨，幾向欄干袖手凭。',32,'全唐诗/poet.song.206000.json','["兒時意氣謾騎鯨，幾向欄干袖手凭。", "今日逢君成一笑，却慚窗下讀書燈。"]'),
('42b885d3-ccbf-4739-a2c8-106272792a38','風雨宿湖心','嚴粲','宋','宋诗','song-poetry','','[]','渺渺平湖四接天，孤舟曾繫夜來船。',32,'全唐诗/poet.song.206000.json','["渺渺平湖四接天，孤舟曾繫夜來船。", "持鞭又逐風塵去，却憶秋篷聽雨眠。"]'),
('a68fe9f5-0258-472e-89ee-005446bc3ec9','新晴','嚴粲','宋','宋诗','song-poetry','','[]','滑路愁騎馬，晴天好放船。',48,'全唐诗/poet.song.206000.json','["滑路愁騎馬，晴天好放船。", "水紋摇倒壁，花影弄澄川。", "夢寐驅馳在，光陰少壯遷。", "心期猶浩蕩，搔首白鷗前。"]'),
('497e9f35-2928-4531-8a85-70720f426d45','舟中夜雪','嚴粲','宋','宋诗','song-poetry','','[]','落帆侵夜色，客思正悽悽。',48,'全唐诗/poet.song.206000.json','["落帆侵夜色，客思正悽悽。", "風撼瀟湘覆，雲連宇宙低。", "灑篷吹乍急，欹枕聽還迷。", "懶惰無清興，誰人訪剡溪。"]'),
('5d78f465-455f-4aee-8d52-ccbc86569649','七夕','嚴粲','宋','宋诗','song-poetry','','[]','纖巧逐時新，誰將大雅陳。',24,'全唐诗/poet.song.206000.json','["纖巧逐時新，誰將大雅陳。", "天孫古機錦，笑殺世間人。"]'),
('c238b8f4-bb55-49b5-a6a4-5f468dcaa22d','送戴式之','嚴粲','宋','宋诗','song-poetry','','[]','自小尋詩出，江湖今白頭。',48,'全唐诗/poet.song.206000.json','["自小尋詩出，江湖今白頭。", "應嫌少陵讀，不似子長遊。", "風雨夜愁枕，鶑花春醉樓。", "吟邊消息好，懷古問沙鷗。"]'),
('e9f0dca1-20d4-41cb-aece-a9e2f57a0989','茅舍','嚴粲','宋','宋诗','song-poetry','','[]','村居遠城市，獨木渡塘坳。',48,'全唐诗/poet.song.206000.json','["村居遠城市，獨木渡塘坳。", "迸笋補籬竹，落松添屋茅。", "童歸携酒榼，客至得鹽包。", "隨分山中好，低簷燕有巢。"]'),
('14132cee-6002-4d3a-bcd2-d66b3832a139','憩田家','嚴粲','宋','宋诗','song-poetry','','[]','晝問田家憩，相呼隔短籬。',48,'全唐诗/poet.song.206000.json','["晝問田家憩，相呼隔短籬。", "負薪髽引犢，挑菜跣携兒。", "沙井和蝦汲，村舂夾稻炊。", "老翁評貴糶，覼縷舊年時。"]'),
('e9b5d6f4-fbb7-4ed2-9c76-be5fd4ec9891','過江東','嚴粲','宋','宋诗','song-poetry','','[]','落花時節過江東，濃綠山頭間小紅。',32,'全唐诗/poet.song.206000.json','["落花時節過江東，濃綠山頭間小紅。", "野店日長春寂寂，柳陰摇颺酒旗風。"]'),
('1874d80a-b749-442a-9b7c-94020d677536','騎牛圖','嚴粲','宋','宋诗','song-poetry','','[]','乃翁騎牛馿馱兒，松間提挈羣童隨。',32,'全唐诗/poet.song.206000.json','["乃翁騎牛馿馱兒，松間提挈羣童隨。", "馿逢短橋兒回顧，牛背推敲了不知。"]'),
('4ef82308-946c-4551-b432-42380526b27e','戲友人','嚴粲','宋','宋诗','song-poetry','','[]','今朝有清興，無處覓詩人。',48,'全唐诗/poet.song.206000.json','["今朝有清興，無處覓詩人。", "寺占房空鎖，窗窺榻有塵。", "尋芳知尚早，報謁未應頻。", "只在城中醉，煙雲滿澹津。"]'),
('3baa9daf-3043-4b2d-8b76-3f58f1e04801','孤雁','嚴粲','宋','宋诗','song-poetry','','[]','一雁度岑寂，流空音響哀。',48,'全唐诗/poet.song.206000.json','["一雁度岑寂，流空音響哀。", "雲沙天地闊，霜雪羽毛摧。", "力小知機早，心危見影猜。", "蘆洲迷處所，飛遶正徘徊。"]'),
('0a6c3fba-0f73-40c7-bec4-5dce50e22b4a','蒙齋先生賦張通守佚老堂次韻','嚴粲','宋','宋诗','song-poetry','','[]','拂衣歸共白雲間，佚老堂中天地寬。',64,'全唐诗/poet.song.206000.json','["拂衣歸共白雲間，佚老堂中天地寬。", "黄髮可教供鞅掌，青山聊足對高寒。", "杖藜行樂春風軟，紙帳佳眠曉日團。", "林下未應忘世事，併煩寄語謝家安。"]'),
('cd6e616c-f606-4769-9ce0-ca6a15a21826','菊','嚴粲','宋','宋诗','song-poetry','','[]','寒林色枯槁，粲粲籬菊鮮。',48,'全唐诗/poet.song.206000.json','["寒林色枯槁，粲粲籬菊鮮。", "冷艷無俗韻，孤芳弄秋妍。", "金晶與高絜，未覺陽和偏。", "豈無兒女花，誰能制頹年。"]'),
('9186d5ba-9c50-4269-8bc8-838559789109','歐陽道士歸自臨安','嚴粲','宋','宋诗','song-poetry','','[]','洞穴雲生窗戶凉，道人宴坐但焚香。',32,'全唐诗/poet.song.206000.json','["洞穴雲生窗戶凉，道人宴坐但焚香。", "向來遊遍王侯第，還似山林意味長。"]'),
('7dd9f3bf-6759-48cf-a31a-8baba3a281d9','張輯馮去非話別','嚴粲','宋','宋诗','song-poetry','','[]','此夕真成別，幽懷欲語誰。',24,'全唐诗/poet.song.206000.json','["此夕真成別，幽懷欲語誰。", "梅花霜月曉，獨起詠君詩。"]'),
('d64295bc-4fe5-4415-ba83-2482400926c7','夜讀晉書','嚴粲','宋','宋诗','song-poetry','','[]','南來未省有良圖，可更清談傲五胡。',32,'全唐诗/poet.song.206000.json','["南來未省有良圖，可更清談傲五胡。", "撫卷興懷千載事，一窗風露夜檠孤。"]'),
('fb94949f-0011-4028-bc52-0fbbaf930cd2','午憩僧房','嚴粲','宋','宋诗','song-poetry','','[]','黄塵吹不到禪房，窗紙風翻葉葉凉。',32,'全唐诗/poet.song.206000.json','["黄塵吹不到禪房，窗紙風翻葉葉凉。", "觸熱行來牽晝夢，孤蓬聽雨下瀟湘。"]'),
('ec5b8487-9273-4f49-9941-e4a93e4d466a','憶山中','嚴粲','宋','宋诗','song-poetry','','[]','山中桂香滿，無復向來遊。',24,'全唐诗/poet.song.206000.json','["山中桂香滿，無復向來遊。", "官事何時了，一年孤負秋。"]'),
('4a1118c1-d44f-4085-b946-5ddbd7ef6135','即事','嚴粲','宋','宋诗','song-poetry','','[]','僧屋藏深塢，漁舟带遠汀。',24,'全唐诗/poet.song.206000.json','["僧屋藏深塢，漁舟带遠汀。", "誰教雙白鳥，來點暮山青。"]'),
('d2eeaa39-8cb6-485d-9249-27ce5fa7d616','野興','嚴粲','宋','宋诗','song-poetry','','[]','身閑歸未得，野興日翛然。',48,'全唐诗/poet.song.206000.json','["身閑歸未得，野興日翛然。", "抱牘無來吏，尋詩即散仙。", "盃明松罅月，座引石根泉。", "有客知余意，清風三兩弦。"]'),
('144ced99-a9b2-4d9c-ab4c-d2ce5e0a589c','重九後五日遊齊山','嚴粲','宋','宋诗','song-poetry','','[]','官癡縛辰酉，節物如相負。',48,'全唐诗/poet.song.206000.json','["官癡縛辰酉，節物如相負。", "茲遊未覺晚，黄花落吾手。", "沒鷗江自迥，脫葉山新瘦。", "淒涼千載心，西風一搔首。"]'),
('93316f61-6f94-4906-8732-12fb2fad1f46','湘中','嚴粲','宋','宋诗','song-poetry','','[]','千古懷沙恨，淒涼何處論。',48,'全唐诗/poet.song.206000.json','["千古懷沙恨，淒涼何處論。", "坐看宗國事，安用一身存。", "落葉西風岸，孤舟半夜猿。", "年年江月白，爲照獨醒魂。"]'),
('144c206a-3ed7-4a08-8c07-75c2ad2534cd','寓京城和曾左曹韻  其一','嚴粲','宋','宋诗','song-poetry','','[]','日日思君君不知，京塵染盡带來衣。',32,'全唐诗/poet.song.206000.json','["日日思君君不知，京塵染盡带來衣。", "客心正自傷飄泊，更看湖邊花片飛。"]'),
('70312654-04fd-4460-b7fc-f706730614c1','寓京城和曾左曹韻  其二','嚴粲','宋','宋诗','song-poetry','','[]','車馬聲中又日斜，可堪芳草思天涯。',32,'全唐诗/poet.song.206000.json','["車馬聲中又日斜，可堪芳草思天涯。", "來時憶別山中桂，今見長安梔子花。"]'),
('3eeba09f-ce7a-4478-916f-1ba9532e34f3','閒居','嚴粲','宋','宋诗','song-poetry','','[]','盡日門前草，青青不染塵。',48,'全唐诗/poet.song.206000.json','["盡日門前草，青青不染塵。", "生書方破卷，幽鳥忽啼春。", "失意成高興，多閒信懶身。", "不須憂世事，廊廟有經綸。"]'),
('9165373d-c833-4cec-a62f-0cb730efbd0f','觀北來倡優','嚴粲','宋','宋诗','song-poetry','','[]','見說中原極可哀，更無飛鳥下蒿萊。',32,'全唐诗/poet.song.206000.json','["見說中原極可哀，更無飛鳥下蒿萊。", "吾儂尚笑倡優拙，欲喚新翻歌舞來。"]'),
('fb168df3-4070-468e-a8e8-758e229f775b','李賈携詩卷見訪賈與嚴滄浪遊','嚴粲','宋','宋诗','song-poetry','','[]','石屏新卷裏，曾得見君詩。',48,'全唐诗/poet.song.206000.json','["石屏新卷裏，曾得見君詩。", "大冊煩來教，平生慰夢思。", "高標去塵遠，古調少人知。", "汝與吾宗好，風騷更屬誰。"]'),
('a5254f75-1e15-4efd-a1cf-ceae005841f2','新竹','嚴粲','宋','宋诗','song-poetry','','[]','樹頭不動天無風，六月還當日正中。',32,'全唐诗/poet.song.206000.json','["樹頭不動天無風，六月還當日正中。", "唯有滿林新長竹，別生凉意襲簾櫳。"]'),
('e1df9972-3033-4d70-ba0e-9d31984a7b98','月','嚴粲','宋','宋诗','song-poetry','','[]','只道今宵月出遲，雲間不覺上多時。',32,'全唐诗/poet.song.206000.json','["只道今宵月出遲，雲間不覺上多時。", "夜深花影如清晝，何處山頭一笛吹。"]'),
('312475ff-cf8f-4689-8351-21f57155be7f','二水聞角','嚴粲','宋','宋诗','song-poetry','','[]','少日鄉閭不解愁，閒聽畫角起譙樓。',32,'全唐诗/poet.song.206000.json','["少日鄉閭不解愁，閒聽畫角起譙樓。", "西風依舊闌干月，獨自瀟湘萬里秋。"]'),
('e41b59ce-5300-461d-acae-7c6ea53fe993','軍行','嚴粲','宋','宋诗','song-poetry','','[]','野人自說老爲農，舊識戎裝紙畫中。',32,'全唐诗/poet.song.206000.json','["野人自說老爲農，舊識戎裝紙畫中。", "近日軍行渾見慣，兒童嬉戲學刀弓。"]'),
('e06b0be9-1427-4c53-af45-2a45bc28a5ab','子陵灘  其一','嚴粲','宋','宋诗','song-poetry','','[]','西風吹雨暮江寒，想見當年獨把竿。',32,'全唐诗/poet.song.206000.json','["西風吹雨暮江寒，想見當年獨把竿。", "不是君王思故舊，何人知有子陵灘。"]'),
('3598d667-9348-4018-a0f8-517053e13846','子陵灘  其二','嚴粲','宋','宋诗','song-poetry','','[]','一榻從容話歲寒，相忘共作布衣看。',32,'全唐诗/poet.song.206000.json','["一榻從容話歲寒，相忘共作布衣看。", "雲臺諸子成何事，萬古清風一釣竿。"]'),
('55489518-3333-4491-ba6a-e4cab2d11160','汎湖','嚴粲','宋','宋诗','song-poetry','','[]','四邊天共水漫漫，身在鴻濛縹渺間。',32,'全唐诗/poet.song.206000.json','["四邊天共水漫漫，身在鴻濛縹渺間。", "忽見浮空青一抹，舟中人說是湖山。"]'),
('4d54a38c-14d5-41fc-8e12-2956767c9226','慈湖墨竹  其一','嚴粲','宋','宋诗','song-poetry','','[]','先生萬慮盡空時，元氣渾淪可得窺。',32,'全唐诗/poet.song.206000.json','["先生萬慮盡空時，元氣渾淪可得窺。", "還有發生消息在，揮毫煙雨一枝枝。"]'),
('fba05db6-fad8-4946-97dc-8124b71878f6','慈湖墨竹  其二','嚴粲','宋','宋诗','song-poetry','','[]','戲筆偶然成此耳，直將造化論錙銖。',32,'全唐诗/poet.song.206000.json','["戲筆偶然成此耳，直將造化論錙銖。", "不知茂叔庭前草，有此風煙一段無。"]'),
('70d99736-f076-4951-82a5-a86a6eebabc2','未開梅','嚴粲','宋','宋诗','song-poetry','','[]','老樹天機早，潛回一點春。',48,'全唐诗/poet.song.206000.json','["老樹天機早，潛回一點春。", "寒梢方蓓蕾，瘦影已精神。", "冷淡看前輩，芳菲總後塵。", "更須香共色，未是監花人。"]'),
('d6b3a022-78de-4d2c-8226-0ca0cec54290','客裏','嚴粲','宋','宋诗','song-poetry','','[]','客裏還來此，寒燈耿獨吟。',48,'全唐诗/poet.song.206000.json','["客裏還來此，寒燈耿獨吟。", "一官江國夢，十載草堂心。", "木落秋聲小，蛩孤夜思深。", "驅馳空自許，冉冉鬢霜侵。"]'),
('79f1a2dd-25ce-4f60-9126-9b782c51d7d8','戲詩友談仙','嚴粲','宋','宋诗','song-poetry','','[]','君期汗漫遊，不敢問所適。',72,'全唐诗/poet.song.206000.json','["君期汗漫遊，不敢問所適。", "贈別亦何有，當辦鶴一隻。", "還疑是凡羽，不任載仙質。", "乘煙寧假此，聊以壯行色。", "淹留非牽俗，應未得良日。", "空令施肩吾，久待問詩律。"]'),
('ca9e7d2d-59d1-4196-8e46-8834009bcdbd','秋懷','嚴粲','宋','宋诗','song-poetry','','[]','秋懷不到夢，歷歷數寒更。',48,'全唐诗/poet.song.206000.json','["秋懷不到夢，歷歷數寒更。", "坐得楚天白，吟教湘水清。", "殘燈摇壁影，片葉墜階聲。", "起看孤城霧，人間事又生。"]'),
('683a0173-3b4a-43d1-ab6a-49bd27bd5e7f','初注清湘令寄馮深居','嚴粲','宋','宋诗','song-poetry','','[]','深居定何處，無便寄聲頻。',48,'全唐诗/poet.song.206000.json','["深居定何處，無便寄聲頻。", "舊別芝山月，相思楚水春。", "白雲生夢遠，華髮折腰新。", "料得今書到，看題笑故人。"]'),
('784037fc-de36-46b2-8a77-96c3968e0f8d','上饒界首傷曾殊','嚴粲','宋','宋诗','song-poetry','','[]','故人曾此賦梅詩，人共梅花一夢非。',32,'全唐诗/poet.song.206000.json','["故人曾此賦梅詩，人共梅花一夢非。", "欲喚青山話前事，西風吹淚溼征衣。"]'),
('080329e8-7a56-463f-9835-37d937882244','秋風','嚴粲','宋','宋诗','song-poetry','','[]','門與姑山對，溪邊有故廬。',48,'全唐诗/poet.song.206000.json','["門與姑山對，溪邊有故廬。", "別來三徑菊，閒却一樓書。", "水碓長腰米，村船巨口魚。", "秋風歸去好，留滯意何如。"]'),
('68dea4f2-5699-487e-96fa-8faa0468ff5c','戲友人','嚴粲','宋','宋诗','song-poetry','','[]','怪得詩情減一分，知君爲學有新聞。',32,'全唐诗/poet.song.206000.json','["怪得詩情減一分，知君爲學有新聞。", "塵中畢竟閒人少，獨自開樽對白雲。"]'),
('4ad61629-b079-4d31-9d84-57950e373e4e','早行','嚴粲','宋','宋诗','song-poetry','','[]','脩程避晝炎，中夜征夫起。',48,'全唐诗/poet.song.206000.json','["脩程避晝炎，中夜征夫起。", "蟲聲荒郊迥，犬吠衡門閉。", "行行月色淡，微霞露天際。", "永懷高卧人，幽夢繞蒼翠。"]'),
('ac679f53-9d18-4d58-badd-7a92fbf0e09e','西湖','嚴粲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','何處春晴好，西湖元巳朝。',48,'全唐诗/poet.song.206000.json','["何處春晴好，西湖元巳朝。", "馬嘶堤上路，船過柳陰橋。", "敲竹鶴聲起，弄泉花影摇。", "坐看遊客盡，煙水思迢迢。"]'),
('b9ef51f1-a1f7-4085-944a-ef1ca38fc94d','閏九','嚴粲','宋','宋诗','song-poetry','','[]','前月登高去，猶嫌菊未黄。',24,'全唐诗/poet.song.206000.json','["前月登高去，猶嫌菊未黄。", "秋風不相負，特地再重陽。"]'),
('b88caba1-a4d9-43e2-805f-fc4613368733','顔范祠堂','嚴粲','宋','宋诗','song-poetry','','[]','顔范新祠番水陽，邦人來此識綱常。',64,'全唐诗/poet.song.206000.json','["顔范新祠番水陽，邦人來此識綱常。", "海波澒洞孤峰峭，天宇清明一鳳翔。", "英蹟重尋餘古帖，高情猶想賦秋香。", "姦諛骨朽今安在，三歎前賢死不亡。"]'),
('f9290d51-674d-42ac-aa24-3c3ccfa49825','張德慶挽詩  其一','嚴粲','宋','宋诗','song-poetry','','[]','擢第家聲在，通班宦路亨。',48,'全唐诗/poet.song.206000.json','["擢第家聲在，通班宦路亨。", "爲親遲受邑，未老謝專城。", "活計詩書富，歲寒梅竹清。", "閒中將道眼，醉夢笑功名。"]'),
('066f9f70-c72c-4a36-a030-88dfed4cfdc4','張德慶挽詩  其二','嚴粲','宋','宋诗','song-poetry','','[]','九秩猶身健，聯麾見子榮。',48,'全唐诗/poet.song.206000.json','["九秩猶身健，聯麾見子榮。", "笏牀歡節序，鳩杖話平生。", "世久傷零落，吾猶及老成。", "酸風吹苦淚，一爲典刑傾。"]'),
('d083c7df-2179-40a8-b5b8-77e642d78e3e','調古','嚴粲','宋','宋诗','song-poetry','','[]','調古人能聽，眉長世共妍。',48,'全唐诗/poet.song.206000.json','["調古人能聽，眉長世共妍。", "家山夕陽外，心事落鷗邊。", "弟妹知何在，風塵祗自憐。", "孤燈照危坐，不是少林禪。"]'),
('d789fb8a-fba2-4817-b691-4b6ac5fc4775','道傍木犀','嚴粲','宋','宋诗','song-poetry','','[]','路人攀折半成荒，何似山中自在芳。',32,'全唐诗/poet.song.206000.json','["路人攀折半成荒，何似山中自在芳。", "可耐西風相料理，爲誰消得許清香。"]'),
('8fc75b8e-aea0-46f7-ac83-fd2bd511dce8','示園丁','嚴粲','宋','宋诗','song-poetry','','[]','種竹宜疎延夜月，澆花須早趁晨陰。',32,'全唐诗/poet.song.206000.json','["種竹宜疎延夜月，澆花須早趁晨陰。", "溪邊釣石勤時掃，恐有詩人來醉吟。"]'),
('d4a57c7b-e7d4-4039-9aad-43f8ec1354eb','舟中夜酌別鄧均','嚴粲','宋','宋诗','song-poetry','','[]','共對船頭月，通宵語未終。',48,'全唐诗/poet.song.206000.json','["共對船頭月，通宵語未終。", "鄉關幾歲別，筆墨小時同。", "江影高低樹，秋聲斷續鴻。", "相逢渾草草，明日又西東。"]'),
('3e32f84e-784b-4790-beb5-534581d0c2db','發清湘  其一','嚴粲','宋','宋诗','song-poetry','','[]','歸棹將秋色，三湘是勝遊。',48,'全唐诗/poet.song.206000.json','["歸棹將秋色，三湘是勝遊。", "灣回仍小嶼，灘過盡平流。", "臨水聞僧磬，隈巖隠釣舟。", "江頭每佳處，沽酒小夷猶。"]'),
('6d15dbc3-2946-4097-807c-b01e97c3adbb','發清湘  其二','嚴粲','宋','宋诗','song-poetry','','[]','花樹移方活，丁寧莫損殘。',48,'全唐诗/poet.song.206000.json','["花樹移方活，丁寧莫損殘。", "待逢春氣暖，開與後人看。", "酒任隨車載，詩從就柱刊。", "料應吟賞處，說著種時難。"]'),
('aa241a8d-36ff-4759-9aad-0286b411c83a','發清湘  其三','嚴粲','宋','宋诗','song-poetry','','[]','栽樹未花開，其如行色催。',48,'全唐诗/poet.song.206000.json','["栽樹未花開，其如行色催。", "遥憐今歲雪，誰看一庭梅。", "餘俸刊詩卷，歸程賣酒盃。", "輕舟下灘穩，鷗鷺莫驚猜。"]'),
('32d33f9e-e288-4825-8e6c-30b5a853800e','繫舟','嚴粲','宋','宋诗','song-poetry','','[]','古岸人家少，蒼茫此繫舟。',48,'全唐诗/poet.song.206000.json','["古岸人家少，蒼茫此繫舟。", "閨中今夜月，江上晚風秋。", "一水縈寒夢，雙鴻亂遠愁。", "湘源知不惡，吾意肯淹留。"]'),
('9c053ee2-59ed-4150-ad0a-8bf7bdee33da','夜行舟','嚴粲','宋','宋诗','song-poetry','','[]','忽報風波息，梢人倚柁看。',48,'全唐诗/poet.song.206000.json','["忽報風波息，梢人倚柁看。", "開船星斗轉，吹笛水雲寒。", "犬吠知村近，烏啼覺夜闌。", "兒童將白石，敲火趁晨餐。"]'),
('0ca3d626-80fd-43c2-aff8-786b991a679e','道中','嚴粲','宋','宋诗','song-poetry','','[]','客思曉寒凝，初陽樹外昇。',48,'全唐诗/poet.song.206000.json','["客思曉寒凝，初陽樹外昇。", "氣蒸茅屋雪，聲裂野池冰。", "倦路行偏遠，思山隠未能。", "僕夫愁過嶺，遥指最高層。"]'),
('170063df-726a-4835-841c-8ec7a044f367','冬日同趙與臻閒過雷園','嚴粲','宋','宋诗','song-poetry','','[]','地幽元在郭，景好即爲春。',48,'全唐诗/poet.song.206000.json','["地幽元在郭，景好即爲春。", "相約同來者，能閒有幾人。", "風池行墜葉，晴隙走游塵。", "共爾煙霞契，交情深更親。"]'),
('76d1b35f-5196-42ea-bb48-ae71bef3916d','寄鄧均','嚴粲','宋','宋诗','song-poetry','','[]','題書對殘燭，幾日到江濆。',48,'全唐诗/poet.song.206000.json','["題書對殘燭，幾日到江濆。", "故里經年別，清秋此夜分。", "月昏斜映雨，風細慢移雲。", "數雁聲初過，知君不寐聞。"]'),
('ca1e6060-ea35-474c-95bf-76e4d3df32fb','任機宜新圃','嚴粲','宋','宋诗','song-poetry','','[]','小斸煙苔地，春生一笑間。',48,'全唐诗/poet.song.206000.json','["小斸煙苔地，春生一笑間。", "亭邀鄰圃樹，臺挹隔城山。", "幽夢壺天曉，清時幕府閒。", "旋移花盡活，容我醉來攀。"]'),
('d551d69d-e362-4559-9108-7a5fd8a606ac','岳麓寺  其一','嚴粲','宋','宋诗','song-poetry','','[]','幾層攀石磴，高寺白雲邊。',48,'全唐诗/poet.song.206000.json','["幾層攀石磴，高寺白雲邊。", "臺舊懷人古，泉幽想鶴僊。", "遠帆湘浦樹，暮角楚城煙。", "長是登臨處，滄洲意惘然。"]'),
('b725f8b2-eee2-44ed-bf74-8e90d67dc487','岳麓寺  其二','嚴粲','宋','宋诗','song-poetry','','[]','吟到湘江倚釣篷，秋風日日望空濛。',32,'全唐诗/poet.song.206000.json','["吟到湘江倚釣篷，秋風日日望空濛。", "偶來上到闌干處，却指孤城夕照中。"]'),
('906f5a22-bad3-493d-beea-d0d6dfa798e1','次韻菊花山人沈莊可見過之作','嚴粲','宋','宋诗','song-poetry','','[]','借得山中集，塵埃一半侵。',48,'全唐诗/poet.song.206000.json','["借得山中集，塵埃一半侵。", "讀來知句好，老去向誰吟。", "高義先投刺，忘懷肯抱琴。", "茅齋亦相約，樽酒要同斟。"]'),
('850e0d89-659b-4ade-b5bc-272e5ec8a5e5','重過雷園','嚴粲','宋','宋诗','song-poetry','','[]','靜處人來少，園扉本不關。',48,'全唐诗/poet.song.206000.json','["靜處人來少，園扉本不關。", "寒叢淒古徑，落日思空山。", "倚樹吟情遠，臨池立影閒。", "晚林看更好，一抹冷煙還。"]'),
('7248e5cd-00c5-42de-859c-b05804e521ab','湘川逢故人','嚴粲','宋','宋诗','song-poetry','','[]','少小□同巷，分携知幾年。',48,'全唐诗/poet.song.206000.json','["少小□同巷，分携知幾年。", "乍逢如未識，相問轉悽然。", "月色秋看好，潮聲夜聽圓。", "醉來共鄉語，不覺是湘川。"]'),
('c6f5d911-9ed9-45b1-9c07-65d104fb495d','兵火後還里','嚴粲','宋','宋诗','song-poetry','','[]','十載青山幾戰塵，還家何處訪情親。',32,'全唐诗/poet.song.206000.json','["十載青山幾戰塵，還家何處訪情親。", "兒時巷陌今難認，却問新移來住人。"]'),
('caef4e17-6e75-4fb4-a6c6-dba0497e5a47','宿澤心','嚴粲','宋','宋诗','song-poetry','','[]','自從孤棹背鄉關，幾度麻姑夢裏山。',32,'全唐诗/poet.song.206000.json','["自從孤棹背鄉關，幾度麻姑夢裏山。", "此地不知何洞府，石間松蔭水潺潺。"]'),
('3e4d0439-06ba-4016-a603-473a58d7eead','夜發湘城','嚴粲','宋','宋诗','song-poetry','','[]','西風吹客衣，一舸載書歸。',48,'全唐诗/poet.song.206000.json','["西風吹客衣，一舸載書歸。", "肯爲身謀便，而令心事違。", "艣聲江月碎，人影水煙微。", "漸覺寒城遠，沈沈擊柝稀。"]'),
('be105522-0c0f-4bd9-9724-2b60d4380539','雪梅','嚴粲','宋','宋诗','song-poetry','','[]','報道梅邊雪未休，披衣晨起上簾鈎。',32,'全唐诗/poet.song.206000.json','["報道梅邊雪未休，披衣晨起上簾鈎。", "孤根清健元如許，空爲花寒一夜愁。"]'),
('4d38117a-1802-4be4-804f-be9ba1309592','定王臺觀雪','嚴粲','宋','宋诗','song-poetry','','[]','清晨吟思獨憑欄，十二樓中白玉寒。',32,'全唐诗/poet.song.206000.json','["清晨吟思獨憑欄，十二樓中白玉寒。", "此地古來風雪裏，有人惆悵望長安。"]'),
('0ddc0e2c-4f2a-4ad9-8c86-799b0ebb9f0a','有客','嚴粲','宋','宋诗','song-poetry','','[]','有客華陽巾，□□□園竹。',72,'全唐诗/poet.song.206000.json','["有客華陽巾，□□□園竹。", "傲睨若無人，風神動巖谷。", "主人延客語，山中酒新熟。", "飲酣出素書，鳥篆不可讀。", "欲問度世訣，長嘯振林木。", "軒然別我去，舉頭但黄鵠。"]'),
('2c448ede-1846-4e94-b1ae-6f27411f5de7','樂齋','嚴粲','宋','宋诗','song-poetry','','[]','顔巷當年事，同門自少知。',48,'全唐诗/poet.song.206000.json','["顔巷當年事，同門自少知。", "誰言公子貴，心與古人期。", "望柳尋花意，吟風弄月時。", "人琴無處問，空想考亭詩。"]'),
('71a97ec0-fc78-4808-aa58-e7e5abaf4fb5','琴','嚴粲','宋','宋诗','song-poetry','','[]','孤松風下弦秋清，湘江湛湛湘山青。',32,'全唐诗/poet.song.206000.json','["孤松風下弦秋清，湘江湛湛湘山青。", "一聲吹入天冥冥，何處白鶴飛來聽。"]'),
('95f8a036-27c2-4097-a3df-f82e6492cc6a','菊','嚴粲','宋','宋诗','song-poetry','','[]','秋籬霜露寒，獨立爾良難。',48,'全唐诗/poet.song.206000.json','["秋籬霜露寒，獨立爾良難。", "不作過時恨，從教耐久看。", "風流沾臘蕊，臭味憶騷蘭。", "孤淡逢心賞，幽香故未闌。"]'),
('6ce188aa-9504-4812-a9d2-370e450169b8','大虎頭灘','嚴粲','宋','宋诗','song-poetry','','[]','聞說前灘大虎頭，行人愁絕欲回舟。',32,'全唐诗/poet.song.206000.json','["聞說前灘大虎頭，行人愁絕欲回舟。", "世閒多有虛名誤，不見錢塘海逆流。"]'),
('151fdf32-e06f-4c19-8181-9c3d62ed4205','到清湘','嚴粲','宋','宋诗','song-poetry','','[]','客裏今年月，相逢九處圓。',48,'全唐诗/poet.song.206000.json','["客裏今年月，相逢九處圓。", "行窮湘水際，愁到楚雲邊。", "屋內煙明路，椽閒瓦見天。", "州城何處是，人指隔山煙。"]'),
('2432a42c-8bf9-4bbe-a983-86abbd79d311','旋摘盆柑','嚴粲','宋','宋诗','song-poetry','','[]','金丸手自摘，色味香三絕。',24,'全唐诗/poet.song.206000.json','["金丸手自摘，色味香三絕。", "從來天者全，風韻迥然別。"]'),
('c0e72f8d-3d6a-4fd6-9b4f-d097aef01e0f','參蒙齋先生','嚴粲','宋','宋诗','song-poetry','','[]','陋巷頹然號庶幾，更無言說最精微。',21,'全唐诗/poet.song.206000.json','["陋巷頹然號庶幾，更無言說最精微。", "何人參了。"]'),
('59a53ab4-10ab-42cb-a87e-8301b4c2461f','句','嚴粲','宋','宋诗','song-poetry','','[]','南來知寄誰。',6,'全唐诗/poet.song.206000.json','["南來知寄誰。"]'),
('29de6507-950a-4ab7-b875-df6b0b7f4b7f','端居寫興','李龏','宋','宋诗','song-poetry','','[]','地偏雙耳靜，心近古無懷。',48,'全唐诗/poet.song.206000.json','["地偏雙耳靜，心近古無懷。", "掃壁書秋夢，聽鐘辨午齋。", "貧疏親骨肉，老病瘦形骸。", "欲買劉伶鍤，教童死即埋。"]'),
('f56c012a-c5d7-4d67-a584-a8d9c2d2aa51','二月二日行藥城下','李龏','宋','宋诗','song-poetry','','[]','病懷歡易失，勝踐負流年。',48,'全唐诗/poet.song.206000.json','["病懷歡易失，勝踐負流年。", "行藥到城下，看春立水邊。", "小花雙蝶閙，禿樹一鷗眠。", "弦管同羈旅，今辰幾處偏。"]'),
('4460aa2f-3b92-4f97-8447-f4333338056a','題瑩講主雲林','李龏','宋','宋诗','song-poetry','','[]','聞說有雲林，吟人未易吟。',48,'全唐诗/poet.song.206000.json','["聞說有雲林，吟人未易吟。", "無風常滃滃，不雨自陰陰。", "宿鶴秋枝老，懸燈夜屋深。", "雖於朝市遠，僧住若爲心。"]'),
('1123f849-b206-417b-bae6-efe7dd4da9be','貽劉似道','李龏','宋','宋诗','song-poetry','','[]','百年能幾日，一別又三秋。',48,'全唐诗/poet.song.206000.json','["百年能幾日，一別又三秋。", "涉世雖相似，成名却不侔。", "蘋香分旅夢，棗色動邊愁。", "南海曾游處，應多異寶收。"]'),
('646c6c45-6f89-493a-b2ec-226a41a0d7d3','贈蜀客','李龏','宋','宋诗','song-poetry','','[]','萬里潼川路，連年沒野蒿。',48,'全唐诗/poet.song.206000.json','["萬里潼川路，連年沒野蒿。", "君家在何許，客寺忽相遭。", "渴雨秋雲熱，窺人夜月高。", "時平歸蜀去，應記識吾曹。"]'),
('fd3cfc37-308a-4cfe-a957-b4dc0e72e274','松邊晚思','李龏','宋','宋诗','song-poetry','','[]','小立聽松聲，身如海際行。',48,'全唐诗/poet.song.206000.json','["小立聽松聲，身如海際行。", "認巢飛鳥盡，脫雨素蟾生。", "角動州城遠，燈深古巷明。", "一春和病過，猶未得心清。"]'),
('7f0d32c6-a239-4719-baa9-a353ad33f228','道室雨中','李龏','宋','宋诗','song-poetry','','[]','無事役長日，幽孱掩道房。',48,'全唐诗/poet.song.206000.json','["無事役長日，幽孱掩道房。", "雨蒸吟軸潤，雲滃藥爐香。", "黄螘穿苔走，青蛇入竹藏。", "世緣拋似夢，還自覺凄凉。"]'),
('84d0221a-c0f6-4844-b4f4-aeef7e865fe7','春思','李龏','宋','宋诗','song-poetry','','[]','一心無外事，春思似秋清。',48,'全唐诗/poet.song.206000.json','["一心無外事，春思似秋清。", "掩室惟欹枕，看山間出城。", "花分閒地落，筍入斷階生。", "寂寞從人笑，貧難與命爭。"]'),
('181d1c37-1b61-4d4b-abb8-686e849c4150','夢遊僊','李龏','宋','宋诗','song-poetry','','[]','渺渺僊京到不難，夢遊頃刻過蓬山。',64,'全唐诗/poet.song.206000.json','["渺渺僊京到不難，夢遊頃刻過蓬山。", "桃池根暖春常在，桂殿花寒夜弗關。", "簇仗龍來珠箔捲，奏章人去玉庭閒。", "塵緣未斷雞聲起，又落黄粱未熟間。"]'),
('1d276f79-6088-4863-879a-747ec08d007d','寒食日','李龏','宋','宋诗','song-poetry','','[]','歌哭相喧熟食邊，野原花柳盡生煙。',64,'全唐诗/poet.song.206000.json','["歌哭相喧熟食邊，野原花柳盡生煙。", "身如厄木猶多病，心似寒灰豈欲然。", "鷗鷺乾坤知有我，燕鶑日月認誰憐。", "溪城半掩斜陽暝，落得閒愁幾畫船。"]'),
('2e414a42-a787-49ed-8b25-d15394c618b6','失題','李龏','宋','宋诗','song-poetry','','[]','應是三生愛酒人，誤流醉魄入花身。',32,'全唐诗/poet.song.206000.json','["應是三生愛酒人，誤流醉魄入花身。", "風酣日釅微香度，全似偷閒穤甕春。"]'),
('8f4e7de6-a378-4a64-9365-51ccee9e249e','木筆','李龏','宋','宋诗','song-poetry','','[]','巧如雞距銳如簪，蘸紫濡紅粉不深。',32,'全唐诗/poet.song.206000.json','["巧如雞距銳如簪，蘸紫濡紅粉不深。", "青帝合教隨侍史，萬花國裏寫春心。"]'),
('5721a774-8664-424c-b95c-ab3330f3717b','緋桃  其一','李龏','宋','宋诗','song-poetry','','[]','漢武西池宴未歸，霞妃粲粲弄春機。',32,'全唐诗/poet.song.206000.json','["漢武西池宴未歸，霞妃粲粲弄春機。", "靚粧似怕東風笑，盡換宮羅五品衣。"]'),
('49820133-9e6b-4ae1-aeb5-d3d0eb5bb9ea','緋桃  其二','李龏','宋','宋诗','song-poetry','','[]','衣裁緗纈態纖穠，猶在瑶池午醉中。',32,'全唐诗/poet.song.206000.json','["衣裁緗纈態纖穠，猶在瑶池午醉中。", "嫌近清明時節冷，趁渠新火一番紅。"]'),
('873ee72b-996a-4019-8651-6135eeb7c127','郁李花','李龏','宋','宋诗','song-poetry','','[]','花身合向玉新裁，同是玄元指姓來。',32,'全唐诗/poet.song.206000.json','["花身合向玉新裁，同是玄元指姓來。", "拋擲人間春色裏，霞衣小艷亦文哉。"]'),
('803e7468-bd4f-487f-b333-83dad07e4a9f','聞貴家搗浣','李龏','宋','宋诗','song-poetry','','[]','敲風點月重還輕，遊子聞來最動情。',32,'全唐诗/poet.song.206000.json','["敲風點月重還輕，遊子聞來最動情。", "峻宇雕牆雲雨外，那知此石有離聲。"]'),
('0d538d6f-5112-45c6-bfc3-09a7d870ac43','寓惠日寺','李龏','宋','宋诗','song-poetry','','[]','世路兢兢似履冰，得閒何處不輸僧。',32,'全唐诗/poet.song.206000.json','["世路兢兢似履冰，得閒何處不輸僧。", "青山未有投閒地，我亦僧邊寄一燈。"]'),
('d8519b2d-1eb0-407f-b841-25a445543749','題丁吉父梅扇','李龏','宋','宋诗','song-poetry','','[]','簾捲春寒月過中，瑣窗風淡暗香濃。',32,'全唐诗/poet.song.206000.json','["簾捲春寒月過中，瑣窗風淡暗香濃。", "橫枝半颭蘭缸影，曾惹佳人繡唾絨。"]'),
('2b17898e-4012-4982-a345-afe87fbbfd53','夢回荆溪聞雨','李龏','宋','宋诗','song-poetry','','["\u592a\u6e56"]','迢迢殘夢太湖西，窗眼未明雞已啼。',32,'全唐诗/poet.song.206000.json','["迢迢殘夢太湖西，窗眼未明雞已啼。", "蕙草無香秋被冷，十年情緒雨淒淒。"]'),
('df9a9ca1-5c17-4f21-90de-7a32017b07a1','貽陳體忠','李龏','宋','宋诗','song-poetry','','[]','十日不作詩，昏昏如著酒。',120,'全唐诗/poet.song.206000.json','["十日不作詩，昏昏如著酒。", "西風吹笛聲，淒然透窗牖。", "暝色起煙浦，庭梧多空枝。", "因軫故物念，暗螢死書帷。", "濡毫寫中情，哀蛩沸窮巷。", "藜藿弗滿餐，庸兒謂癡蠢。", "天高白雲遠，獨偭梟獺羣。", "蹇步望逸駕，衣巾粘垢氛。", "交游日凋疏，芳草積零露。", "薄俗徒云云，此意欲誰訴。"]'),
('f12884a5-afa9-4a21-a5ea-f0f1863e97ee','答江無極','李龏','宋','宋诗','song-poetry','','[]','男兒懶種南山豆，短褐踆踆走京口。',96,'全唐诗/poet.song.206000.json','["男兒懶種南山豆，短褐踆踆走京口。", "一枝彩筆度陽春，五年不飲烏程酒。", "杳眇長堤斷馬蹄，吟詩豈爲黄金悲。", "菖蒲花老楓香謝，頭上驚霜添暗絲。", "紅雲無光日將暮，半幅離情捲幽素。", "迷魂細雨撲寒空，秦淮鯉魚撇波去。"]'),
('630d5563-96e4-49de-933f-cd45e87b9ea6','東家','李龏','宋','宋诗','song-poetry','','[]','東家買金鈿，西家買翠鈿。',83,'全唐诗/poet.song.206000.json','["東家買金鈿，西家買翠鈿。", "雙鬟耀釵澤，顔色如春妍。", "朝開鉛粉匣，金翠爭光鮮。", "粧成倚高樓，誰不生愛憐。", "君不見采蘋老人門似水，嬌女無錢作梳洗。", "學他隣舍爲花鈿，惟將素面貼苔錢。"]'),
('dd967a30-dbae-46e9-ab60-b27d024e1cef','貽張巨濟','李龏','宋','宋诗','song-poetry','','[]','上國交游盡，見君殊惘然。',48,'全唐诗/poet.song.206000.json','["上國交游盡，見君殊惘然。", "相尋相別日，二十二三年。", "紫陌辭塵佩，青門委蠹編。", "詎知歸老地，還向弁峰前。"]'),
('cbbf3530-2806-4971-9d6d-086c16327d30','贈摘阮道士','李龏','宋','宋诗','song-poetry','','[]','下山何處去，語別老君前。',48,'全唐诗/poet.song.206000.json','["下山何處去，語別老君前。", "自背一張阮，遠登三楚船。", "夜程依岸芷，午飯對江蓮。", "若見知音了，歸來定絕弦。"]'),
('03046c74-793d-4f6c-9192-c4f1658c782d','贈陳籙士','李龏','宋','宋诗','song-poetry','','[]','青囊傳寶籙，龍虎度師家。',48,'全唐诗/poet.song.206000.json','["青囊傳寶籙，龍虎度師家。", "短褐煙霞滿，離山歲月賒。", "不愁生白髮，自解死朱砂。", "遠向華陽去，言尋蔡少霞。"]'),
('b8bfb115-60b1-4221-a912-d6c856541e4d','寄從弟道士惟中','李龏','宋','宋诗','song-poetry','','[]','一門羣從葬秋煙，奕世儒家失舊氈。',64,'全唐诗/poet.song.206000.json','["一門羣從葬秋煙，奕世儒家失舊氈。", "汝昔已工敲月句，而今惟使醮星錢。", "夫差臺榭遊應徧，魯望篇章錄想全。", "古觀燈殘風雨夜，可無歸夢入臨川。"]'),
('4e0a837b-f4fa-4471-a1f9-6a910aa33eba','寄餘干鄭丞','李龏','宋','宋诗','song-poetry','','[]','君爲丞處是吾鄉，門對煙霞竹繞牆。',64,'全唐诗/poet.song.206000.json','["君爲丞處是吾鄉，門對煙霞竹繞牆。", "于越城荒雲樹暗，代陽溪近水苔香。", "的知左宦心應折，未必東歸鬢便蒼。", "若過藏山山下寺，松楸憑與問凄凉。"]'),
('7f7e7d40-dae7-4374-9e6b-3e746ac38847','貽孫花翁','李龏','宋','宋诗','song-poetry','','[]','數寸書空筆，拈來直欲焚。',48,'全唐诗/poet.song.206000.json','["數寸書空筆，拈來直欲焚。", "絕憐吟貌減，多爲客情分。", "晚逕飄黄葉，秋簷掛白雲。", "因君論一飯，千古憶田文。"]'),
('886b3f31-72a8-4da3-823f-94c435c14732','早起','李龏','宋','宋诗','song-poetry','','[]','遠鐘雲際斷，一雁度殘河。',48,'全唐诗/poet.song.206000.json','["遠鐘雲際斷，一雁度殘河。", "閏氣今年正，秋聲昨夜多。", "露花縣蔦蔓，風葉捲蟲窠。", "坐結西遊恨，南隣猶醉歌。"]'),
('c3a080ce-069a-4e84-929b-025b9289f4c2','寄張公洞黄宮主','李龏','宋','宋诗','song-poetry','','[]','春草沒馿肩，新吟今幾篇。',48,'全唐诗/poet.song.206000.json','["春草沒馿肩，新吟今幾篇。", "每逢僊友說，多在石田邊。", "燕穴穿平地，龍巢出半天。", "常思訪毛節，凡骨恐腥羶。"]'),
('c2f1066d-0900-462e-ab14-cb161b23d9b7','說經道者','李龏','宋','宋诗','song-poetry','','[]','瀾翻口裏說三車，一衲唯披百結麻。',32,'全唐诗/poet.song.206000.json','["瀾翻口裏說三車，一衲唯披百結麻。", "應笑經僧內供奉，等閒盡著紫袈裟。"]'),
('21d0d8f6-4b76-47fb-ba00-554e02accf44','送柳鍊師歸台山','李龏','宋','宋诗','song-poetry','','[]','月照秋塵三丈飛，破囊携藥下黄池。',32,'全唐诗/poet.song.206000.json','["月照秋塵三丈飛，破囊携藥下黄池。", "僊家不數人間事，瀑布橋邊憶看棋。"]'),
('89f9a928-dcd4-4056-af89-14009248200a','題贈秋洞周鍊師  其一','李龏','宋','宋诗','song-poetry','','[]','誦熟神農本草經，夜深猿鶴亦潜聽。',32,'全唐诗/poet.song.206000.json','["誦熟神農本草經，夜深猿鶴亦潜聽。", "世間三百來般藥，用著醫人盡有靈。"]'),
('aee18082-0237-48ee-a819-efd15b39f6e8','題贈秋洞周鍊師  其二','李龏','宋','宋诗','song-poetry','','[]','沆瀣壇邊月影寒，朝元多戴蘚花冠。',32,'全唐诗/poet.song.206000.json','["沆瀣壇邊月影寒，朝元多戴蘚花冠。", "俗人或問長生事，教看西風一竈丹。"]'),
('548aa23c-8164-48ee-804b-7f7eeba3daf6','送月窗王敬叔遊武夷','李龏','宋','宋诗','song-poetry','','[]','客程遥指建溪行，要踏東風看幔亭。',32,'全唐诗/poet.song.206000.json','["客程遥指建溪行，要踏東風看幔亭。", "君去莫嫌春色晚，落花一路水苔青。"]'),
('ee2d8029-0a3c-4f88-b57e-e9da5a417ac9','題贈高士章少機','李龏','宋','宋诗','song-poetry','','[]','度人經注就，進罷徑還鄉。',48,'全唐诗/poet.song.206000.json','["度人經注就，進罷徑還鄉。", "自說爲高士，深恩感壽皇。", "斷琴支醉石，寒帽擲吟床。", "八十身猶健，元無服食方。"]'),
('f948715e-00fc-426f-838d-af7aac681803','寄國史校勘陳體仁','李龏','宋','宋诗','song-poetry','','[]','天祿對藜燈，丹鉛照眼明。',48,'全唐诗/poet.song.206000.json','["天祿對藜燈，丹鉛照眼明。", "雖稱小朝士，不是老書生。", "職重三場筆，官聯六館名。", "懷君既良晤，歲久又崢嶸。"]'),
('d6bf91da-df21-47c5-88bf-b9d05ce75722','端午日','李龏','宋','宋诗','song-poetry','','[]','高門高掛艾天師，玉臂還纏五彩絲。',32,'全唐诗/poet.song.206000.json','["高門高掛艾天師，玉臂還纏五彩絲。", "我只一杯昌歜酒，羲皇窗下讀騷辭。"]'),
('6f13d237-c5de-4772-8069-45f0cd941028','摺疊扇','李龏','宋','宋诗','song-poetry','','[]','尺素裁成半葉荷，竹批六夾影相羅。',32,'全唐诗/poet.song.206000.json','["尺素裁成半葉荷，竹批六夾影相羅。", "玉人笑把遮羞面，還向縚邊見笑渦。"]'),
('969849a3-d7ec-4565-818e-7c2a1e27a5ad','早起','李龏','宋','宋诗','song-poetry','','[]','殺更聲裏亂啼鴉，十二屏山捲碧紗。',32,'全唐诗/poet.song.206000.json','["殺更聲裏亂啼鴉，十二屏山捲碧紗。", "海月傾欹光未沒，隔牆猶照紫薇花。"]'),
('9e107c63-5291-42e6-b9c4-b1fc14844a6b','看竹','李龏','宋','宋诗','song-poetry','','[]','節抱秋霜綠玉君，一林風月有司存。',32,'全唐诗/poet.song.206000.json','["節抱秋霜綠玉君，一林風月有司存。", "吟邊不領閒公事，報了平安聽掩門。"]'),
('fcfbbe9f-8d19-4ea1-a199-d7146030b056','祀神詞','李龏','宋','宋诗','song-poetry','','[]','食蘋兮崑崙，駕文鰩兮西海。',118,'全唐诗/poet.song.206000.json','["食蘋兮崑崙，駕文鰩兮西海。", "登羣玉之府兮白雲熊熊，祀司天兮毛采。", "占筳篿兮瑶池，恍余心兮飉厲。", "旋升兮軒丘，即平圃兮佇眙。", "颯晨風兮丹木，聞環玉兮泠泠。", "神來歸兮洋水，舞青鳥兮都庭。", "陳桂尊兮藉白茅，申微詞兮再拜以傴。", "歆余誠兮神何私，惟怙終兮拙魯。"]'),
('035499a5-dffc-4e42-bc8f-eaebcda7503d','秋征圖','李龏','宋','宋诗','song-poetry','','[]','斷崖兮秋清，野橋兮煙橫。',69,'全唐诗/poet.song.206000.json','["斷崖兮秋清，野橋兮煙橫。", "彼何人兮短褐，跨蹇馿兮孤征。", "登蜀道兮出函谷，叫閶闔兮謁承明。", "蘭皋兮芷葺，木涵風兮楚聲。", "渺何之兮不返，因有感兮吾生。"]'),
('3c408c88-9040-4620-a4fb-11c2913e3a8a','君子有所思','李龏','宋','宋诗','song-poetry','','[]','揚帆越震澤，暮上姑蘇臺。',120,'全唐诗/poet.song.206000.json','["揚帆越震澤，暮上姑蘇臺。", "飛目眺衢市，第宅星宮開。", "丹甍翔虹浦，碧戶闖瑶街。", "方泉沼清鏡，怪石環蓬萊。", "姬房儲越女，歌院集吳娃。", "涌觴廣遥夜，蠟淚球青煤。", "懸景駛流水，安樂難安排。", "堪輿金玉身，不防熬豹胎。", "石穹霤能穴，樹大風先摧。", "君子哉若人，方寸逆自裁。"]'),
('fe24cb4d-c25b-46a9-80bc-2f0fd9e2fe45','遣興三首  其一','李龏','宋','宋诗','song-poetry','','[]','弱齡性淡泊，鄭圃吾其師。',96,'全唐诗/poet.song.206000.json','["弱齡性淡泊，鄭圃吾其師。", "及茲拙生事，窮窘常經時。", "無方可紓急，何以宣中懷。", "柴門蔽殘席，咏書倦徘徊。", "呼兒促觴至，目翫天雲飛。", "山鳥送新響，日遲花露滋。", "頹然醉簷下，不省何如時。", "雖非富貴樂，富貴乃所乖。"]'),
('be32862c-cd96-4130-8571-254927e3fcec','遣興三首  其二','李龏','宋','宋诗','song-poetry','','[]','疏松碎明月，密竹篩清風。',72,'全唐诗/poet.song.206000.json','["疏松碎明月，密竹篩清風。", "親交昔與別，若謂行相從。", "延企邈不及，音容隨想生。", "諒彼亦耿耿，飛爽留空形。", "援琴不能寐，意乃多於聲。", "晤言豈無偶，眷眷詎可忘。"]'),
('ca865cc0-5183-4ae4-95e8-363b544f8af3','遣興三首  其三','李龏','宋','宋诗','song-poetry','','[]','編蓬諧夙心，尊古豈文義。',84,'全唐诗/poet.song.206000.json','["編蓬諧夙心，尊古豈文義。", "所得靡有言，應酬聊爾爾。", "室中無萊婦，童弱偶成四。", "團欒寧無思，達此天亦蛻。", "客來問長鬚，新醅可篘未。", "行行陟高岡，一顧俯煙水。", "客去不肯留，吾歸且休矣。"]'),
('0cbf1662-d29f-4eb4-b08c-4efe8564ad51','寒暑吟','李龏','宋','宋诗','song-poetry','','[]','赦寒乃望春，赦暑乃望秋。',96,'全唐诗/poet.song.206000.json','["赦寒乃望春，赦暑乃望秋。", "望望復望望，寒暑無停輈。", "磨空兩靈魄，日夜東西流。", "血肉具此體，老我誰爲謀。", "泛然寓大塊，萬物同一丘。", "壯兮耄所伏，盛者衰之由。", "暑退秋紅滋，寒往春綠稠。", "奈何秋與春，不赦腸中愁。"]'),
('7c13163f-d04f-474d-9a65-be5dc04b8385','蕭寺逢寒食','李龏','宋','宋诗','song-poetry','','[]','皇天無私覆，白日照不明。',144,'全唐诗/poet.song.206000.json','["皇天無私覆，白日照不明。", "覽鏡見白髮，無路通上清。", "惡命如惡草，羞與蕭艾爭。", "春風鼓元造，吹我來吳城。", "繁華久寂寞，車馬猶肥輕。", "寄家盤門裏，古寺如荒塋。", "地頑蘚皮厚，終日無人行。", "囂譊故相遠，妻女多輕驚。", "朝聞勃姑聲，暮聞姑惡聲。", "聲云苦復苦，朝暮難爲情。", "梨花照愁腸，痛似遭五兵。", "一杯寒食酒，誰與論浮生。"]'),
('495e3d21-ee46-483d-9773-e1d4702d77b2','飛仙篇用周草窗韻','李龏','宋','宋诗','song-poetry','','[]','明星燦白石，八極傍無端。',120,'全唐诗/poet.song.206000.json','["明星燦白石，八極傍無端。", "羽駕紫霞表，月窟春闌珊。", "三元流珠秘，換骨初不難。", "彈指一塵刼，世人漫愁歎。", "王喬羨門生，鸞鶴常媻媻。", "剛風導旛旟，冉冉如飛翰。", "仙人攬六著，著以赬玉盤。", "上朝東華閣，主君顔渥丹。", "邀我小稅駕，爲說平生歡。", "彤雲爍羽袂，鼇背晨光寒。"]'),
('d8aa2712-cc86-4645-8307-31f79860595a','古興四首用周草窗韻  其一','李龏','宋','宋诗','song-poetry','','[]','薰風入虞弦，萬物闡生意。',48,'全唐诗/poet.song.206000.json','["薰風入虞弦，萬物闡生意。", "圖南豈無心，所恨老已至。", "浮雲翳高槐，縹緲動羈思。", "吁嗟鷦鷯枝，詎可巢孔翠。"]'),
('82a96966-e314-41a4-a552-399a54e6195e','古興四首用周草窗韻  其二','李龏','宋','宋诗','song-poetry','','[]','塵坌障雙眼，閉門息交游。',48,'全唐诗/poet.song.206000.json','["塵坌障雙眼，閉門息交游。", "聖經斷金義，當從古人求。", "清尊洗風月，非可與婦謀。", "據梧不成寐，簾影燈幽幽。"]'),
('b09a191d-8302-40ef-9a06-30689b2c79ca','古興四首用周草窗韻  其三','李龏','宋','宋诗','song-poetry','','[]','陰崖月常昏，曠野日生早。',48,'全唐诗/poet.song.206000.json','["陰崖月常昏，曠野日生早。", "太行不通舟，車馬畏鳥道。", "草草度歲時，空慕茹芝老。", "不有離騷詞，何能泄幽抱。"]'),
('65427e29-f91b-4a48-ad36-6d3ffe7f0213','古興四首用周草窗韻  其四','李龏','宋','宋诗','song-poetry','','[]','流俗厭拙直，對面猶褒斜。',48,'全唐诗/poet.song.206000.json','["流俗厭拙直，對面猶褒斜。", "冰玉漫堅白，錦繡矜妍華。", "往往怪僻者，反爲時所誇。", "交情到妻子，令人生歎嗟。"]'),
('6bc1083b-1c2f-4bb4-b81c-5d9107b1db0f','採桑行','李龏','宋','宋诗','song-poetry','','[]','採桑東陌頭，日出紅光流。',144,'全唐诗/poet.song.206000.json','["採桑東陌頭，日出紅光流。", "採桑南陌頭，和風滿桑鉤。", "採桑西陌頭，日落烏颼颼。", "採桑北陌頭，明月照歌樓。", "携籃敢憚遠，手胝足成趼。", "蠶饑恐歸遲，一日三四返。", "昨朝蠶三眠，燈前微合眼。", "夢中見征夫，短衣供築版。", "庭樹啼霜鴉，夢回自天涯。", "小姑報蠶起，蓬鬢忙梳爬。", "相望萬餘里，那敢興怨嗟。", "出門還採葉，細雨濕桐花。"]'),
('c9f390df-d918-4be2-a06d-a1aa3120f662','弔魏嶼川','李龏','宋','宋诗','song-poetry','','[]','寓形大塊內，變滅如風埃。',144,'全唐诗/poet.song.206000.json','["寓形大塊內，變滅如風埃。", "依依孤蘭姿，不上黄金臺。", "客死古豈無，君死猶蒿萊。", "方君初病時，秋自京都回。", "空齋數相見，書案皆寒灰。", "對飯不能喫，買藥親炮煨。", "氣劣面如削，高說尚雄瑰。", "破衾裹羸骨，今在古廟隈。", "俛仰視所親，旅櫬惟霜苔。", "何人置肴豆，何人陳酒杯。", "故鄉那得返，義塚將就培。", "我成薤歌聲，君聞寧不哀。"]'),
('f6a0696e-a5a0-48d4-a9bc-eb523a2d1e89','八月三十日小園桂香清甚招同僚吟賞憶劉判官葉令君','李龏','宋','宋诗','song-poetry','','[]','日出理簿書，夜常秉燭歸。',120,'全唐诗/poet.song.206000.json','["日出理簿書，夜常秉燭歸。", "不知花開謝，間關園鳥啼。", "朅來巾峰下，三度著秋衣。", "丹桂立西風，明年開向誰。", "俗吏癡已甚，騷人貌難追。", "坐中金蘭契，蕭爽芙蓉姿。", "酒漓飲不醉，取歡在琴詩。", "村落有貧民，攔道訴寒饑。", "官涂一笑過，念此令人悲。", "賢哉二大夫，露宿東西溪。"]'),
('c535ed48-0a01-4672-955e-3d37829767f9','古贈別三首  其一','李龏','宋','宋诗','song-poetry','','[]','撫我膝上琴，酌君杯中酒。',48,'全唐诗/poet.song.206000.json','["撫我膝上琴，酌君杯中酒。", "惟琴乃正聲，惟酒是醇酎。", "芳年如驚飈，願介斯文壽。", "結交非悠悠，所貴在耐久。"]'),
('7d1f471e-43df-4e6a-af7b-ff52334f03d3','古贈別三首  其二','李龏','宋','宋诗','song-poetry','','[]','今君遠行邁，黄葉辭故林。',48,'全唐诗/poet.song.206000.json','["今君遠行邁，黄葉辭故林。", "驅車背寒日，何能冩沖襟。", "勿歎儒服弊，去爲塵土侵。", "白雲在空谷，歲晚毋遐心。"]'),
('5d7f7ec5-0d30-408c-b0c4-9058b24aa54e','古贈別三首  其三','李龏','宋','宋诗','song-poetry','','[]','孤寂久杜門，莓苔未嘗掃。',48,'全唐诗/poet.song.206000.json','["孤寂久杜門，莓苔未嘗掃。", "風吹別離顔，少日鬢已槁。", "靡靡歲月逝，清霜散幽草。", "君去贈一言，岐路歸直道。"]'),
('ad0ca528-a44d-486f-9292-880642097159','有所思','李龏','宋','宋诗','song-poetry','','[]','白蘋洲前風似刀，白頭有客披苧袍。',64,'全唐诗/poet.song.206000.json','["白蘋洲前風似刀，白頭有客披苧袍。", "芙蓉鬰紅墮芳沼，楊柳擯綠摇空壕。", "擣衣砧歇蛩無語，美人清宵隔湘浦。", "獨掩高樓聽遠更，不禁老樹鳴秋雨。"]'),
('0a4d266b-cdc4-47cb-9d49-9b0aa38049f6','夜宴曲用草窗韻','李龏','宋','宋诗','song-poetry','','[]','博山飛香靄空綠，大菊杯心凸金粟。',96,'全唐诗/poet.song.206000.json','["博山飛香靄空綠，大菊杯心凸金粟。", "百幅罘罳障夜寒，歌臺小妓吹橫玉。", "蘭堂畫燭如椽粗，楚腰魏鬢嬌相扶。", "四筵高談遏花漏，犀盤雜遝羅天酥。", "杯行過手如飛箭，座上愁無繫歡線。", "曉韉馱月朦朧歸，東家又報開春宴。"]'),
('80ae3d18-862d-403d-bb92-5c758da3f7f5','猗蘭曲','李龏','宋','宋诗','song-poetry','','[]','湘花小朵分幽春，封根苔土如蛇鱗。',64,'全唐诗/poet.song.206000.json','["湘花小朵分幽春，封根苔土如蛇鱗。", "東風曉剝兔豪殻，青瑶斛冷香吹人。", "滋香夜滴金蟾水，綠葉紫莖光韡韡。", "佩囊荒破赤龍愁，璧月斜沉泣騷鬼。"]'),
('187c56c7-0945-48ca-ab4a-735475ca1e8f','古春謠','李龏','宋','宋诗','song-poetry','','[]','蒼梧雲塞東風路，勾芒太皞無行處。',64,'全唐诗/poet.song.206000.json','["蒼梧雲塞東風路，勾芒太皞無行處。", "草嚙枯泥后土愁，桃花自滿雲中樹。", "黄牛力作興農工，一犁細雨香濛濛。", "阿香夜奉玉皇詔，搥鼓空喚閒蛇蟲。"]'),
('df00ae8c-544f-4efd-983a-3c23eba191b9','桃州古田鎛歌','李龏','宋','宋诗','song-poetry','','[]','老翁犁山田土中，獲得昔人墾田器。',268,'全唐诗/poet.song.206000.json','["老翁犁山田土中，獲得昔人墾田器。", "似鐸有柄，如鍾不圜。", "身長二尺徑八寸，口薄腹厚唇微穿。", "顔色紺碧艷綠處，間有班紅如血鮮。", "形模古拙見者怪，銅性已變不復辨，疑是死鐵兼頑鉛。", "老翁視爲棄物委床下，一朝移出茅簷前，塵灰糠粃俱塞填。", "乃有博雅識是古田鎛，垂涎拂拭再三看，扣之尚覺聲隠然。", "水痕土色兩相蝕，歎息不知鑄自三代之何年。", "邀翁問所得，共入酒家保，買以十萬青銅錢。", "買來携歸置几案，一架坐插青絲氈。", "圖書鍾鼎相聯編，寶玩要使兒孫傳。", "自秦歷漢以來此鎛只在土，出世便苦無常主。", "博雅好事歸泉臺，可憐閲世亦如草頭露，高堂山鬼不守護。", "他家更有好古人，又以青錢易將去。"]'),
('fda28da8-a091-4e91-9aa1-430c1aa7046c','憶昔行','李龏','宋','宋诗','song-poetry','','[]','憶昔當年十四五，嘗看秋潮到江滸。',304,'全唐诗/poet.song.206000.json','["憶昔當年十四五，嘗看秋潮到江滸。", "飛裾徑上酒家樓，憑欄直望潮生處。", "數百里間名海門，悠悠一線色如銀。", "漸近江心痕漸大，洶湧聲吞十萬軍。", "須臾潮頭高數丈，衆潮隨接皆奔上。", "中有雄心拍浪兒，幾點紅旗爭蕩漾。", "風前縹緲奪標來，神蛟鬼鰐俱摧頹。", "監潮侯有伍胥在，但見濆薄旋推回。", "後來沙漲西興口，潮勢何曾十分有。", "水上人騎騍馬行，車如雞栖馬如狗。", "數年之後不可當，漰湃驚聞洗目塘。", "汪洋且撥菜園去，壩子橋邊亦渺茫。", "神臯內史承天旨，擺樁疊石曾料理。", "至今遏捺逾十年，樁石如城牢在水。", "江頭人謂可安居，連年不奈還憂虞。", "西風吹潮半夜起，子胥之怒知何如。", "陰威作寒带烟霧，捲石掀沙出幽府。", "堪羨雲中拍浪兒，踏著危機不怕危。", "乘除消長君休忽，牢執長竿一面旗。"]'),
('6825a60d-0ec5-4c5d-a801-6bb26154fa0e','婺源琉璃萬燈歌','李龏','宋','宋诗','song-poetry','','[]','婺源燈匠奪天巧，做出新燈極精好。',192,'全唐诗/poet.song.206000.json','["婺源燈匠奪天巧，做出新燈極精好。", "細細琉璃萬縷中，織得禽魚及花草。", "錦娘眷眷繡娘羞，煌芒五色燿冰毬。", "江梅盈枝玉彯蘂，離枝滿樹紅堆頭。", "水晶不瑩珠璣冷，屏間雲母空烘影。", "百尺長竿橫畫梁，寶蓋懸空繫纖綆。", "綠灧鱗鱗晃曲波，斜岡蹙蹙映平坡。", "瓶中梔子豆心綻，籃裏海棠絨带拖。", "午夜高堂明似晝，璧月涵光燦星斗。", "蠟香坱靄焰春陽，錦光倒射金杯酒。", "此燈絕妙世間無，乃是婺源燈畫圖。", "梁園下客非夸大，從今不必說姑蘇。"]'),
('bbfadfe2-0154-4d28-b563-916faebbee02','冰壺飲歌','李龏','宋','宋诗','song-poetry','','[]','金流石爍草欲枯，炎氣熇熇噓洪鑪。',96,'全唐诗/poet.song.206000.json','["金流石爍草欲枯，炎氣熇熇噓洪鑪。", "蘭臺兔園避處無，高堂貯冰排玉壺。", "珊瑚水晶間犀株，扇車作風轉轆轤。", "水戲蠟刻鴻鷗鳬，大瓜浮綠李沉朱。", "碧筩捲香𣂏雲腴，膾盤堆雪封秋鱸。", "美人笑指袁安圖，汗珠滴出紅羅襦。"]'),
('3da63f9b-c48e-4d39-9738-b023ddca67e4','苦寒歌','李龏','宋','宋诗','song-poetry','','[]','凍天添雲埋晝光，江河膠合蛟龍僵。',64,'全唐诗/poet.song.206000.json','["凍天添雲埋晝光，江河膠合蛟龍僵。", "涸陰噓風無慘烈，枯磧莽莽沙浮霜。", "蟄春老屋如冰井，獸炭烹紅烘不醒。", "南山飛瀑成玉絲，哀猿𤻎落孤松頂。"]'),
('cdbcfa1b-8ab0-4541-9adf-e189ec1045c9','關山月','李龏','宋','宋诗','song-poetry','','[]','玉門關外月，遠接黑山明。',48,'全唐诗/poet.song.206000.json','["玉門關外月，遠接黑山明。", "晃色同沙冷，飛光掩雪清。", "宿師方偃陣，游騎復窺城。", "不信長生魄，年年照戰爭。"]'),
('1a65a8c8-40dd-45ba-9069-1265500bd3bc','對月','李龏','宋','宋诗','song-poetry','','[]','水上重樓閉，虛空雲盡收。',48,'全唐诗/poet.song.206000.json','["水上重樓閉，虛空雲盡收。", "十分今夜月，一片玉晨秋。", "祇有詩能寫，都無價可酬。", "寥寥飛鵲外，歌吹在青樓。"]'),
('38db4517-6f9b-48ac-93fd-860f4a329d68','道埸山災後葉靖逸同遊','李龏','宋','宋诗','song-poetry','','[]','石爛木全焦，鍾魚變寂寥。',48,'全唐诗/poet.song.206000.json','["石爛木全焦，鍾魚變寂寥。", "老僧無法說，諸佛亦魂消。", "寺有州圖載，山餘窣堵標。", "嗟嗟伏虎事，誰更問前朝。"]'),
('34a21b75-8b5d-42ed-9a82-a7ffae3fe43c','石山僧','李龏','宋','宋诗','song-poetry','','[]','禪衣掛石稜，月澗瀨流冰。',48,'全唐诗/poet.song.206000.json','["禪衣掛石稜，月澗瀨流冰。", "釘畫掃寒壁，覆棋然夜燈。", "別來增落葉，病起損枯藤。", "說透蓮花偈，相依有越僧。"]'),
('4bf62c68-b2d4-404f-acde-41cb70ea7d79','華亭延恩律師','李龏','宋','宋诗','song-poetry','','[]','花會收雲席，經聲散窅冥。',48,'全唐诗/poet.song.206000.json','["花會收雲席，經聲散窅冥。", "無言坐巖壑，隨意使精靈。", "齋鉢重教漆，埋龕預作銘。", "養成松上鶴，相對兩眸青。"]'),
('f0bf5627-54cd-454a-8f7c-0da830ee0176','寄北山僧','李龏','宋','宋诗','song-poetry','','[]','一庵猿鳥外，琢石疊禪扃。',48,'全唐诗/poet.song.206000.json','["一庵猿鳥外，琢石疊禪扃。", "行道拖寒衲，消閒補壞經。", "新泉開出遠，古像呪來靈。", "常憶相尋日，中巖松桂馨。"]'),
('e2518361-9bd6-40a0-8c3a-68ad75ea0703','贈華亭延慶坦講主','李龏','宋','宋诗','song-poetry','','[]','身不鑽權貴，諸方盡說師。',48,'全唐诗/poet.song.206000.json','["身不鑽權貴，諸方盡說師。", "講多禪子聽，行少俗人知。", "猿護挑經錫，龍依洗鉢池。", "舊房天目下，松長幾秋枝。"]'),
('199f7ac8-2b80-44e3-8c00-10c8bba842ac','寄心禪人','李龏','宋','宋诗','song-poetry','','[]','寂寂古山根，閒房竹半分。',48,'全唐诗/poet.song.206000.json','["寂寂古山根，閒房竹半分。", "野禽聽佛偈，香草入禪薰。", "白露滴孤壁，悲風生破墳。", "昨來經世業，應已付浮雲。"]'),
('9864855a-26a6-452b-afa5-62c43549bc1d','送超海翁遊金陵','李龏','宋','宋诗','song-poetry','','[]','渺渺金陵道，江天正寂寥。',48,'全唐诗/poet.song.206000.json','["渺渺金陵道，江天正寂寥。", "孤鴻隨去影，一錫破寒飈。", "官渡潮多涸，臺城寺半凋。", "離宮見楊柳，莫折弄春條。"]'),
('52f080ab-6a41-4a01-b325-247e1de456c9','送僧歸杼山','李龏','宋','宋诗','song-poetry','','[]','亂峰村口寺，舊有晝公房。',48,'全唐诗/poet.song.206000.json','["亂峰村口寺，舊有晝公房。", "鳥宿猿啼處，風吹月在傍。", "揭雲松景黑，涸石蘚痕黄。", "明日烟霞外，相望隔夕陽。"]'),
('1233a286-a850-4f0b-bc9a-6498032c2348','送僧廣明','李龏','宋','宋诗','song-poetry','','[]','忽辭同侶去，自喜水烟濃。',48,'全唐诗/poet.song.206000.json','["忽辭同侶去，自喜水烟濃。", "江草有閒色，野僧無定蹤。", "衣弢方眼笠，瓶系曲枝筇。", "明宿楓橋寺，先聽夜半鐘。"]'),
('eec87c79-e9ab-4fbe-acb8-80e4965cb1af','題贈然鏡潭','李龏','宋','宋诗','song-poetry','','[]','象圜非假鑄，湛湛一泓深。',48,'全唐诗/poet.song.206000.json','["象圜非假鑄，湛湛一泓深。", "獨露古今體，靜涵天地心。", "月沉聲不響，雲晦影無侵。", "定起何人會，魚龍識梵音。"]'),
('cff8f834-3f80-4da7-aeca-6df8baa582f8','寄輝老','李龏','宋','宋诗','song-poetry','','[]','八十空門侶，如君有幾僧。',48,'全唐诗/poet.song.206000.json','["八十空門侶，如君有幾僧。", "眼明非服藥，身健不扶藤。", "雲綴搜吟筆，花紛說戒燈。", "小師親得法，新度碓頭能。"]'),
('891e8d36-f0b0-497e-aa2b-8be6c1c66b4c','與昭慶因律師','李龏','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖戒壇寺，近逼九重天。',48,'全唐诗/poet.song.206000.json','["西湖戒壇寺，近逼九重天。", "師住無他惱，人言有宿緣。", "蓮香熏梵裓，柳色護齋筵。", "四分南山律，今誰可共宣。"]'),
('b473b2cf-5141-464d-b40f-34e9955c88d3','春日題吳興峴山寺','李龏','宋','宋诗','song-poetry','','[]','花草滿苕陽，東風隔短牆。',48,'全唐诗/poet.song.206000.json','["花草滿苕陽，東風隔短牆。", "漥樽殘葉爛，壞塔老藤僵。", "鴿暝栖苔殿，僧寒閉竹房。", "荒阡人哭散，惟覺紙煙香。"]'),
('843dbf11-cc60-4c82-92b0-08f8b4bba11b','送客赴邊任','李龏','宋','宋诗','song-poetry','','[]','山陽今近敵，君去酒當呼。',48,'全唐诗/poet.song.206000.json','["山陽今近敵，君去酒當呼。", "不爲留行役，閑因說道途。", "春沙郵騎老，夜雨戍樓孤。", "袖裏酬君劍，須將示丈夫。"]'),
('f4f591d2-f6b6-4abd-8a47-575549e9e2f5','河軒初秋夜坐','李龏','宋','宋诗','song-poetry','','[]','滌熱屢呼茶，河軒去郭賒。',48,'全唐诗/poet.song.206000.json','["滌熱屢呼茶，河軒去郭賒。", "雲紅初夜月，風白久晴沙。", "樹暗惟聞蚻，波明間躍蛙。", "松江鱸入思，客老媿浮家。"]'),
('1a315416-066d-4dcd-a713-fd5df28fda90','題車蓋實公庵','李龏','宋','宋诗','song-poetry','','[]','雲火欲燒天，得凉過得仙。',48,'全唐诗/poet.song.206000.json','["雲火欲燒天，得凉過得仙。", "蛙隨殘雨閙，犬護一僧禪。", "竹色摇山磴，荷聲拂水田。", "別期秋月夜，來借石床眠。"]'),
('8ebcbd7d-3844-4767-888e-5f448d03a1a3','雨樓晚思','李龏','宋','宋诗','song-poetry','','[]','紅葉入溪樹，悽悽吟思微。',48,'全唐诗/poet.song.206000.json','["紅葉入溪樹，悽悽吟思微。", "雨連秋市暗，鐘遶暮天飛。", "淺井陰螢出，高城宿鳥歸。", "誰知憑欄處，愁響隔林機。"]'),
('f531d011-bc8a-4f43-a64d-81af35d13963','遊空相寺追憶輝老兼懷伯弜詩','李龏','宋','宋诗','song-poetry','','[]','山門掩夕曛，芳草綠紛紛。',48,'全唐诗/poet.song.206000.json','["山門掩夕曛，芳草綠紛紛。", "蛛殿縣陰火，鴉城聚冷雲。", "探吟僧滅度，寄靜客離羣。", "何處增惆悵，秋房駁蘚文。"]'),
('1caa8969-fefa-4df3-be0a-0e64b081dcac','題友人郊居','李龏','宋','宋诗','song-poetry','','[]','鷗鷺羣栖地，幽人長閉關。',48,'全唐诗/poet.song.206000.json','["鷗鷺羣栖地，幽人長閉關。", "孤村皆是水，疊石自爲山。", "春雨車溪外，秋風笠澤間。", "短籬忘世味，惟看釣舟還。"]'),
('1ecf1e9d-9956-41be-b794-ad6659650b5d','烏程趙尉廳冬夜詩宴','李龏','宋','宋诗','song-poetry','','[]','論詩仙吏宅，酒罷夜寒增。',48,'全唐诗/poet.song.206000.json','["論詩仙吏宅，酒罷夜寒增。", "雪映高城月，風吹古岸冰。", "入橋聞短棹，隔塢見微燈。", "重媿羈吟客，青雲去未能。"]'),
('f62586d0-7fd1-4abf-b7f6-f630df567a34','送溧陽友人依茅山玉宸觀主','李龏','宋','宋诗','song-poetry','','[]','抱琴遊帝里，一帽兩靴塵。',48,'全唐诗/poet.song.206000.json','["抱琴遊帝里，一帽兩靴塵。", "忽憶歸金瀨，還謀老玉宸。", "魚分仙澗月，虎讓古山春。", "伏事陶弘景，終非是俗人。"]'),
('794ec8cb-8dec-48ad-ae85-e59bc7b0d4f1','樗翁朱安叔下省','李龏','宋','宋诗','song-poetry','','[]','真儒方進用，春榜又遺賢。',48,'全唐诗/poet.song.206000.json','["真儒方進用，春榜又遺賢。", "時屈道終在，才高人共憐。", "休疑考官眼，且結作詩緣。", "桃李東風外，身閑却是仙。"]'),
('fe4b00f6-0255-402a-8e0a-708d8b52eed0','憑欄呈劉季良','李龏','宋','宋诗','song-poetry','','[]','傲貧成白首，萬事不相關。',48,'全唐诗/poet.song.206000.json','["傲貧成白首，萬事不相關。", "有病身元嬾，無官心更閒。", "紅塵拋永日，黄葉換秋山。", "欲識冥冥意，孤鴻夕照間。"]'),
('719b7dc1-4ddb-4df0-a5f6-6de345b0f4a9','道院春日','李龏','宋','宋诗','song-poetry','','[]','褰簾捲竹房，僧去罷焚香。',48,'全唐诗/poet.song.206000.json','["褰簾捲竹房，僧去罷焚香。", "濕樹流殘雪，疏籬挂夕陽。", "花遲春意靜，苔密凍痕光。", "野水盈愁望，尋巢燕已忙。"]'),
('0cf7a24e-579d-447d-8097-03dbff53101f','刈田','李龏','宋','宋诗','song-poetry','','[]','刈田秋雨外，孤嶼集罛師。',48,'全唐诗/poet.song.206000.json','["刈田秋雨外，孤嶼集罛師。", "紅樹籠斜照，青篙網細絲。", "鐘殷山麓寺，燈淡野塘祠。", "一片鳧鷖水，羞來鑑白髭。"]'),
('14d2c3f9-e68a-4945-8daa-7dd002b2b870','送趙子真尉進賢','李龏','宋','宋诗','song-poetry','','[]','王孫爲一尉，古邑近西山。',48,'全唐诗/poet.song.206000.json','["王孫爲一尉，古邑近西山。", "梅福仙名在，此官非等閒。", "水程蟂孽後，野店鼠逃間。", "未必須三考，應持鶚表還。"]'),
('0f1b23f3-afc6-4f65-bd63-3c9236fb3476','送趙子真赴信州司戶','李龏','宋','宋诗','song-poetry','','[]','鳴鐸臨征路，信州非路程。',48,'全唐诗/poet.song.206000.json','["鳴鐸臨征路，信州非路程。", "官曹有名勝，版賦足修明。", "地富饒銀母，山清韞水精。", "貧交以貧累，不得伴君行。"]'),
('5015d3a1-fb44-491b-b8ec-4b103e8d4f00','貽趙司戶','李龏','宋','宋诗','song-poetry','','[]','同往爭名地，回頭二十年。',48,'全唐诗/poet.song.206000.json','["同往爭名地，回頭二十年。", "君今官幕府，我費客遊錢。", "夜雨梨花店，春風柳絮船。", "澆情一尊酒，逢在冶亭邊。"]'),
('36a803b4-ffc6-4f72-8d4d-f099d7ff4aa3','九衢  其一','李龏','宋','宋诗','song-poetry','','[]','九衢名利路，日有是非塵。',48,'全唐诗/poet.song.206000.json','["九衢名利路，日有是非塵。", "所以隠淪客，棲於寂寞濱。", "秋聲飛野柳，凉色弄溪蘋。", "贏得身心凈，人間不媿人。"]'),
('4601a54e-717a-433b-8046-b7b17f16f6a2','九衢  其二','李龏','宋','宋诗','song-poetry','','[]','小窗臨竹地，借住半年過。',48,'全唐诗/poet.song.206000.json','["小窗臨竹地，借住半年過。", "枕上感秋事，月中聞棹歌。", "青山無力買，白髮有痕多。", "那得成漁計，江村自養和。"]'),
('23a56f85-f249-4421-9bc5-c44fad016876','張約嘯巖書院','李龏','宋','宋诗','song-poetry','','[]','雅調背時流，月分吟外秋。',48,'全唐诗/poet.song.206000.json','["雅調背時流，月分吟外秋。", "墨研青嶂石，茶泛碧霞甌。", "果熟猿難喚，松寒鹿自遊。", "風前橫一笛，不必更登樓。"]'),
('55630bb4-cede-42c6-a487-137d9267fb8b','看桃偶集僧舍','李龏','宋','宋诗','song-poetry','','[]','看桃臨水寺，幽會得文襟。',48,'全唐诗/poet.song.206000.json','["看桃臨水寺，幽會得文襟。", "移石分花坐，含毫對酒吟。", "日斜幡影倒，風斷磬聲沉。", "人散清溪暮，鶑啼出柳林。"]'),
('7c3f57b1-013e-41b5-ba66-81bc173d017f','與箬溪煥上人夜坐','李龏','宋','宋诗','song-poetry','','[]','一庵秋色裏，共坐佛燈前。',48,'全唐诗/poet.song.206000.json','["一庵秋色裏，共坐佛燈前。", "風引上香磬，月浮煎茗泉。", "袖寒沙氣逼，窗迥樹聲懸。", "語罷鴉棲定，山僧入夜禪。"]'),
('16fbe08e-9561-4c4d-9fb2-9387f01c34c3','送張將領','李龏','宋','宋诗','song-poetry','','[]','平生憑一箭，此去必成名。',48,'全唐诗/poet.song.206000.json','["平生憑一箭，此去必成名。", "晚月催行色，秋風入別情。", "潮分江口鎮，山擁石頭城。", "匹馬烟塵外，當開驃騎營。"]'),
('721ddb43-f01e-48d7-a1a5-ce1ed9d1a884','偶飲溪寺','李龏','宋','宋诗','song-poetry','','[]','疏雨過長林，溪頭日半沉。',48,'全唐诗/poet.song.206000.json','["疏雨過長林，溪頭日半沉。", "開尊成草酌，得句嚼花吟。", "蝸砌苔堆濕，蛛簾柳映深。", "倚欄秋欲暮，醉耳怯寒砧。"]'),
('9c8c247d-edee-411d-bfc3-a2b0165c168f','雲間贈別薛沂叔','李龏','宋','宋诗','song-poetry','','[]','水竹居成久，何因又出山。',48,'全唐诗/poet.song.206000.json','["水竹居成久，何因又出山。", "有詩懸肘後，無事在人間。", "短劍丹霞鋟，扁舟白石間。", "野情元不定，遥載鶴鶵還。"]'),
('bbbe5618-9da3-408d-bf36-5e5800c66aaa','梅','李龏','宋','宋诗','song-poetry','','[]','草木盡凋殘，孤標獨耐寒。',48,'全唐诗/poet.song.206000.json','["草木盡凋殘，孤標獨耐寒。", "瘦成唐杜甫，高抵漢袁安。", "雪裏開春國，花中立將壇。", "年年笑紅紫，翻作背時看。"]'),
('ea4959b8-46d5-4a0e-b52e-5a1cc6ab5ee8','癸卯元日','李龏','宋','宋诗','song-poetry','','[]','一簷朝雨若輕塵，新歷雖開未是春。',64,'全唐诗/poet.song.206000.json','["一簷朝雨若輕塵，新歷雖開未是春。", "著出隠衣朝太帝，送來名紙謝同人。", "故園有弟音書絕，要路無親旅食貧。", "五十平頭今日到，不堪卧病似漳濱。"]'),
('276f7730-4156-4fa8-89e5-689d12e83669','送僧過建康','李龏','宋','宋诗','song-poetry','','[]','一酌離亭桑落酒，毿毿短髮長愁苗。',64,'全唐诗/poet.song.206000.json','["一酌離亭桑落酒，毿毿短髮長愁苗。", "秋房已棄星居屋，晚寺應投旦過寮。", "歌哭盡從流水去，榮枯半逐暗塵消。", "江船載月敲銅斗，莫向臺城問六朝。"]'),
('d64c6950-cd09-4f56-ae29-935a65d17d95','倚欄','李龏','宋','宋诗','song-poetry','','[]','裊裊朱欄倚細波，綠雲相對閟嵯峨。',64,'全唐诗/poet.song.206000.json','["裊裊朱欄倚細波，綠雲相對閟嵯峨。", "中天車駕曾擒寇，何日樓船定入河。", "霽柳午陰隨岸遠，露桃春色過牆多。", "黄旗適應東南運，已辦簫鐃幾曲歌。"]'),
('f0bd3cf6-382e-480a-b048-75efc3a390cc','吳下春陰','李龏','宋','宋诗','song-poetry','','[]','雲揭繁陰雨乍收，吳王故國悄如秋。',64,'全唐诗/poet.song.206000.json','["雲揭繁陰雨乍收，吳王故國悄如秋。", "春光物態千年在，草色人心一樣愁。", "香徑有時迷野蝶，帆涇無處覓沙鷗。", "桃花欲謝清明近，兩鬢霜絲感昔遊。"]'),
('a6303f34-40a7-4862-badb-6a95e316fd33','秋日山家','李龏','宋','宋诗','song-poetry','','[]','露華滲冷入綀袍，獨坐雲亭日易高。',64,'全唐诗/poet.song.206000.json','["露華滲冷入綀袍，獨坐雲亭日易高。", "林茂不知山色減，石枯因見水痕牢。", "避人黑鼠窺茅栗，引子黄猨拾楮桃。", "野老欲論城市事，遠教童稚覓香醪。"]'),
('cb2b178f-113e-49dd-ab63-c96d018e8e36','水軒遣懷','李龏','宋','宋诗','song-poetry','','[]','漠漠風烟滃綠陰，小軒多是暗愁侵。',64,'全唐诗/poet.song.206000.json','["漠漠風烟滃綠陰，小軒多是暗愁侵。", "逗明月落杜鵑叫，向晚雨寒蚯蚓吟。", "一鏡自知添鶴髮，五湖誰解食魚心。", "带春應有餘花在，吳苑荒殘不可尋。"]'),
('9c577f1a-3582-4266-bf45-657d585cc9ad','古項王祠','李龏','宋','宋诗','song-poetry','','[]','冊帝追王事總非，殘碑猶自對斜暉。',64,'全唐诗/poet.song.206000.json','["冊帝追王事總非，殘碑猶自對斜暉。", "廟無人到苔痕古，地有蛇盤樹色肥。", "月暗野風吹鬼火，塵昏沙雨駁神衣。", "烏江渡口停騅處，今日誰知作釣磯。"]'),
('2c620f04-b02c-4048-bbbb-4fe61e87bc2b','退將','李龏','宋','宋诗','song-poetry','','[]','自慚戰陣未曾親，便待歸田養幸身。',64,'全唐诗/poet.song.206000.json','["自慚戰陣未曾親，便待歸田養幸身。", "隨仗馬閑秋骨瘦，打毬單散曉眉嚬。", "遊邊尚憶擒虓將，畫閣何堪作老臣。", "昨日望春門外過，鐵鞭惆悵暗生塵。"]'),
('3e800398-b281-465a-8a80-eed4cd48bef3','偶憩破寺','李龏','宋','宋诗','song-poetry','','[]','當軒水漬一池苔，竟日無人見客來。',64,'全唐诗/poet.song.206000.json','["當軒水漬一池苔，竟日無人見客來。", "飛鳥忽從花下出，游僧恰自雨中回。", "半邊枯樹雷燒破，幾段殘碑雪凍開。", "檀施只今何處在，金容冷對石爐灰。"]'),
('f1a864a2-2c07-4dee-8af9-f8aa718ccb22','秋初漫吟','李龏','宋','宋诗','song-poetry','','[]','吟腸悽斷月蒼蒼，促織聲中露未凉。',64,'全唐诗/poet.song.206000.json','["吟腸悽斷月蒼蒼，促織聲中露未凉。", "高掛酒經緣抱病，閒看藥錄爲參方。", "久要兄弟書皆絕，旋雇奴童住不常。", "擬續逐貧揚子賦，筆黏塵網硯池荒。"]'),
('0102215e-7aba-46dc-ad6c-02a9341aae70','弔松山曹可擇','李龏','宋','宋诗','song-poetry','','[]','供奉芸籤內殿間，身清不愧是卑官。',64,'全唐诗/poet.song.206000.json','["供奉芸籤內殿間，身清不愧是卑官。", "带殘敕號縚應斷，吟出新詩板未刊。", "妾引哀歌秋燭暝，客收閑迹曉松寒。", "端平才子如君者，免死江湖把釣竿。"]'),
('710c00a0-0416-4971-b09f-0f4510c73598','喜宥寺梅屋','李龏','宋','宋诗','song-poetry','','[]','幽幽一屋巧藏春，花匠何曾動斧斤。',64,'全唐诗/poet.song.206000.json','["幽幽一屋巧藏春，花匠何曾動斧斤。", "逐朵似裁霜漢月，滿椽如架石橋雲。", "繁花綽有苔錢賃，清夢那無蝶羽分。", "欠得玉人相共住，金樽檀板送斜曛。"]'),
('ad64155c-ca9b-4d9c-966b-7e75710c9ce3','秋曉聞鶴唳','李龏','宋','宋诗','song-poetry','','[]','角斷鐘殘月尚明，誰家霜鶴唳蘋汀。',64,'全唐诗/poet.song.206000.json','["角斷鐘殘月尚明，誰家霜鶴唳蘋汀。", "空簷竹上滴寒露，野水城邊沉曉星。", "清带離情穿碧戶，遠將秋思入蒼冥。", "往年禮謁茅司命，曾記昇元頂上聽。"]'),
('c8642857-b78e-4527-b1b9-007f711ba58e','夜歸','李龏','宋','宋诗','song-poetry','','[]','風急漏聲斷，月斜人影長。',24,'全唐诗/poet.song.206000.json','["風急漏聲斷，月斜人影長。", "殘燈收短市，鴛瓦已凝霜。"]'),
('ef774e1a-6e1f-4554-b46c-4afe5c41aa50','詠老桐','李龏','宋','宋诗','song-poetry','','[]','枯心不作花，儀鳳那采取。',24,'全唐诗/poet.song.206000.json','["枯心不作花，儀鳳那采取。", "何當被朱弦，齎身大晟府。"]'),
('02f134a0-812c-4b5e-9b06-3c5f2160f1a1','贈舟上人','李龏','宋','宋诗','song-poetry','','[]','放浪詩騷外，塵心鍊到空。',24,'全唐诗/poet.song.206000.json','["放浪詩騷外，塵心鍊到空。", "白雲開夜觀，海月冷松風。"]'),
('8f1357c0-a9c7-47cf-82f7-8889f205555f','倚樓','李龏','宋','宋诗','song-poetry','','[]','客意入燈篝，無詩過一秋。',24,'全唐诗/poet.song.206000.json','["客意入燈篝，無詩過一秋。", "角聲吹雨斷，人在截雲樓。"]'),
('e02a5ac2-a973-4593-8c7b-b01d5e2cbbc7','山崦早梅','李龏','宋','宋诗','song-poetry','','[]','晴逼寒笆春滿鄰，漢奩芳額漸輕勻。',32,'全唐诗/poet.song.206000.json','["晴逼寒笆春滿鄰，漢奩芳額漸輕勻。", "東風未放全消息，雨萼愁香不見人。"]'),
('1f554dc5-f05d-43f8-a89d-0b19c4622b60','留別范可叔','李龏','宋','宋诗','song-poetry','','[]','吳臯一水幾番行，鷗鷺相逢眼亦青。',32,'全唐诗/poet.song.206000.json','["吳臯一水幾番行，鷗鷺相逢眼亦青。", "一別隔年頭白盡，離歌今日不須聽。"]'),
('ae6fc7a1-04f7-43e9-881a-c1e0d2b153ed','漁父引','李龏','宋','宋诗','song-poetry','','[]','漁伴歸來語笑喧，盡携筒罩醉雲根。',32,'全唐诗/poet.song.206000.json','["漁伴歸來語笑喧，盡携筒罩醉雲根。", "自從城裏魚增稅，船在江村不入門。"]'),
('a20e2f64-6cba-4595-992d-779fa8b208f0','代贈牧馬將','李龏','宋','宋诗','song-poetry','','[]','草枯水冷馬添臕，箭放鳴髇不射鵰。',32,'全唐诗/poet.song.206000.json','["草枯水冷馬添臕，箭放鳴髇不射鵰。", "塞北又傳烽火動，冠軍人望霍票姚。"]'),
('d6d16503-69ad-41af-9767-a72684dfe958','寒食日','李龏','宋','宋诗','song-poetry','','[]','讀盡唐人寒食詩，人於此日重傷悲。',32,'全唐诗/poet.song.206000.json','["讀盡唐人寒食詩，人於此日重傷悲。", "如今裹飯吳中俗，可是相沿爲子推。"]'),
('6b37cf8f-893f-472a-9792-b536a7aa061c','楚宮秋怨','李龏','宋','宋诗','song-poetry','','[]','水殿芙蓉拆錦苞，暮簷小網集蠨蛸。',32,'全唐诗/poet.song.206000.json','["水殿芙蓉拆錦苞，暮簷小網集蠨蛸。", "射麋人醉秋江畔，風罥塵絲落燕巢。"]'),
('4651c81b-05d5-4e36-a924-43992c1e23d2','張氏池亭飲歸','李龏','宋','宋诗','song-poetry','','[]','金荷杯冷酒醺醺，重費殘花一夜春。',32,'全唐诗/poet.song.206000.json','["金荷杯冷酒醺醺，重費殘花一夜春。", "橫玉聲乾桃葉渡，斷雲空惹舞靴塵。"]'),
('def5455e-e34c-42bd-850b-4ec0c9e5a200','淳祐辛丑元日','李龏','宋','宋诗','song-poetry','','[]','滴酒焚香把筆熏，未書名紙謁朱門。',32,'全唐诗/poet.song.206000.json','["滴酒焚香把筆熏，未書名紙謁朱門。", "對天大寫宜春字，先與孤寒懺宿根。"]'),
('d953bcfe-63d4-489c-b110-615b3865ff00','杜鵑','李龏','宋','宋诗','song-poetry','','[]','心聲叫出思歸苦，叫得春風破膽愁。',32,'全唐诗/poet.song.206000.json','["心聲叫出思歸苦，叫得春風破膽愁。", "江北江南皆蜀客，年來添白幾人頭。"]'),
('a23ccf5b-b01f-420b-9bbb-8fb183d25db0','一片','李龏','宋','宋诗','song-poetry','','[]','一片青蘿絡緯啼，星稀月沒未聞雞。',32,'全唐诗/poet.song.206000.json','["一片青蘿絡緯啼，星稀月沒未聞雞。", "數聲柔艣斜窗外，彷彿風光罨畫溪。"]'),
('a900baad-ec41-4932-a854-e96f1145862e','僧去','李龏','宋','宋诗','song-poetry','','[]','僧去焚香白晝空，客窗斜掩楝花風。',32,'全唐诗/poet.song.206000.json','["僧去焚香白晝空，客窗斜掩楝花風。", "黄鸝舌結春歸盡，煙雨滿林聞郭公。"]'),
('e27d84e5-de7b-4356-9483-bc911d4f5e78','閑倚','李龏','宋','宋诗','song-poetry','','[]','春風樓外白雲堆，壁上塵昏雨後苔。',32,'全唐诗/poet.song.206000.json','["春風樓外白雲堆，壁上塵昏雨後苔。", "倚盡夕陽窗欲掩，小風猶抱落花來。"]'),
('5a9c22df-633a-4440-8d19-5282a63f8626','送高可久遊越','李龏','宋','宋诗','song-poetry','','[]','東風大扇九區春，吳下吟人發廣津。',32,'全唐诗/poet.song.206000.json','["東風大扇九區春，吳下吟人發廣津。", "欲上會稽探禹穴，桃花和雨撲離巾。"]'),
('313ccbbe-3108-4bab-a531-c329bff5b410','賦元秀坐主孤峰','李龏','宋','宋诗','song-poetry','','[]','一峰峭立俯羣山，下有僧居一體閒。',32,'全唐诗/poet.song.206000.json','["一峰峭立俯羣山，下有僧居一體閒。", "收拾春煙與秋雨，年年曾在碧苔間。"]'),
('0af8cb0c-69f2-4f0b-bf94-6cc2c84cff07','文式上人月溪','李龏','宋','宋诗','song-poetry','','[]','菰蒲聲裏著禪扃，一派蟾光畫不成。',32,'全唐诗/poet.song.206000.json','["菰蒲聲裏著禪扃，一派蟾光畫不成。", "試看世人心似火，何時得此定中清。"]'),
('bbbd4e3a-3819-4e66-bfca-b552b20e7c4a','曉起','李龏','宋','宋诗','song-poetry','','[]','蕭城一雨夜迷迷，聞道春流已滿溪。',32,'全唐诗/poet.song.206000.json','["蕭城一雨夜迷迷，聞道春流已滿溪。", "漉禿隔牆烏桕樹，曉來猶有亂鴉棲。"]'),
('46628a53-e380-45f5-8ed5-09da386e130c','春晚呈節齋趙大資二首  其一','李龏','宋','宋诗','song-poetry','','[]','韶光似酒著人濃，池館春殘柳絮風。',32,'全唐诗/poet.song.206000.json','["韶光似酒著人濃，池館春殘柳絮風。", "花不耐愁春自去，鶑聲全在綠陰中。"]'),
('f2c973bf-f1c4-4228-959f-587c5f91800c','春晚呈節齋趙大資二首  其二','李龏','宋','宋诗','song-poetry','','[]','宿雲惹雨膩如塵，濕盡薔薇一片春。',32,'全唐诗/poet.song.206000.json','["宿雲惹雨膩如塵，濕盡薔薇一片春。", "鶗鴂恰鳴胡蝶嬾，軫香惟惱扈芳人。"]'),
('7efce267-0e79-4c64-8b65-4a57e5adc143','蟋蟀','李龏','宋','宋诗','song-poetry','','[]','朱欄碧戶綠莎邊，挑入雕籠合自憐。',32,'全唐诗/poet.song.206000.json','["朱欄碧戶綠莎邊，挑入雕籠合自憐。", "應是不知悽楚意，癡兒爭把鬭金錢。"]'),
('9b3489ed-8430-4b8e-a8bb-a618da350cb1','月林爲僧甫賦','李龏','宋','宋诗','song-poetry','','[]','篩金鏤玉影颼颼，一片松杉不斷頭。',32,'全唐诗/poet.song.206000.json','["篩金鏤玉影颼颼，一片松杉不斷頭。", "鐘梵聲殘寒汐外，石床常擁四時秋。"]'),
('bff0d270-3014-4ff4-ab83-798e9d86ddaf','送超上人過靈隠','李龏','宋','宋诗','song-poetry','','[]','斗邊一塔冷浮光，九里松風揭寺香。',32,'全唐诗/poet.song.206000.json','["斗邊一塔冷浮光，九里松風揭寺香。", "君去正當春雨動，雪花消盡石蘭芳。"]'),
('81333135-4759-4dbf-8606-6beaadbf2739','贈僧某','李龏','宋','宋诗','song-poetry','','[]','曾見升壇落髮時，伽黎衣冷影離離。',32,'全唐诗/poet.song.206000.json','["曾見升壇落髮時，伽黎衣冷影離離。", "少年同隊修禪者，秋水蓮中玉一枝。"]'),
('b5c94bc3-ae7b-4928-829d-222016255b96','贈僧演若海','李龏','宋','宋诗','song-poetry','','[]','禪心靜寄十三徽，流水知音舉世稀。',32,'全唐诗/poet.song.206000.json','["禪心靜寄十三徽，流水知音舉世稀。", "自愛聲空弦絕處，滿天明月鶴孤飛。"]'),
('38d1b3d5-ca85-4e26-a8ee-011ce16587fa','敬酬芳庭植講師','李龏','宋','宋诗','song-poetry','','[]','一卷新詩寫衆芳，碧雲裹出白雲鄉。',32,'全唐诗/poet.song.206000.json','["一卷新詩寫衆芳，碧雲裹出白雲鄉。", "小溪秋水蘋花外，良慰孤吟老夕陽。"]'),
('27350d72-46de-41e3-b4b7-9f21dd6b7e17','送中巖立上人還臯亭山','李龏','宋','宋诗','song-poetry','','[]','少年如玉在緇林，此去臯亭落葉深。',32,'全唐诗/poet.song.206000.json','["少年如玉在緇林，此去臯亭落葉深。", "寺近海門潮上處，水中孤月是禪心。"]'),
('989413c2-9d6c-45c5-9538-bb922b3abd20','送觀物初禪師退院後歸靈隠','李龏','宋','宋诗','song-poetry','','[]','擊殘塗毒抖衣塵，便掛輕帆破淺春。',32,'全唐诗/poet.song.206000.json','["擊殘塗毒抖衣塵，便掛輕帆破淺春。", "後夜冷泉池上看，白雲明月是閒身。"]'),
