('5df28b3e-4588-460b-b578-3bb27487f1bd','梅花集句  其一八八','李龏','宋','宋诗','song-poetry','','[]','梅落經霜霰，雲連京國深。',24,'全唐诗/poet.song.206000.json','["梅落經霜霰，雲連京國深。", "金罍列四座，春色豈知心。"]'),
('0ecb8aa5-1893-4082-b235-d40a991a7b37','梅花集句  其一八九','李龏','宋','宋诗','song-poetry','','[]','池草艷春色，流芳復滿園。',24,'全唐诗/poet.song.206000.json','["池草艷春色，流芳復滿園。", "只應連夜雨，花落擁籬根。"]'),
('c555a0e9-6e00-4219-a65a-3a60a0e9d339','梅花集句  其一九○','李龏','宋','宋诗','song-poetry','','[]','世上樹桃李，逢春解惜春。',24,'全唐诗/poet.song.206000.json','["世上樹桃李，逢春解惜春。", "不知春色早，對此合傷神。"]'),
('0cc3568f-1f12-4ba7-9f31-38e757364513','梅花集句  其一九一','李龏','宋','宋诗','song-poetry','','[]','逆旅相逢處，冥冥花正開。',24,'全唐诗/poet.song.206000.json','["逆旅相逢處，冥冥花正開。", "今朝與君醉，不辨越王臺。"]'),
('6ce44d07-ff7b-4512-9bdd-c85ad5237676','梅花集句  其一九二','李龏','宋','宋诗','song-poetry','','[]','野渡人初過，人悲花自閑。',24,'全唐诗/poet.song.206000.json','["野渡人初過，人悲花自閑。", "歌聲隨綠水，春滿杏花山。"]'),
('e0af6d70-f9e7-41b8-8adb-bc071e00fb94','梅花集句  其一九三','李龏','宋','宋诗','song-poetry','','[]','舊雪逐泥沙，驚雷長荻芽。',24,'全唐诗/poet.song.206000.json','["舊雪逐泥沙，驚雷長荻芽。", "低簷一枝在，恐有夜來花。"]'),
('16f1b2ef-e327-466b-8387-af140b0d01ff','梅花集句  其一九四','李龏','宋','宋诗','song-poetry','','[]','一點白如雪，玄機未易窺。',24,'全唐诗/poet.song.206000.json','["一點白如雪，玄機未易窺。", "歲華摇落盡，空把月中枝。"]'),
('961e08cf-2b58-4ab7-a45d-20b43eb3b3f1','梅花集句  其一九五','李龏','宋','宋诗','song-poetry','','[]','病見巖花發，風霜一歲殘。',24,'全唐诗/poet.song.206000.json','["病見巖花發，風霜一歲殘。", "月斜寒影動，清比玉堪餐。"]'),
('3c0ff26f-3b90-471d-94b0-4f3f00c04a94','梅花集句  其一九六','李龏','宋','宋诗','song-poetry','','[]','高樹梅初發，城隅古謝村。',24,'全唐诗/poet.song.206000.json','["高樹梅初發，城隅古謝村。", "况多秋蘚色，巧詠任人言。"]'),
('1da988bd-6d28-4c52-9a81-fe32eb1af5c5','梅花集句  其一九七','李龏','宋','宋诗','song-poetry','','[]','落日明深塢，新移棘補籬。',24,'全唐诗/poet.song.206000.json','["落日明深塢，新移棘補籬。", "野花春後發，獨自立多時。"]'),
('a07decb3-d19b-4d76-8c34-25f8b0dad054','梅花集句  其一九八','李龏','宋','宋诗','song-poetry','','[]','畫閤餘寒在，花明綺陌春。',24,'全唐诗/poet.song.206000.json','["畫閤餘寒在，花明綺陌春。", "今年看花伴，東去汶陽濱。"]'),
('9d5256e2-1669-43dc-8a68-70cbb5c71fdc','梅花集句  其一九九','李龏','宋','宋诗','song-poetry','','[]','無處寫幽懷，前山雪未開。',24,'全唐诗/poet.song.206000.json','["無處寫幽懷，前山雪未開。", "一階春草碧，偶到樹邊來。"]'),
('ba291dda-c0ff-4f31-a149-53cadb9ba9c6','梅花集句  其二○○','李龏','宋','宋诗','song-poetry','','[]','數枝寒照水，幽意日相親。',24,'全唐诗/poet.song.206000.json','["數枝寒照水，幽意日相親。", "愛此無他客，遥將寄野人。"]'),
('c32605d5-2e2b-435e-8e95-f879d6f998f4','梅花集句  其二○一','李龏','宋','宋诗','song-poetry','','[]','漁舸汀鴻外，霜天似水清。',24,'全唐诗/poet.song.206000.json','["漁舸汀鴻外，霜天似水清。", "更無花上月，新句與誰評。"]'),
('3ccd4f3d-8966-4b64-b4b1-1a4d67d8a491','梅花集句  其二○二','李龏','宋','宋诗','song-poetry','','[]','枯株圍古寺，老怪昔誰栽。',24,'全唐诗/poet.song.206000.json','["枯株圍古寺，老怪昔誰栽。", "水國花開早，疏花晚自開。"]'),
('a39c867d-75ad-4a26-a6f6-74827dfd81b1','梅花集句  其二○三','李龏','宋','宋诗','song-poetry','','[]','問得梅花信，新晴花氣香。',24,'全唐诗/poet.song.206000.json','["問得梅花信，新晴花氣香。", "戲賡和靖句，炙背負斜陽。"]'),
('93fd90d0-575a-4717-88fb-c35350d25328','梅花集句  其二○四','李龏','宋','宋诗','song-poetry','','[]','觸處是花開，孤高不受埃。',24,'全唐诗/poet.song.206000.json','["觸處是花開，孤高不受埃。", "春風別有意，時有暗香來。"]'),
('42588f56-f947-4f53-81c3-74de1733a2b3','梅花集句  其二○五','李龏','宋','宋诗','song-poetry','','[]','幾度尋春信，親曾到石橋。',24,'全唐诗/poet.song.206000.json','["幾度尋春信，親曾到石橋。", "寒雲拂縞夜，恨不坐通宵。"]'),
('5be84c81-ed04-4bb8-bba7-56a1d63d9c47','梅花集句  其二○六','李龏','宋','宋诗','song-poetry','','[]','旅望因高盡，江春入舊年。',24,'全唐诗/poet.song.206000.json','["旅望因高盡，江春入舊年。", "紛紛對寂寞，花隔杜陵煙。"]'),
('4db2889f-9a4b-4ba2-9bd3-fd069b2b7cb2','梅花集句  其二○七','李龏','宋','宋诗','song-poetry','','[]','捲簾清夢後，靜角揜山城。',24,'全唐诗/poet.song.206000.json','["捲簾清夢後，靜角揜山城。", "氣射燈花落，饑膚片玉明。"]'),
('dfb42c50-c66d-4da2-85cb-29eb24df5432','梅花集句  其二○八','李龏','宋','宋诗','song-poetry','','[]','積雪暮山寒，枝枝入肺肝。',24,'全唐诗/poet.song.206000.json','["積雪暮山寒，枝枝入肺肝。", "高風吹不盡，一半更須看。"]'),
('3a6b3393-a481-48a9-9e97-0ce5addb012b','梅花集句  其二○九','李龏','宋','宋诗','song-poetry','','[]','雪消春力展，林雪似芳菲。',24,'全唐诗/poet.song.206000.json','["雪消春力展，林雪似芳菲。", "獨映孤松色，煩君問是非。"]'),
('32ffc4ab-8abc-42b1-a4c3-d804018b33fa','梅花集句  其二一○','李龏','宋','宋诗','song-poetry','','[]','蠹根停雪水，花落釣人頭。',24,'全唐诗/poet.song.206000.json','["蠹根停雪水，花落釣人頭。", "萬里猿頻斷，春風亦似秋。"]'),
('c9453f9b-1b27-4f89-bff4-925b0c18c1b2','梅花集句  其二一一','李龏','宋','宋诗','song-poetry','','[]','鳥喧金谷樹，惟此出塵埃。',24,'全唐诗/poet.song.206000.json','["鳥喧金谷樹，惟此出塵埃。", "古戍鳴寒角，池塘暗不開。"]'),
('6632f33b-2907-4d64-ab4a-2ef0f9f4dfa1','梅花集句  其二一二','李龏','宋','宋诗','song-poetry','','[]','人情皆共惜，勿謂少知音。',24,'全唐诗/poet.song.206000.json','["人情皆共惜，勿謂少知音。", "若問陽臺客，曾供雪夜吟。"]'),
('6acd5713-48ba-46b5-85bc-166c97465133','謫仙吟','李龏','宋','宋诗','song-poetry','','[]','空白凝雲頹不流，牧龍丈人病歌秋。',64,'全唐诗/poet.song.206000.json','["空白凝雲頹不流，牧龍丈人病歌秋。", "尋詩北嶺截珠樹，老夫饑寒龍爲愁。", "呼龍耕煙種瑶草，若爲失意居蓬島。", "泓泓水繞青苔洲，鯉魚風起芙蓉老。"]'),
('b2aa6f8c-f229-4371-b264-5f2b8beaa22b','公無渡河','李龏','宋','宋诗','song-poetry','','[]','屈平沉湘不足慕，公無渡河兮公苦渡。',65,'全唐诗/poet.song.206000.json','["屈平沉湘不足慕，公無渡河兮公苦渡。", "行搔短髮提壺漿，玉白蘭芳不相顧。", "驚波不在黤黮間，顔色錯漠生風煙。", "其下無底旁無邊，何用將身自棄捐。"]'),
('3a1b5067-d56d-4145-ac4c-e80b9547ed89','長安春','李龏','宋','宋诗','song-poetry','','[]','春欲來，日日望春門早開。',76,'全唐诗/poet.song.206000.json','["春欲來，日日望春門早開。", "花臺欲暮春辭去，禁城煙暖蒸青苔。", "齷齪浮生如走電，客舍似愁誰遣來。", "夜夜抱冰寒不睡，流光暫出還入地。", "門外平橋連柳堤，落花聲裏仙娥醉。"]'),
('eab46cc7-874e-4143-9fc9-494d322af26e','行路難','李龏','宋','宋诗','song-poetry','','[]','君不見長安城北渭橋邊，長安惡少不少錢。',158,'全唐诗/poet.song.206000.json','["君不見長安城北渭橋邊，長安惡少不少錢。", "飛窗複道傳頭飲，金鯨瀉酒如飛泉。", "春風細雨走馬去，鳴鞭晚出章臺路。", "半垂衫袖揖金吾，誰道黄金如糞土。", "床頭黄金盡，中門爲異域。", "骨肉且不顧，促刺復促刺。", "世路有趨競，人無一定顔。", "何處是平地，暗水自波瀾。", "君不見建章宮中金明枝，春花落盡蜂不窺。", "雙輪晚上銅梁雪，當春對酒不須疑。", "行路難，君好看。"]'),
('b38ddb96-0a26-4432-bf23-77e65bf326f8','塞上北風行','李龏','宋','宋诗','song-poetry','','[]','北風叫枯桑，玉沙粼粼光。',60,'全唐诗/poet.song.206000.json','["北風叫枯桑，玉沙粼粼光。", "天寒山路石斷裂，駐馬相看遼水傍。", "軍容带甲三十萬，都護寶刀凍欲斷。", "旄頭夜落捷書飛，少年金紫就光輝。"]'),
('285a0778-6df1-4b46-b990-25cf07c45ac9','吳娃歌','李龏','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭明月一千里，芙蓉水殿春風起。',64,'全唐诗/poet.song.206000.json','["洞庭明月一千里，芙蓉水殿春風起。", "殘絲欲斷黄蜂歸，鴛鴦翡翠承燕私。", "露脚斜飛濕寒兔，越王金雞報天曙。", "官街柳带不堪折，謝豹空啼采香月。"]'),
('d70082a4-5afe-46ca-8df5-25eca51ccdf9','致酒行','李龏','宋','宋诗','song-poetry','','[]','零落棲遲一杯酒，綠凸蠻觥奉君壽。',64,'全唐诗/poet.song.206000.json','["零落棲遲一杯酒，綠凸蠻觥奉君壽。", "湖花江月前後隣，寒風又變爲春柳。", "離鸞別鳳煙梧中，曦輪送客溝水東。", "霜白松溪轉斜蓋，世間何處無春風。"]'),
('0fecf53e-cb16-4493-8e9e-7e577583a347','採蓮歸','李龏','宋','宋诗','song-poetry','','[]','採蓮女，採蓮歸。',68,'全唐诗/poet.song.206000.json','["採蓮女，採蓮歸。", "落日晴江裏，蓮舟漸覺稀。", "蓮莖有刺不成折，爭弄蓮花水濕衣。", "白練束腰袖半卷，不語低鬟幽思遠。", "碧玉搔頭落水中，粉痕零落愁紅淺。"]'),
('76c5b02b-36ca-4ef4-8309-e5812f259ab0','溪上春','李龏','宋','宋诗','song-poetry','','[]','黄璈散珠層殿曛，東方風來滿眼春。',64,'全唐诗/poet.song.206000.json','["黄璈散珠層殿曛，東方風來滿眼春。", "龍蛇洗鱗春水暖，薇帳逗煙生綠塵。", "古人花爲今人發，溪女洗花染白雲。", "赤水閬風誰是主，西山日沒東山昏。"]'),
('39916a9a-16ea-45ed-99b1-15a2e8e1c490','秋閨思','李龏','宋','宋诗','song-poetry','','[]','征人遥遥出古城，天河夜轉漂迴星。',64,'全唐诗/poet.song.206000.json','["征人遥遥出古城，天河夜轉漂迴星。", "銀縷香寒鳳皇薄，樹色深含臺榭情。", "雨滋苔蘚侵階綠，爲有秋期眠不足。", "城邊殘月勢如弓，月下丁東擣寒玉。"]'),
('830c0c6b-d567-4ec6-802c-4fdd48b152f3','京洛篇','李龏','宋','宋诗','song-poetry','','[]','東望龍門北朝市，甲第千甍分戚里。',64,'全唐诗/poet.song.206000.json','["東望龍門北朝市，甲第千甍分戚里。", "朱門峨峨臨九衢，垂柳金絲香拂水。", "毗陵震澤九州通，董賢女弟在椒風。", "周公舊跡生紅蘚，九泉寂寞葬秋蟲。"]'),
('717f4983-d688-4676-9fda-6e3ee61d4600','夢上天','李龏','宋','宋诗','song-poetry','','[]','馭鳳昇崑崙，夢上高高天。',92,'全唐诗/poet.song.206000.json','["馭鳳昇崑崙，夢上高高天。", "雲樓半開壁斜白，蓬萊宮殿玉爐煙。", "春羅書字邀王母，綠章封事諮元父。", "鴻瓏九關朝玉皇，大道無言暗相許。", "身不沉，骨不重，半空回首晨雞弄。", "寒綠幽風生短絲，春雷蟄蟄龍蛇動。"]'),
('f8b99387-e9db-4f34-a22c-ab176c1aa589','空城曲','李龏','宋','宋诗','song-poetry','','[]','玉轉濕絲牽曉水，昔日住人今住鬼。',64,'全唐诗/poet.song.206000.json','["玉轉濕絲牽曉水，昔日住人今住鬼。", "東家胡蝶西家飛，星流露泫誰驅使。", "秋風吹地百草乾，兔苑詞人去不還。", "誰念幽寒坐嗚呃，長憶深雲海上山。"]'),
('e255c147-2094-4a3d-ac0a-69991a369ea9','短歌行','李龏','宋','宋诗','song-poetry','','[]','日月出又沒，貴賤同一塵。',128,'全唐诗/poet.song.206000.json','["日月出又沒，貴賤同一塵。", "求榮不求辱，利欲相紛綸。", "鯨魚張鬣海水沸，擬學長生更容易。", "不知中有長恨端，秦亡祖龍失天地。", "野草白根肥，鳳雛長忍饑。", "人生過五十，何用假光輝。", "四時相催節回換，烏頭雖黑有白時。", "一尊綠酒綠於染，有歌有舞聞早爲。", "庭前芳樹朝夕改，可歎年光不相待。"]'),
('29407739-7fac-40f4-943d-8820cd67e150','蒿里曲','李龏','宋','宋诗','song-poetry','','[]','古人今人留不住，六街馬蹄浩無主。',64,'全唐诗/poet.song.206000.json','["古人今人留不住，六街馬蹄浩無主。", "喪車轔轔入秋草，丘壠年年無舊道。", "天娃剪霞鋪曉空，幽愁秋氣上青楓。", "寒食家家送紙錢，紙錢那得到黄泉。"]'),
('32dae627-6695-40fb-bfef-2cb7651fe3ff','烏夜啼','李龏','宋','宋诗','song-poetry','','[]','衆鳥各歸枝，落花香滿泥。',60,'全唐诗/poet.song.206000.json','["衆鳥各歸枝，落花香滿泥。", "狹斜柳樹烏爭宿，夜夜夜半當戶啼。", "浮萍摇蕩門前水，九節菖蒲石上死。", "感郎中夜渡瀟湘，恩光暗入簾櫳裏。"]'),
('4ecc88cc-c4b1-473a-9c3f-5d291fde7e43','公無出門','李龏','宋','宋诗','song-poetry','','[]','天迷迷，地密密，海漫漫。',134,'全唐诗/poet.song.206000.json','["天迷迷，地密密，海漫漫。", "身若倉中鼠，遲回出門難。", "大道冥冥不知處，小人心裏藏崩湍。", "我亦爲君長嘆息，炊沙作飯豈堪喫。", "棘鍼生猛義路閑，太華磨成一拳石。", "不懼天地傾，津涯浩難識。", "龍蟠泥中未有雲，封狐雄虺自成群。", "人生結交在終始，細人何言入君耳。", "歸卧東窗兀然醉，任他上是天，下是地。"]'),
('3a23038f-f189-41f5-a024-90efb7639473','少年行','李龏','宋','宋诗','song-poetry','','[]','丈夫十八九，驄馬拂繡裳。',48,'全唐诗/poet.song.206000.json','["丈夫十八九，驄馬拂繡裳。", "倒插銀魚袋，陪遊出建章。", "醉下酒家樓，軒車滿垂楊。", "君王正年少，無人薦馮唐。"]'),
('2ad7054f-0564-4e15-929d-80435705045f','遠別離','李龏','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖三山口，中有西行舟。',80,'全唐诗/poet.song.206000.json','["太湖三山口，中有西行舟。", "望望不相近，望中生遠愁。", "重露濕蒼苔，秋風散楊柳。", "空藏蘭蕙心，離恨如旨酒。", "碧紗窗外葉騷騷，三更風作切夢刀。", "千里萬里獨爲客，少年心事風中毛。"]'),
('234860bf-6fd2-439c-9452-e85c121cc696','銅雀妓','李龏','宋','宋诗','song-poetry','','[]','淚眼看花枝，齊行奠玉杯。',52,'全唐诗/poet.song.206000.json','["淚眼看花枝，齊行奠玉杯。", "日暮銅雀迥，歌舞妾空來。", "悲心舞不成，恨唱歌聲咽。", "君王去後行人絕，但見西陵慘明月。"]'),
('b20ca405-a01c-4572-a242-ebe797159039','江南思','李龏','宋','宋诗','song-poetry','','[]','妾家白蘋浦，柳惲乘馬歸。',72,'全唐诗/poet.song.206000.json','["妾家白蘋浦，柳惲乘馬歸。", "恰值清風起，朱服弄芳菲。", "離居不自堪，留情此芳甸。", "臨醉欲拚嬌，惡許傍人見。", "相逢恐相失，徘徊雙明璫。", "歸時不覺夜，要使兩情傷。"]'),
('ffc2ec6c-9e24-44dd-8236-22f0bc50c703','折楊柳','李龏','宋','宋诗','song-poetry','','[]','萬里邊城地，垂楊二月春。',48,'全唐诗/poet.song.206000.json','["萬里邊城地，垂楊二月春。", "年華枝上見，日暮客愁新。", "露葉疑啼臉，風花思舞巾。", "玳梁誰道好，持此寄情人。"]'),
('f94f8e63-c4c6-4b86-9c68-79f864b4eee6','秋夜曲','李龏','宋','宋诗','song-poetry','','[]','秋夜長，殊未央。',40,'全唐诗/poet.song.206000.json','["秋夜長，殊未央。", "秋燈向壁掩洞房，天漢東西月色光。", "啼蛄吊月鈎欄下，寒衣未寄莫飛霜。"]'),
('63be8356-bf8d-4cc5-9ac2-e86bd8ed3fc7','出塞','李龏','宋','宋诗','song-poetry','','[]','單于寇井陘，進軍飛狐北。',48,'全唐诗/poet.song.206000.json','["單于寇井陘，進軍飛狐北。", "沙昏夜探遲，遠樹深疑賊。", "胡霜損漢兵，不妨得頭白。", "功成須獻捷，會勒燕然石。"]'),
('6e933ee8-e7a1-4953-b264-055ce8909fe1','老婦吟','李龏','宋','宋诗','song-poetry','','[]','萬轉愁成繫腸線，青畝春蕪連石苑。',32,'全唐诗/poet.song.206000.json','["萬轉愁成繫腸線，青畝春蕪連石苑。", "爲他人作嫁衣裳，頭白如絲面如繭。"]'),
('7968e258-e5d6-40ec-ba97-58ac66a04258','寒女歎','李龏','宋','宋诗','song-poetry','','[]','國色久在室，寒女不自知。',36,'全唐诗/poet.song.206000.json','["國色久在室，寒女不自知。", "安得長不老，爲君玄鬢衰。", "我有古時鏡，一照一回悲。"]'),
('04012d5e-798a-4149-9a42-86075d6322d3','怨詩二首  其一','李龏','宋','宋诗','song-poetry','','[]','綠蔓花綿綿，日晚梧桐落。',24,'全唐诗/poet.song.206000.json','["綠蔓花綿綿，日晚梧桐落。", "所思終不來，蟲聲入羅幕。"]'),
('a15070a8-cadb-4640-9674-ba9f48a49ae2','怨詩二首  其二','李龏','宋','宋诗','song-poetry','','[]','洞房秋月明，玉關芳信斷。',24,'全唐诗/poet.song.206000.json','["洞房秋月明，玉關芳信斷。", "含怨倚蘭叢，日驚羅带緩。"]'),
('ef7ddfa9-531d-4c9c-b023-ed294ef9f95c','過臺城','李龏','宋','宋诗','song-poetry','','[]','雲慘煙愁苑路斜，馬嘶殘日沒殘霞。',32,'全唐诗/poet.song.206000.json','["雲慘煙愁苑路斜，馬嘶殘日沒殘霞。", "繞籬野菜飛黄蝶，宮殿餘基長草花。"]'),
('0e9e957d-fc0c-47a0-b756-4c4935583c9a','金陵春日','李龏','宋','宋诗','song-poetry','','[]','登臨吟望思無窮，折盡青青賞盡紅。',32,'全唐诗/poet.song.206000.json','["登臨吟望思無窮，折盡青青賞盡紅。", "白鳥影從江樹沒，數峰春色在雲中。"]'),
('db4da065-6a34-4961-a9ab-03f2b011f01e','寒食日花讌','李龏','宋','宋诗','song-poetry','','[]','萬象鮮明禁火前，紅英翠萼簇芳筵。',32,'全唐诗/poet.song.206000.json','["萬象鮮明禁火前，紅英翠萼簇芳筵。", "殘春未必多風雨，少別穠華又隔年。"]'),
('82d7d35d-11ee-4524-a353-cd21cf64fa3d','湖上贈新得意者','李龏','宋','宋诗','song-poetry','','[]','湖上新正逢故人，天明騎馬入紅塵。',32,'全唐诗/poet.song.206000.json','["湖上新正逢故人，天明騎馬入紅塵。", "憑君莫話封侯事，栲栳量金買斷春。"]'),
('b2acc8be-f32a-46da-91ac-da4ccb5be917','惆悵詩  其一','李龏','宋','宋诗','song-poetry','','[]','覺來燈背錦屏空，自愛殘粧曉鏡中。',32,'全唐诗/poet.song.206000.json','["覺來燈背錦屏空，自愛殘粧曉鏡中。", "寂寞閑庭春欲晚，垂楊無力受東風。"]'),
('1785c8ff-32a6-4252-ab3f-d4faf0325b8d','惆悵詩  其二','李龏','宋','宋诗','song-poetry','','[]','繡林紅岸落花鈿，目極雲霄思浩然。',32,'全唐诗/poet.song.206000.json','["繡林紅岸落花鈿，目極雲霄思浩然。", "漳浦病多愁易老，滿庭榆莢似秋天。"]'),
('70339f28-3695-4359-acac-6f20f9acb4d7','初夏偶賦','李龏','宋','宋诗','song-poetry','','[]','野煙喬木弄殘暉，虛室無人乳燕飛。',32,'全唐诗/poet.song.206000.json','["野煙喬木弄殘暉，虛室無人乳燕飛。", "正是清和好時節，青叢花盡蝶來稀。"]'),
('efaf51ca-9812-416f-bdf3-082454a5b3ff','宿建溪','李龏','宋','宋诗','song-poetry','','[]','樹侵閩嶺漸無霜，一望繁花一縣香。',32,'全唐诗/poet.song.206000.json','["樹侵閩嶺漸無霜，一望繁花一縣香。", "寂寞舟中誰借問，隔簾微月入中倉。"]'),
('f8e68d4b-93c7-4c08-b2a3-8ffc91d7eedb','夏日松陵道中','李龏','宋','宋诗','song-poetry','','[]','煙岸人稀草色中，火天無處買清風。',32,'全唐诗/poet.song.206000.json','["煙岸人稀草色中，火天無處買清風。", "西南一望雲和水，萬樹鳴蟬隔斷虹。"]'),
('4e6a914f-84c1-4ba8-bcc2-7aeb31bf49fe','秋晚泊吳江塔院寄王抱節','李龏','宋','宋诗','song-poetry','','[]','雨後沙虛古岸崩，水風霜氣夜稜稜。',32,'全唐诗/poet.song.206000.json','["雨後沙虛古岸崩，水風霜氣夜稜稜。", "冷煙粘柳蟬聲老，高塔晴來獨自登。"]'),
('fc8c5e6b-88a2-479b-9e0e-b521517302ab','漁人野祭','李龏','宋','宋诗','song-poetry','','[]','婆官賽却坐江隈，煙水悠悠霽景開。',32,'全唐诗/poet.song.206000.json','["婆官賽却坐江隈，煙水悠悠霽景開。", "精魄不知何處在，野風吹起紙錢灰。"]'),
('27014e42-69d8-4e7f-940b-a84c130fdcbb','酬左行之金陵夕遊','李龏','宋','宋诗','song-poetry','','[]','宮城日晚度寒鴉，新意雖多舊約賒。',32,'全唐诗/poet.song.206000.json','["宮城日晚度寒鴉，新意雖多舊約賒。", "商女不知亡國恨，恨君嗔折後庭花。"]'),
('eda0b652-f72a-4f47-92be-f86c5a553867','書山居女冠繡樓','李龏','宋','宋诗','song-poetry','','[]','一渠流水數家分，絃管樓中永不聞。',32,'全唐诗/poet.song.206000.json','["一渠流水數家分，絃管樓中永不聞。", "燈下此心誰共說，紫煙衣上繡春雲。"]'),
('c77ae55e-2881-4129-b30e-f98bbba239ea','雪  其一','李龏','宋','宋诗','song-poetry','','[]','細玉羅紋下碧霄，縈叢自學小梅嬌。',32,'全唐诗/poet.song.206000.json','["細玉羅紋下碧霄，縈叢自學小梅嬌。", "閑吟只愛煎茶澹，旋斫生柴带葉燒。"]'),
('2a89aa31-6efb-4fc4-83ec-96464ef103eb','雪  其二','李龏','宋','宋诗','song-poetry','','[]','密片無聲急復遲，夜來誰向月中歸。',32,'全唐诗/poet.song.206000.json','["密片無聲急復遲，夜來誰向月中歸。", "江湖不見飛禽影，寒鎖侯門見客稀。"]'),
('04a5d538-bcec-4ae0-b0c7-2ad214f1a7cd','三衢道中','李龏','宋','宋诗','song-poetry','','[]','桂玉愁居帝里貧，南行無罪似流人。',32,'全唐诗/poet.song.206000.json','["桂玉愁居帝里貧，南行無罪似流人。", "橘村籬落香潜度，漸覺生衣不著身。"]'),
('cace872d-59bf-4c1b-aae7-c42d488c2791','天城貴家妓','李龏','宋','宋诗','song-poetry','','[]','龍山晴雪鳳樓霞，煙水初消見萬家。',32,'全唐诗/poet.song.206000.json','["龍山晴雪鳳樓霞，煙水初消見萬家。", "寶枕垂雲選春夢，隔簾微雨濕梨花。"]'),
('8791f48b-f753-4b5c-919c-0b2b23f884f6','送通上人謁賈寺丞','李龏','宋','宋诗','song-poetry','','[]','進乏梯媒退又難，近因多難怕長安。',32,'全唐诗/poet.song.206000.json','["進乏梯媒退又難，近因多難怕長安。", "相知莫話詩心苦，乞取新詩合掌看。"]'),
('9283de88-ccf0-4282-a80a-ca0904dd0adf','與鄭澹然','李龏','宋','宋诗','song-poetry','','[]','曾是朱門寄食身，一生生計祇長貧。',32,'全唐诗/poet.song.206000.json','["曾是朱門寄食身，一生生計祇長貧。", "清閑自可齊三壽，他日相逢乞藥銀。"]'),
('f96683c1-a33e-4fdc-931e-219d9f6724db','送黄中入吳門','李龏','宋','宋诗','song-poetry','','[]','行到鱸魚鄉裏時，一宮花渚漾漣漪。',32,'全唐诗/poet.song.206000.json','["行到鱸魚鄉裏時，一宮花渚漾漣漪。", "看春又過清明節，更把愁心說向誰。"]'),
('23aa2a11-08f3-4620-8536-e58e4455939c','桐江客舍酬客','李龏','宋','宋诗','song-poetry','','[]','一片離心白羽輕，桐廬江上晚潮生。',32,'全唐诗/poet.song.206000.json','["一片離心白羽輕，桐廬江上晚潮生。", "客來吳越星霜久，身賤多慙問姓名。"]'),
('bc032845-372f-4bb5-9d5d-7b77dea5b202','春日詠懷  其一','李龏','宋','宋诗','song-poetry','','[]','客舍青青柳色新，濕雲如夢雨如塵。',32,'全唐诗/poet.song.206000.json','["客舍青青柳色新，濕雲如夢雨如塵。", "經年抱疾誰來問，萍梗何年是住身。"]'),
('5ca3a9a7-8a19-4a03-bcb2-b8193de5e24b','春日詠懷  其二','李龏','宋','宋诗','song-poetry','','[]','春陰初過海棠時，病客遥聽百舌兒。',32,'全唐诗/poet.song.206000.json','["春陰初過海棠時，病客遥聽百舌兒。", "縱有芳樽心不醉，落花如雨淚胭脂。"]'),
('efc80086-d024-4cca-ab15-c328a67c890a','南郭晴步','李龏','宋','宋诗','song-poetry','','[]','春城無處不開花，南陌晴雲稍變霞。',32,'全唐诗/poet.song.206000.json','["春城無處不開花，南陌晴雲稍變霞。", "高下麥苗新雨後，不教閑地著春華。"]'),
('4c513e08-1f8b-4bb7-bc8e-557466be5522','送人歸霅城','李龏','宋','宋诗','song-poetry','','[]','江蘺初綠怨騷人，且向東溪種白蘋。',32,'全唐诗/poet.song.206000.json','["江蘺初綠怨騷人，且向東溪種白蘋。", "別恨最深何處寫，數株殘柳不勝春。"]'),
('17ec413a-6a41-4eef-8c67-fa36fd7bf013','遊法華寺','李龏','宋','宋诗','song-poetry','','[]','野寺尋春春已遲，青山一路鳥空啼。',32,'全唐诗/poet.song.206000.json','["野寺尋春春已遲，青山一路鳥空啼。", "何人爲倚東樓柱，可有文詞詠碧雞。"]'),
('76176ade-2114-4dcb-9e17-9d12caaff2cf','贈野廟祈雨老巫','李龏','宋','宋诗','song-poetry','','[]','桑條無葉土生煙，上德由來合動天。',32,'全唐诗/poet.song.206000.json','["桑條無葉土生煙，上德由來合動天。", "銅鼓祭龍雲塞廟，對花歌詠似狂顛。"]'),
('e9864dcd-eb87-4204-9efe-0bdf902fda38','秋日得鄭茂弘書','李龏','宋','宋诗','song-poetry','','[]','野燒空原盡荻灰，逐臣千里寄書來。',32,'全唐诗/poet.song.206000.json','["野燒空原盡荻灰，逐臣千里寄書來。", "蟲聲竟夜引鄉淚，舊館秋陰生綠苔。"]'),
('6db71364-31ac-48af-b3b5-2ad2f59b4cad','采藥翁','李龏','宋','宋诗','song-poetry','','[]','滿頭霜雪背青山，百歲身心幾日閑。',32,'全唐诗/poet.song.206000.json','["滿頭霜雪背青山，百歲身心幾日閑。", "異果奇花香撲面，往來惟在酒徒間。"]'),
('1b587def-29f7-43cc-b47b-575696af1893','出元符宮逢雨','李龏','宋','宋诗','song-poetry','','[]','水流黄葉意無窮，倚棟星開牛斗宮。',32,'全唐诗/poet.song.206000.json','["水流黄葉意無窮，倚棟星開牛斗宮。", "風入古松添急雨，暮程還過秣陵東。"]'),
