('5b37d757-02c5-4ad3-abc8-439002533c46','代野老作','李龏','宋','宋诗','song-poetry','','[]','浮世浮名能幾何，青山滿眼少年多。',32,'全唐诗/poet.song.206000.json','["浮世浮名能幾何，青山滿眼少年多。", "有時捫蝨獨搔首，目送歸鴻笑復歌。"]'),
('1345d7e9-2c1c-4b75-84dc-9c509beadd3e','道傍古松','李龏','宋','宋诗','song-poetry','','[]','寒流石上一株松，一半死皮藏蠹蟲。',32,'全唐诗/poet.song.206000.json','["寒流石上一株松，一半死皮藏蠹蟲。", "石馬雙雙當古樹，厖眉書客感秋蓬。"]'),
('268e3366-ab27-40ac-b3ca-47113015736d','塞上曲','李龏','宋','宋诗','song-poetry','','[]','賀蘭山下陣如雲，擬報平生未殺身。',32,'全唐诗/poet.song.206000.json','["賀蘭山下陣如雲，擬報平生未殺身。", "誰道古來多簡策，古來名將盡爲神。"]'),
('4187fcb5-4ab2-42d5-850a-d0c5c5a094ed','塞下曲','李龏','宋','宋诗','song-poetry','','[]','都護今年破武威，磧煙烽火夜深微。',32,'全唐诗/poet.song.206000.json','["都護今年破武威，磧煙烽火夜深微。", "金釵漫作封侯別，白髮生頭未得歸。"]'),
('1e4a07ad-361d-4870-abb6-f5df1aa9d981','送春  其一','李龏','宋','宋诗','song-poetry','','[]','三月惟殘一日春，豈知惆悵有閑人。',32,'全唐诗/poet.song.206000.json','["三月惟殘一日春，豈知惆悵有閑人。", "隨風未辨歸何處，斜日橫窗起暗塵。"]'),
('c905ad6b-94cb-4bc2-9d72-4e3dceef2ade','送春  其二','李龏','宋','宋诗','song-poetry','','[]','百和初薰越布衣，一年春盡送春詩。',32,'全唐诗/poet.song.206000.json','["百和初薰越布衣，一年春盡送春詩。", "滿庭芳草坐成恨，貧過長安櫻笋時。"]'),
('996cf0cb-28d8-4fba-b56f-d6fc5205364a','秋曉聞蟬','李龏','宋','宋诗','song-poetry','','[]','聲引秋絲逐遠風，月輪移出上陽宮。',32,'全唐诗/poet.song.206000.json','["聲引秋絲逐遠風，月輪移出上陽宮。", "病來旅館誰相問，玄髮侵愁忽似翁。"]'),
('9f44102a-7046-40dc-9956-8d9727f7cf5f','馬堘賣花者','李龏','宋','宋诗','song-poetry','','[]','十里宜春下苑花，濃香染著洞中霞。',32,'全唐诗/poet.song.206000.json','["十里宜春下苑花，濃香染著洞中霞。", "採夫移得將何處，擔入宮城許史家。"]'),
('0749685b-db80-4eff-b35e-0394585c4016','漁父','李龏','宋','宋诗','song-poetry','','[]','罷釣歸來不繫船，坐看秋水落紅蓮。',32,'全唐诗/poet.song.206000.json','["罷釣歸來不繫船，坐看秋水落紅蓮。", "江鮮野菜桃花飯，高唱夕陽孤島邊。"]'),
('6765e01b-4d77-4f15-bb66-0cc3f309b93e','贈費道士','李龏','宋','宋诗','song-poetry','','[]','强梳蓬鬢整斜冠，夜聽步虛山月寒。',32,'全唐诗/poet.song.206000.json','["强梳蓬鬢整斜冠，夜聽步虛山月寒。", "縮地往來無定所，洞天誰道却歸難。"]'),
('40f6752c-ee02-4b52-bfaf-de9da10b3cd5','春夜','李龏','宋','宋诗','song-poetry','','[]','日日日斜空醉歸，敗裘披苦見毛稀。',32,'全唐诗/poet.song.206000.json','["日日日斜空醉歸，敗裘披苦見毛稀。", "杜鵑啼斷回家夢，夢掃蘆花絮客衣。"]'),
('bcac0e19-d99f-4773-b8ce-694ecdefe9e1','古觀','李龏','宋','宋诗','song-poetry','','[]','仙觀曾過知不遠，古壇春雨蘚生磚。',32,'全唐诗/poet.song.206000.json','["仙觀曾過知不遠，古壇春雨蘚生磚。", "行逢買藥歸來客，誰解登高問上玄。"]'),
('3abfb160-f547-4320-9acb-7e11a039aa5f','過烏衣巷','李龏','宋','宋诗','song-poetry','','[]','王謝風流滿晉書，東南一望可長吁。',32,'全唐诗/poet.song.206000.json','["王謝風流滿晉書，東南一望可長吁。", "平蕪隔水時飛燕，更有何人在此居。"]'),
('ef85bdb6-38cf-45df-bca7-71687deac211','宿破寺','李龏','宋','宋诗','song-poetry','','[]','耻將興廢問休公，道似危途動即窮。',32,'全唐诗/poet.song.206000.json','["耻將興廢問休公，道似危途動即窮。", "冷極睡無離枕夢，橘邊沽海半罎空。"]'),
('224ee76e-ad4b-48ac-96cd-b1835b4e8f65','賦青城山陷','李龏','宋','宋诗','song-poetry','','[]','蜀道天收碧落鍾，六丁移路鑿蠶叢。',32,'全唐诗/poet.song.206000.json','["蜀道天收碧落鍾，六丁移路鑿蠶叢。", "飛山夜挾風雷沒，愁殺江南鬼五通。"]'),
('713de76b-b189-43cb-9087-323b740a3e58','偶題','李龏','宋','宋诗','song-poetry','','[]','杞菊苗香雨足時，芼羹千載憶天隨。',32,'全唐诗/poet.song.206000.json','["杞菊苗香雨足時，芼羹千載憶天隨。", "食盤近覺魚蝦貴，勿笑吳傖啖逐夷。"]'),
('5e2c0885-c7c3-4b52-8677-dda4b59e95bc','偶成','李龏','宋','宋诗','song-poetry','','[]','投老謀生未有涯，酸吟空自度年華。',32,'全唐诗/poet.song.206000.json','["投老謀生未有涯，酸吟空自度年華。", "人間春雨秋風夜，落葉堪悲似落花。"]'),
('4c750ea1-142a-448b-8672-95afc0340289','讀周晉仙詩','李龏','宋','宋诗','song-poetry','','[]','句中響處玉瓏玲，合使吟人洗耳聽。',32,'全唐诗/poet.song.206000.json','["句中響處玉瓏玲，合使吟人洗耳聽。", "王謝風流今不見，金鵝山下月冥冥。"]'),
('a776e06a-eadc-4b7a-be06-4ea8f9e092fa','過太湖','李龏','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','水面八百里，所之唯認山。',48,'全唐诗/poet.song.206000.json','["水面八百里，所之唯認山。", "消人名利念，出世是非間。", "帆有凌空勢，雲無不雨顔。", "何年洞庭上，林屋老仙關。"]'),
('b0f914ed-95de-4317-b71a-9d5b9e03d87a','雨花臺','李龏','宋','宋诗','song-poetry','','[]','不見梁時說法僧，一臺芳草自青青。',32,'全唐诗/poet.song.206000.json','["不見梁時說法僧，一臺芳草自青青。", "滿山碼碯殷紅子，空驗天花舊點靈。"]'),
('d74431a1-0377-4de6-a902-78698205c3e6','野梅歎','李龏','宋','宋诗','song-poetry','','[]','蒼岑大野臨回岡，有樹破臘揚孤芳。',64,'全唐诗/poet.song.206000.json','["蒼岑大野臨回岡，有樹破臘揚孤芳。", "枝頭粘得太古雪，月底散出無邊香。", "一清炯然抱幽寂，老與樸樕埋冰霜。", "青苔黄蘚裹寒骨，槁面不入春風場。"]'),
('3cda5dfb-2cbb-4ff0-9d04-7f13e0362e3d','夜發崑山問潮館','李龏','宋','宋诗','song-poetry','','[]','雲耿寒星路不明，問潮人起約三更。',32,'全唐诗/poet.song.206000.json','["雲耿寒星路不明，問潮人起約三更。", "江風吹上一輪月，照動客船多少情。"]'),
('4c3f8ade-9c96-4cbe-8d9a-e8d07a7cec8d','送黄壽老謁淮南賈制帥','李龏','宋','宋诗','song-poetry','','[]','雪邊行李別詩朋，詩教龍門在廣陵。',32,'全唐诗/poet.song.206000.json','["雪邊行李別詩朋，詩教龍門在廣陵。", "十里紅樓明月夜，莫將新句讓徐凝。"]'),
('6f068379-1ede-403b-87d6-1736637a0ebe','分詠得鞋','李龏','宋','宋诗','song-poetry','','[]','一鈎金押皂花羅，頭似鸚哥小不多。',32,'全唐诗/poet.song.206000.json','["一鈎金押皂花羅，頭似鸚哥小不多。", "記得花時人較醉，窣香曾上木蘭坡。"]'),
('08ef77a1-479e-46cf-88ea-69254a8b80a2','前有一樽酒','李龏','宋','宋诗','song-poetry','','[]','前有一樽酒，主人奉客客稱壽。',183,'全唐诗/poet.song.206000.json','["前有一樽酒，主人奉客客稱壽。", "君不見麟不能飛，鳳不能走。", "龜靈於人，龍死於鬭。", "山有時兮崩，河有時兮决。", "秦皇求仙竟不成，梁皇佞佛何曾徹。", "我今爲君拂青萍，履明月，奏雲和，歌白雪。", "洗滌塵埃九折腸，澡瀹風雷三寸舌。", "上願天子聖，下願宰相賢。", "字民之官不愛錢，四夷妥帖無狼煙。", "有田負郭安里{厘/灬/土}，秋堂夏屋臨平川。", "左手黄卷右青編，糟糠功名一百年。", "坐上日日延俊秀，子孫孫子相綿綿。"]'),
('a5a0004c-ceae-4a7b-adf3-d8a823f578f0','當置酒','李龏','宋','宋诗','song-poetry','','[]','故人客秋縣，青軒臨繡楹。',48,'全唐诗/poet.song.206000.json','["故人客秋縣，青軒臨繡楹。", "頹陽橫斷柳，短渡隔孤城。", "風蓮卸湘綺，露草結秦纓。", "當置一樽酒，前途路未平。"]'),
('db2a39a9-21e6-494a-82c8-47a521159d68','懷友','李龏','宋','宋诗','song-poetry','','[]','幽人只隔一峰雲，幾度相思叫不聞。',32,'全唐诗/poet.song.206000.json','["幽人只隔一峰雲，幾度相思叫不聞。", "日暮小溪三四曲，薔薇如雪落紛紛。"]'),
('7e4c30da-5715-418f-99b8-39596218217f','舊館憶王抱節','李龏','宋','宋诗','song-poetry','','[]','夜雨滄波上，寒塘草市中。',48,'全唐诗/poet.song.206000.json','["夜雨滄波上，寒塘草市中。", "鍾聞兩寺應，室掩一床空。", "買醉留僧燭，敲吟折水葓。", "沙邊鳴宿雁，亦似哭詩翁。"]'),
('0acfd999-0a06-4c6c-8dd6-2bc1b3822c18','有憶王抱節陳樗堂','李龏','宋','宋诗','song-poetry','','[]','貧驅遊海縣，常憶老詩朋。',48,'全唐诗/poet.song.206000.json','["貧驅遊海縣，常憶老詩朋。", "秋事無人語，危樓怯自登。", "蚌津紅日冷，鹽竈白煙凝。", "惆悵遼天鶴，緘書喚不應。"]'),
('4928ee54-e6a7-46a3-a7f7-04303a784674','贈黄中爲賦澹翁','李龏','宋','宋诗','song-poetry','','[]','世間無味處，子獨嗜之深。',48,'全唐诗/poet.song.206000.json','["世間無味處，子獨嗜之深。", "野菜羹前飲，梨花月下吟。", "盡於時態別，更沒俗情侵。", "我亦心如水，因題契我心。"]'),
('5afe2e57-d640-4c12-9aac-190e6e8d57d0','沈子玉使君','李龏','宋','宋诗','song-poetry','','[]','黄紙新除郡，欣君得晉陵。',48,'全唐诗/poet.song.206000.json','["黄紙新除郡，欣君得晉陵。", "幾年淹俊軌，今日慰親朋。", "地近家殊便，民淳治易興。", "何時把麾去，莫廢遣書縢。"]'),
('cedee5d2-cbcb-46cc-92bf-d03f78cfc587','寄抱節','李龏','宋','宋诗','song-poetry','','[]','枕簟驚秋客意悲，吳湖一望白雲迷。',64,'全唐诗/poet.song.206000.json','["枕簟驚秋客意悲，吳湖一望白雲迷。", "風枝蟬老寒聲起，野浦蓮衰夕艷淒。", "書寄潮船多不到，詩臨月館少曾題。", "離魂每夜生歸夢，只繞東遷漢縣西。"]'),
('fb276387-bfe5-40c7-b299-75ca9c11bfe1','寄陳公儲','李龏','宋','宋诗','song-poetry','','[]','一歲又將晏，客遊今海濆。',48,'全唐诗/poet.song.206000.json','["一歲又將晏，客遊今海濆。", "水寒鷗上樹，風勁鶻盤雲。", "京醖秋曾飲，湖涼夜亦分。", "雪邊梅事動，吟思正迷羣。"]'),
('19d279a9-385d-4248-b706-0c3112ece2e1','酬陳復初見寄','李龏','宋','宋诗','song-poetry','','[]','不作科場夢，塵愁鬢亦衰。',48,'全唐诗/poet.song.206000.json','["不作科場夢，塵愁鬢亦衰。", "每於明月夜，多憶少年時。", "朗抱花空識，清貧鏡獨知。", "秋來大江上，件件欠君詩。"]'),
('f0af396c-a952-411c-a05a-da4617cab0eb','桑樹','李龏','宋','宋诗','song-poetry','','[]','無花多病枝，唯葉吐春輝。',48,'全唐诗/poet.song.206000.json','["無花多病枝，唯葉吐春輝。", "蠶不資爲食，人應種者稀。", "陰成嬌雉宿，椹熟乳鶑飛。", "幾槎閑紅紫，從渠上錦機。"]'),
('e81aa1ec-5a99-4f86-a046-731bad394462','風琴','李龏','宋','宋诗','song-poetry','','[]','呦咽高低韻不同，斷魂江月更冥朦。',32,'全唐诗/poet.song.206000.json','["呦咽高低韻不同，斷魂江月更冥朦。", "隔窗暗覓聲來處，響落晴霄一線風。"]'),
('241f996a-e59c-4ef0-8b92-ec14638e2bfd','信州道中','李龏','宋','宋诗','song-poetry','','[]','試出江東路，葛溪還玉溪。',48,'全唐诗/poet.song.206000.json','["試出江東路，葛溪還玉溪。", "灘聲喧水石，人語混鳧鷖。", "田卧栽禾鼓，桑閑採葉梯。", "春城紅酒味，猶憶在江西。"]'),
('46f58ac2-3686-4170-9ebf-21ead0a6f85b','清塘','李龏','宋','宋诗','song-poetry','','[]','苧旗風裏響連耞，蓼岸飛塵入釣車。',32,'全唐诗/poet.song.206000.json','["苧旗風裏響連耞，蓼岸飛塵入釣車。", "昨夜碧城疏雨過，斷畦秋菜亦抽花。"]'),
('647c399c-150f-4183-b402-b7fc20aa5fd8','秋夜芭蕉','李龏','宋','宋诗','song-poetry','','[]','綠似春江水染成，窗紗分映色偏明。',32,'全唐诗/poet.song.206000.json','["綠似春江水染成，窗紗分映色偏明。", "霜風一夜渾梢破，葉上殘詩讀不行。"]'),
('fdd4158e-d390-454e-b19f-974692cccc97','採蓮曲','李龏','宋','宋诗','song-poetry','','[]','西風引袂凉雲起，鴛槳扶船浮綠水。',96,'全唐诗/poet.song.206000.json','["西風引袂凉雲起，鴛槳扶船浮綠水。", "露沁花脂茜粉香，滿柄蜂芒刺葱指。", "紅綃半妥金釧明，堤上玉郎闚唱聲。", "湘中暮雨歡期失，各自東西空目成。", "船蕩波心煙漠漠，歸路花從唱邊落。", "綠艷紅妖江水深，水底靈均應不覺。"]'),
('f53e421f-19de-47b0-9fc4-21ed6f8f17e5','秋日子規','李龏','宋','宋诗','song-poetry','','[]','血滴成花不自歸，銜愁猶泣在天涯。',32,'全唐诗/poet.song.206000.json','["血滴成花不自歸，銜愁猶泣在天涯。", "秋聲又比春□苦，除却淵明勸得誰。"]'),
('5cd23d99-c01a-459a-8dda-e298f7acac50','山居友','李龏','宋','宋诗','song-poetry','','[]','不事塵中事，如君只一家。',48,'全唐诗/poet.song.206000.json','["不事塵中事，如君只一家。", "墮巢收煮茗，閑艇借移花。", "養樹填山色，疏池抉草苴。", "妻孥諳地利，亦喜治桑麻。"]'),
('2ca08405-01e5-407d-9a98-b40146276ae7','松濱書館','李龏','宋','宋诗','song-poetry','','[]','一身如鶴信蕭閑，又向松濱寄客單。',64,'全唐诗/poet.song.206000.json','["一身如鶴信蕭閑，又向松濱寄客單。", "世事嬾能捫蝨話，生涯聊作豢龍看。", "刪來稿卷吟還冗，洗過綀衣著倍寬。", "獨有會心真得處，小庭幽草綠平欄。"]'),
('14c39ae3-be55-4183-9921-25e373e3d8fb','登蘇州齊雲樓','李龏','宋','宋诗','song-poetry','','[]','故基何處是吳宮，醉上州城值晚風。',32,'全唐诗/poet.song.206000.json','["故基何處是吳宮，醉上州城值晚風。", "簫鼓沉沉煙樹冷，亂蛙聲在落花中。"]'),
('70702aa6-4527-4746-b5bc-5d8e424f63cd','登鳳凰臺','李龏','宋','宋诗','song-poetry','','[]','繚垣桐數樹，知是阿誰栽。',48,'全唐诗/poet.song.206000.json','["繚垣桐數樹，知是阿誰栽。", "鳴鳳久不至，遊人空自來。", "春聲歸百鳥，古意薄層苔。", "縹緲三山外，離雲掃弗開。"]'),
('50b83e6b-a253-46d7-8d99-7bf24f156f46','西興','毛珝','宋','宋诗','song-poetry','','[]','蚤暮船爭渡，都城隔岸間。',48,'全唐诗/poet.song.206000.json','["蚤暮船爭渡，都城隔岸間。", "昔爲漁釣地，今作利名關。", "潮探塵中事，年催客裏顔。", "水僊花又發，吾欲老江灣。"]'),
('413673e0-7b32-47ff-8185-5a9cea3208f0','寓池之清夷堂','毛珝','宋','宋诗','song-poetry','','[]','堂靜草侵廊，羈懷未易忘。',48,'全唐诗/poet.song.206000.json','["堂靜草侵廊，羈懷未易忘。", "近城知郡圃，有佛即僧坊。", "惡句書盈壁，空樽壘到牆。", "使君臨寵外，滿目樹蒼蒼。"]'),
('14a80821-d26c-45ef-bb37-bf4b40a58134','送客遊吳','毛珝','宋','宋诗','song-poetry','','[]','水鄉秋易冷，珍重過吳松。',48,'全唐诗/poet.song.206000.json','["水鄉秋易冷，珍重過吳松。", "在旅雖難遣，於詩莫厭攻。", "一輪僧寺月，半夜客船鍾。", "况有賢州牧，知音是舊逢。"]'),
('5d96b08c-41bb-4ebc-8da0-2f4fe8603481','小至','毛珝','宋','宋诗','song-poetry','','[]','九地陽初動，披衣起擁鑪。',48,'全唐诗/poet.song.206000.json','["九地陽初動，披衣起擁鑪。", "門前初去馬，窗外漸啼烏。", "雲色呈金未，梅梢破玉無。", "焚香待天曉，點易自研朱。"]'),
('0a465818-943f-4e2a-8530-b17c156302c2','廬山棲賢寺','毛珝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','名重於諸剎，前賢舊隠蹤。',48,'全唐诗/poet.song.206000.json','["名重於諸剎，前賢舊隠蹤。", "無人知有路，隔樹忽聞鍾。", "瀑壯山疑裂，雲深寺若封。", "或傳遺稿在，三叩昔時松。"]'),
('e678558e-72d8-4c68-98d0-2f1d2b542108','登黄崗清淮門','毛珝','宋','宋诗','song-poetry','','[]','風吹蘆葉江頭路，江水江天共秋暮。',64,'全唐诗/poet.song.206000.json','["風吹蘆葉江頭路，江水江天共秋暮。", "邊淮寒早客行稀，只有征鴻向南去。", "征鴻自去書不來，遠衣未寄憑誰催。", "孤城慘咽暮笳起，城下荒榛接淮水。"]'),
('35217f47-8164-4acf-bbf7-1f248d5bccd3','種竹','毛珝','宋','宋诗','song-poetry','','[]','山居無力塵居俗，有客勸予惟種竹。',64,'全唐诗/poet.song.206000.json','["山居無力塵居俗，有客勸予惟種竹。", "種成貧家可驟富，翠色琅玕遶君屋。", "清晨荷鉏斸溪岸，分得溪光入城綠。", "暮年百事課功遲，坐待春風滿林玉。"]'),
('7cb4d117-bb1f-4d6c-ab1f-78aac21c9ec5','墨龍','毛珝','宋','宋诗','song-poetry','','[]','真人尸居雷八荒，斷磚殘墨生蒼茫。',64,'全唐诗/poet.song.206000.json','["真人尸居雷八荒，斷磚殘墨生蒼茫。", "鯢桓下𥉻九淵黑，神光倒射角與亢。", "明明元氣淋漓蹟，水底焚槐海波赤。", "周流萬化元無極，姑使人心識天則。"]'),
('232f6201-2877-4149-8cc4-2de5ee464f7a','湘江','毛珝','宋','宋诗','song-poetry','','[]','湘江誰道無情水，寶瑟聲寒愁帝子。',64,'全唐诗/poet.song.206000.json','["湘江誰道無情水，寶瑟聲寒愁帝子。", "安知日月在中天，萬古重瞳元不死。", "楚南楚北千里雲，持香遥禮雲中君。", "莫起悲風助騷怨，蘭枯菊瘁不堪聞。"]'),
('3c283ead-c3fb-4f09-9998-f8ca9d880674','東風','毛珝','宋','宋诗','song-poetry','','[]','東風煦嫗如慈乳，欲報生成恨無所。',64,'全唐诗/poet.song.206000.json','["東風煦嫗如慈乳，欲報生成恨無所。", "自粘花片作斑衣，起捧春醪勸春舉。", "傍人笑我老如許，我亦笑渠將及汝。", "梅花也笑柳都舞，君如不飲出童羖。"]'),
('baca34d7-f792-4677-9421-9c15df7e04e1','浙江','毛珝','宋','宋诗','song-poetry','','[]','白鷴舊事隨波去，太極陰陽自吞吐。',64,'全唐诗/poet.song.206000.json','["白鷴舊事隨波去，太極陰陽自吞吐。", "長虹夜貫黑頭船，四紀沙迎相公路。", "馮夷作劇真等閒，五都有客雄其間。", "上林三官浪憂國，千年海底生銅山。"]'),
('cc49a890-4105-4804-8964-393b9ffc87ab','檜瀑','毛珝','宋','宋诗','song-poetry','','[]','媧皇失補天南角，一道銀河落君屋。',64,'全唐诗/poet.song.206000.json','["媧皇失補天南角，一道銀河落君屋。", "又疑元氣自周流，不然瀉盡誰能續。", "瀑邊老檜尤可人，髯疎骨瘦皮鱗皴。", "崩崖欲壓全不懼，夜半潜蛟暗來去。"]'),
('fe75ca76-7524-4e49-af66-69bf0c8d9cc2','富川邂逅戚叔開','毛珝','宋','宋诗','song-poetry','','[]','百蟲阫蟄鴈奔忙，君從何來兩袂霜。',64,'全唐诗/poet.song.206000.json','["百蟲阫蟄鴈奔忙，君從何來兩袂霜。", "大冠如箕盍齊魯，此地無乃驚吠厖。", "釣竿曾笑江湖窄，尺水詎容投犗客。", "取羝爲君向東軷，一聲裂石扶桑白。"]'),
('5d948e7e-74ad-4202-a4c7-88f19aa0b24d','虎丘','毛珝','宋','宋诗','song-poetry','','[]','阿鴻血染吳苔碧，氣徹重泉埋不得。',64,'全唐诗/poet.song.206000.json','["阿鴻血染吳苔碧，氣徹重泉埋不得。", "千年至寶復歸天，顛倒海中飛霹靂。", "至今荒怪列虞初，罅石千尋駭遊客。", "寺邊別廟是何神，月黑伽藍問周易。"]'),
('401aa2f9-25f5-4a2d-b36b-8439859d91ad','月','毛珝','宋','宋诗','song-poetry','','[]','人言月裏仙人住，隠約娑羅樹根兔。',64,'全唐诗/poet.song.206000.json','["人言月裏仙人住，隠約娑羅樹根兔。", "玄霜搗就亦多年，不見有人曾得度。", "清光偏照邊城秋，城邊白骨胎王侯。", "王侯白骨卒未已，龜蚌吸月獨不死。"]'),
('ef5a7505-878c-4ceb-80a4-2a2164fef7b1','丹陽館','毛珝','宋','宋诗','song-poetry','','[]','渡江第一南來驛，幾度華堂延鴈客。',64,'全唐诗/poet.song.206000.json','["渡江第一南來驛，幾度華堂延鴈客。", "百年運逐曉雲空，愁殺鞮官老無職。", "南徐今日古陽關，不斷歌聲祖離席。", "國讎已復事尤多，折損年年春柳碧。"]'),
('704d3636-07e4-4fc2-9a9b-d7590912d8ae','富池廟','毛珝','宋','宋诗','song-poetry','','[]','船頭蜀錦三千尺，倒影長虹浸寒碧。',64,'全唐诗/poet.song.206000.json','["船頭蜀錦三千尺，倒影長虹浸寒碧。", "相逢不是紫髯郎，鸚鵡洲邊眼生棘。", "江頭簫鼓雜靈鴉，人道陰兵曾護國。", "安知樓下雪千堆，不是吞曹氣衝激。"]'),
('4e6053b1-27ab-4b5a-9dff-2c4cef6f9c45','秋日即事','毛珝','宋','宋诗','song-poetry','','[]','黄花暴日香欲醉，黄蜂抱香暖欲睡。',64,'全唐诗/poet.song.206000.json','["黄花暴日香欲醉，黄蜂抱香暖欲睡。", "老夫邂逅亦欣然，一段先天畫前意。", "喧喧歸雀聒叢篁，夕風欲轉明朝霜。", "花摇蜂醒我亦覺，斜陽一片秋茫茫。"]'),
('d4a5c6f1-42e7-4c50-821d-0650d17c8a16','甲午江行','毛珝','宋','宋诗','song-poetry','','[]','百川無敵大江流，不與人間洗舊讎。',64,'全唐诗/poet.song.206000.json','["百川無敵大江流，不與人間洗舊讎。", "殘虜自緣他國廢，諸公空負百年憂。", "邊寒戰馬全裝鐵，波闊征船半起樓。", "一舉盡收關洛舊，不知銷得幾分愁。"]'),
('9312ad32-c864-49f9-80ab-824a91259446','寓興國之十詠亭呈諸友','毛珝','宋','宋诗','song-poetry','','[]','斷垣荒棘疑無路，忽有幽亭一畝餘。',64,'全唐诗/poet.song.206000.json','["斷垣荒棘疑無路，忽有幽亭一畝餘。", "不稱郡侯來把酒，偏宜野客借觀書。", "臨堦汲水防苔滑，隔岸看山愛柳疏。", "非有舊交時下顧，十分風味落樵漁。"]'),
('bba6e4c6-f94a-4461-a731-70c11823056a','中年','毛珝','宋','宋诗','song-poetry','','[]','中年已悟昔皆非，正學無師更可悲。',64,'全唐诗/poet.song.206000.json','["中年已悟昔皆非，正學無師更可悲。", "詩道縱能通閫域，聖經曾未涉藩籬。", "擬從周子參無極，更爲東萊續近思。", "適意舞雩時一詠，區區何用苦吟爲。"]'),
('3d2caf79-3d8d-4315-b9aa-351bd7a9c69a','寓泉之定空寺','毛珝','宋','宋诗','song-poetry','','[]','齋鍾聲斷佛香銷，閑步虛廊轉幾遭。',64,'全唐诗/poet.song.206000.json','["齋鍾聲斷佛香銷，閑步虛廊轉幾遭。", "濁世自緣君不捨，青山豈是俗難逃。", "鳥如留客音聲好，松似驕人意氣高。", "因悟宿根元自有，栽培功淺長蓬蒿。"]'),
('245bdf0b-925d-4d3d-bc42-282b40a63f70','掩卷','毛珝','宋','宋诗','song-poetry','','[]','盈箱積案欲何如，誤盡蒼生半屬渠。',64,'全唐诗/poet.song.206000.json','["盈箱積案欲何如，誤盡蒼生半屬渠。", "陸贄外誰無負學，臯陶前是讀何書。", "鑿開素樸惟三畫，斲碎真淳遂五車。", "安得六經行世外，民風盡返結繩初。"]'),
('1ad28b54-3158-44e0-9858-7e1f91513234','謝胡默堂','毛珝','宋','宋诗','song-poetry','','[]','創新小閣畫難成，肯借山翁養病身。',64,'全唐诗/poet.song.206000.json','["創新小閣畫難成，肯借山翁養病身。", "萬事不憂知有命，數椽分庇可無人。", "觀書漆几明於鏡，欹枕藤床軟勝茵。", "終恐傍門心未穩，弊廬雖弊每馳神。"]'),
('a7abe46d-b7a3-48ee-8627-cbb9e3e64dbb','寓泉之安溪','毛珝','宋','宋诗','song-poetry','','[]','已恨逢人語不通，更堪煙嶺隔千重。',64,'全唐诗/poet.song.206000.json','["已恨逢人語不通，更堪煙嶺隔千重。", "山城縱是如花好，海霧終愁似墨濃。", "遠信斷無鴻可寄，故鄉惟有月相逢。", "閒於荔綠蕉紅處，步屧時留到晚鍾。"]'),
('dc785bf9-ea50-48e4-b07f-20e8c5926028','雪','毛珝','宋','宋诗','song-poetry','','[]','無雨無雲曉色乾，忽驚瑰璧滿簷端。',64,'全唐诗/poet.song.206000.json','["無雨無雲曉色乾，忽驚瑰璧滿簷端。", "不教聲到窗前覺，應恐愁添屋下寒。", "占瑞農官尋玉尺，析酲公子索金盤。", "柴門睡起無多事，捲上疏簾带竹看。"]'),
('79f8fb1b-7241-404f-878c-69021f866296','關心','毛珝','宋','宋诗','song-poetry','','[]','關心歲月似驚波，少日無成奈老何。',64,'全唐诗/poet.song.206000.json','["關心歲月似驚波，少日無成奈老何。", "別久帝京知事少，住長客舍識人多。", "典衣酤酒盃難滿，借壁題詩字易磨。", "早信出門無遇合，故山只合守樵柯。"]'),
('54db3434-5fb8-48a2-ae97-7a332da0dc5b','通之海山樓落成','毛珝','宋','宋诗','song-poetry','','[]','千尋雉堞一朝興，五馬行庖此落成。',64,'全唐诗/poet.song.206000.json','["千尋雉堞一朝興，五馬行庖此落成。", "地峻鬼神愁設險，樓高星斗聽談兵。", "霞羞綵幟依山歛，月鬭金盃出海明。", "更有萬堆飛石在，寄聲殘羯盍魂驚。"]'),
('c929ee06-eb41-4c83-b8d2-a24a02880d60','鳳凰臺','毛珝','宋','宋诗','song-poetry','','[]','江山依舊昔人非，多少興亡問不知。',64,'全唐诗/poet.song.206000.json','["江山依舊昔人非，多少興亡問不知。", "鴈去又逢重到日，鳳歸安得再來時。", "風吹木葉隨漁艇，霜壓蘆花出酒旗。", "特地待吟吟未穩，數聲昏笛戍樓吹。"]'),
('8c5963a4-e9a2-42f1-bed8-e81ddefd3e0d','學道','毛珝','宋','宋诗','song-poetry','','[]','學道先須學忍貧，縕袍蔬食當華珍。',64,'全唐诗/poet.song.206000.json','["學道先須學忍貧，縕袍蔬食當華珍。", "摳衣所欠參前輩，開卷猶欣見古人。", "暗坐雨窗心似月，冷眠雪屋氣如春。", "向來酷意耽吟事，今亦相忘越與秦。"]'),
('d3ad34fc-24d3-4db2-811c-e39d398f67aa','贈碧蜍','毛珝','宋','宋诗','song-poetry','','[]','鳶飛魚躍兩悠悠，造物何心莫問休。',64,'全唐诗/poet.song.206000.json','["鳶飛魚躍兩悠悠，造物何心莫問休。", "但得一盃長在手，不須萬戶更封侯。", "人間有夢何非蝶，物外忘機即是鷗。", "我亦青鞵行脚者，會摩銅狄話重遊。"]'),
('a0360198-ee4b-4941-b2c7-c111d4ec2d5c','人才','毛珝','宋','宋诗','song-poetry','','[]','但得人才即治安，不憂外侮敢相干。',64,'全唐诗/poet.song.206000.json','["但得人才即治安，不憂外侮敢相干。", "學關世道方爲士，業曉農家始是官。", "國力在兵堪用少，虜情如鬼欲驅難。", "豈無一代奇男子，抱膝無言靜處看。"]'),
('387e1de2-5399-488d-8d2a-08d411de7c91','和張梅深四首  其一','毛珝','宋','宋诗','song-poetry','','[]','幾踏槐花角寸長，擔簦羞作老來忙。',64,'全唐诗/poet.song.206000.json','["幾踏槐花角寸長，擔簦羞作老來忙。", "立身早慕千層塔，閲世今知百戲場。", "從辟穀來惟嗜酒，自栽梅後不燒香。", "人生底爲青衫急，亦有秋荷可製裳。"]'),
('d5494ea3-0848-4a05-ab72-3b0dee72bbc7','和張梅深四首  其二','毛珝','宋','宋诗','song-poetry','','[]','不用悲歌撫鋏長，古無人可免身忙。',64,'全唐诗/poet.song.206000.json','["不用悲歌撫鋏長，古無人可免身忙。", "存心未必耕無地，涉世難忘選有場。", "新別水雲書尚濕，舊題松桂筆猶香。", "只緣誤觸神舟走，惆悵京塵涴薜裳。"]'),
('076ef384-45ba-4253-862e-a8607df25a5b','和張梅深四首  其三','毛珝','宋','宋诗','song-poetry','','[]','我策曾無一策長，一生蟻踏歷間忙。',64,'全唐诗/poet.song.206000.json','["我策曾無一策長，一生蟻踏歷間忙。", "持經佛寺新投社，寄食田家舊築場。", "古劍放教龍逐伴，殘書分與蠹餐香。", "不愁死去無名在，化作千年老鶴裳。"]'),
('e97d3971-7145-4327-8143-83319a480bfb','和張梅深四首  其四','毛珝','宋','宋诗','song-poetry','','[]','鳬鶴都休較短長，靜非無用動非忙。',64,'全唐诗/poet.song.206000.json','["鳬鶴都休較短長，靜非無用動非忙。", "閑將詩卷排科甲，戲把文枰列戰場。", "無地可施行話柄，有天須監格心香。", "功名細看時來耳，珍重漁蓑即衮裳。"]'),
('3a4efbcb-734a-4580-87c0-b2c43b6f934e','古出塞','毛珝','宋','宋诗','song-poetry','','[]','初說戍漁陽，俄傳出定襄。',24,'全唐诗/poet.song.206000.json','["初說戍漁陽，俄傳出定襄。", "朝朝征馬過，春草不曾長。"]'),
('287b6998-99b2-47bf-9700-23b0fd6b03db','山月','毛珝','宋','宋诗','song-poetry','','[]','山月共徘徊，山泉酌一盃。',24,'全唐诗/poet.song.206000.json','["山月共徘徊，山泉酌一盃。", "詩成無筆寫，畫石記蒼苔。"]'),
('2e789783-41ab-4300-905a-544a878ec74f','書墨竹','毛珝','宋','宋诗','song-poetry','','[]','伯夷有宿世契，子猷結千古交。',28,'全唐诗/poet.song.206000.json','["伯夷有宿世契，子猷結千古交。", "煙外三葉五葉，雨中一梢兩梢。"]'),
('71bbc769-10db-4a0b-a837-644ebd4607dc','觀星','毛珝','宋','宋诗','song-poetry','','[]','九天有象不虛呈，歷歷都關國重輕。',32,'全唐诗/poet.song.206000.json','["九天有象不虛呈，歷歷都關國重輕。", "漢客可無經濟意，只將牛女問君平。"]'),
('21fffd87-8ce5-478e-ac4c-af7bd4a69d80','海陵','毛珝','宋','宋诗','song-poetry','','[]','繞城無數菜花黄，隔岸蒹葭接大荒。',32,'全唐诗/poet.song.206000.json','["繞城無數菜花黄，隔岸蒹葭接大荒。", "不分塞鴻偏得意，年年春老未還鄉。"]'),
('7994c195-9697-42b8-8b63-9093f9502bff','海陵之堡城  其一','毛珝','宋','宋诗','song-poetry','','[]','四面蒹葭水接天，中間一片是人煙。',32,'全唐诗/poet.song.206000.json','["四面蒹葭水接天，中間一片是人煙。", "相逢盡喜干戈息，白鷺飛來立戰船。"]'),
('b22f0440-f681-4d38-a0ef-d67666b21892','海陵之堡城  其二','毛珝','宋','宋诗','song-poetry','','[]','傍城三十里芙蕖，怪底繁華浙景無。',32,'全唐诗/poet.song.206000.json','["傍城三十里芙蕖，怪底繁華浙景無。", "元是近邊農事少，全憑蓮藕當官租。"]'),
('85e5c47b-482a-48f0-8e10-3e0bd49ba34e','海陵之堡城  其三','毛珝','宋','宋诗','song-poetry','','[]','邊聲藉藉早秋風，稻未黄時棗又紅。',32,'全唐诗/poet.song.206000.json','["邊聲藉藉早秋風，稻未黄時棗又紅。", "莫厭水鄉遷避苦，全家載入綠荷中。"]'),
('68a407c3-5aeb-4515-b30c-e37c3dec39f4','儀真  其一','毛珝','宋','宋诗','song-poetry','','[]','頻年歲稔少干戈，到處人能販五河。',32,'全唐诗/poet.song.206000.json','["頻年歲稔少干戈，到處人能販五河。", "只道鹺舟偏輻輳，玉盃涇段近年多。"]'),
('d404020d-63c1-4465-be8f-e7e5718966c5','儀真  其二','毛珝','宋','宋诗','song-poetry','','[]','多旨樓邊古柳斜，龍淵寺裏隔荷花。',32,'全唐诗/poet.song.206000.json','["多旨樓邊古柳斜，龍淵寺裏隔荷花。", "清風盡日無人管，半屬僧家半妓家。"]'),
('0dadabfe-761b-4c45-b01c-dc56b5f45e45','儀真  其三','毛珝','宋','宋诗','song-poetry','','[]','販來北棗堪充膳，種得西瓜可析酲。',32,'全唐诗/poet.song.206000.json','["販來北棗堪充膳，種得西瓜可析酲。", "總是中原舊風物，不堪今日是邊城。"]'),
('1777caec-3458-4bb4-bc0a-e71ea28aba13','晚凉','毛珝','宋','宋诗','song-poetry','','[]','窗前灑地著胡床，浴罷閑來坐晚凉。',32,'全唐诗/poet.song.206000.json','["窗前灑地著胡床，浴罷閑來坐晚凉。", "更取壁燈移暗處，待他月上竹邊牆。"]');
